// DataRover - Clean Working Version
const API = 'backend.php';

// ============================================================
// KEYCLOAK SSO CONFIGURATION
// ============================================================
var KEYCLOAK_CONFIG = {
    url: localStorage.getItem('ssoUrl') || 'http://localhost:8180',
    realm: localStorage.getItem('ssoRealm') || 'datarover',
    clientId: localStorage.getItem('ssoClientId') || 'datarover-app'
};

function isSSOEnabled() {
    return localStorage.getItem('ssoEnabled') !== 'false';
}

