// TRANSLATIONS - Loaded from js/translations.js
// ============================================================

// ============================================================

// ============================================================
// AUTHENTICATION STATE
// ============================================================
let currentUser = null;
let authToken = localStorage.getItem('authToken') || null;
let userPermissions = [];
let userRoles = [];
let keycloakToken = null;

// ============================================================
// DATABASE ONLY MODE - All data from MySQL
// ============================================================

// ============================================================
// API HELPER FUNCTIONS
// ============================================================

async function apiCall(action, method = 'GET', data = null, id = null) {
    let url = `${API}?action=${action}`;
    if (id) url += `&id=${id}`;
    if (authToken) url += `&token=${authToken}`;
    
    const headers = { 'Content-Type': 'application/json' };
    if (authToken) {
        headers['Authorization'] = 'Bearer ' + authToken;
    }
    
    const options = {
        method: method,
        headers: headers
    };
    
    if (data && (method === 'POST' || method === 'PUT')) {
        options.body = JSON.stringify(data);
    }
    
    try {
        const response = await fetch(url, options);
        const result = await response.json();
        
        // Handle auth errors
        if (response.status === 401) {
            handleAuthError();
            return null;
        }
        
        if (!result.success) {
            console.error('API Error:', result.error);
            return null;
        }
        return result.data;
    } catch (error) {
        console.error('Network Error:', error);
        return null;
    }
}

// Sync helper for backwards compatibility
function apiCallSync(action, method = 'GET', data = null, id = null) {
    let url = `${API}?action=${action}`;
    if (id) url += `&id=${id}`;
    if (authToken) url += `&token=${authToken}`;
    
    const xhr = new XMLHttpRequest();
    xhr.open(method, url, false); // false = synchronous
    xhr.setRequestHeader('Content-Type', 'application/json');
    if (authToken) {
        xhr.setRequestHeader('Authorization', 'Bearer ' + authToken);
    }
    
    try {
        if (data && (method === 'POST' || method === 'PUT')) {
            xhr.send(JSON.stringify(data));
        } else {
            xhr.send();
        }
        
        const result = JSON.parse(xhr.responseText);
        return result.success ? result.data : null;
    } catch (error) {
        console.error('API Sync Error:', error);
        return null;
    }
}

// ============================================================
// AUTHENTICATION FUNCTIONS
// ============================================================

function handleAuthError() {
    authToken = null;
    currentUser = null;
    userPermissions = [];
    userRoles = [];
    localStorage.removeItem('authToken');
    // Drop every cached payload so the next login starts from a clean slate.
    invalidateCache('all');
    showLoginPage();
}

function checkAuth() {
    if (!authToken) {
        showLoginPage();
        return false;
    }
    
    // Verify token with server
    const result = apiCallSync('auth/me', 'GET');
    if (!result) {
        handleAuthError();
        return false;
    }
    
    currentUser = result.user;
    userRoles = result.roles || [];
    userPermissions = result.permissions || [];
    return true;
}

function hasPermission(module, action) {
    if (!userPermissions || userPermissions.length === 0) return false;
    return userPermissions.some(p => p.module === module && p.action === action);
}

function hasAnyPermission(module) {
    if (!userPermissions || userPermissions.length === 0) return false;
    return userPermissions.some(p => p.module === module);
}

function hasRole(roleCode) {
    if (!userRoles || userRoles.length === 0) return false;
    return userRoles.some(r => r.code === roleCode);
}

function isAdmin() {
    return hasRole('admin');
}

async function login(username, password) {
    try {
        const response = await fetch(`${API}?action=auth/login`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ username, password })
        });
        
        const result = await response.json();
        
        if (!result.success) {
            return { success: false, error: result.error };
        }
        
        authToken = result.data.token;
        currentUser = result.data.user;
        userRoles = result.data.roles || [];
        userPermissions = result.data.permissions || [];

        localStorage.setItem('authToken', authToken);

        // New user just logged in — drop every cached payload so the next render
        // re-fetches with this user's identity (visibility filter depends on it).
        invalidateCache('all');

        // Check if must change password
        if (currentUser.must_change_password) {
            showChangePasswordModal(true);
            return { success: true, mustChangePassword: true };
        }
        
        return { success: true };
    } catch (error) {
        console.error('Login error:', error);
        return { success: false, error: 'Network error' };
    }
}

async function logout() {
    try {
        await apiCall('auth/logout', 'POST');
    } catch (e) {
        console.error('Logout error:', e);
    }

    // If SSO logout, redirect to Keycloak logout
    if (keycloakToken) {
        const logoutUrl = `${KEYCLOAK_CONFIG.url}/realms/${KEYCLOAK_CONFIG.realm}/protocol/openid-connect/logout?redirect_uri=${encodeURIComponent(window.location.origin + '/datarover/')}`;
        keycloakToken = null;
        localStorage.removeItem('keycloakToken');
        window.location.href = logoutUrl;
        return;
    }

    authToken = null;
    currentUser = null;
    userPermissions = [];
    userRoles = [];
    localStorage.removeItem('authToken');
    // Drop every cached payload so the next login starts from a clean slate.
    invalidateCache('all');
    showLoginPage();
}

// ============================================================
// KEYCLOAK SSO FUNCTIONS
// ============================================================

function loginWithSSO() {
    // Build Keycloak authorization URL
    const redirectUri = encodeURIComponent(window.location.origin + '/datarover/');
    const authUrl = `${KEYCLOAK_CONFIG.url}/realms/${KEYCLOAK_CONFIG.realm}/protocol/openid-connect/auth?` +
        `client_id=${KEYCLOAK_CONFIG.clientId}` +
        `&redirect_uri=${redirectUri}` +
        `&response_type=code` +
        `&scope=openid profile email`;

    window.location.href = authUrl;
}

async function handleSSOCallback() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');

    if (!code) return false;

    try {
        // Exchange code for token
        const redirectUri = window.location.origin + '/datarover/';
        const tokenUrl = `${KEYCLOAK_CONFIG.url}/realms/${KEYCLOAK_CONFIG.realm}/protocol/openid-connect/token`;

        const response = await fetch(tokenUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body: new URLSearchParams({
                grant_type: 'authorization_code',
                client_id: KEYCLOAK_CONFIG.clientId,
                code: code,
                redirect_uri: redirectUri
            })
        });

        const tokenData = await response.json();

        if (tokenData.access_token) {
            keycloakToken = tokenData.access_token;
            localStorage.setItem('keycloakToken', keycloakToken);

            // Get user info from Keycloak
            const userInfoUrl = `${KEYCLOAK_CONFIG.url}/realms/${KEYCLOAK_CONFIG.realm}/protocol/openid-connect/userinfo`;
            const userInfoResponse = await fetch(userInfoUrl, {
                headers: { 'Authorization': 'Bearer ' + keycloakToken }
            });
            const userInfo = await userInfoResponse.json();

            // Create or login user in our system
            await loginSSOUser(userInfo);

            // Clean URL
            window.history.replaceState({}, document.title, window.location.pathname);
            return true;
        }
    } catch (error) {
        console.error('SSO callback error:', error);
    }
    return false;
}

async function loginSSOUser(userInfo) {
    // Try to login/register user via SSO
    try {
        const response = await fetch(`${API}?action=auth/sso_login`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                username: userInfo.preferred_username || userInfo.email,
                email: userInfo.email,
                first_name: userInfo.given_name || '',
                last_name: userInfo.family_name || '',
                sso_provider: 'keycloak',
                sso_id: userInfo.sub
            })
        });

        const result = await response.json();

        if (result.success) {
            authToken = result.data.token;
            currentUser = result.data.user;
            userRoles = result.data.roles || [];
            userPermissions = result.data.permissions || [];
            localStorage.setItem('authToken', authToken);
            invalidateCache('all');
            initApp();
            loadDashboard();
        } else {
            // Fallback: just show dashboard with SSO user info
            currentUser = {
                id: 0,
                username: userInfo.preferred_username || userInfo.email,
                full_name: (userInfo.given_name || '') + ' ' + (userInfo.family_name || ''),
                email: userInfo.email,
                role: 'user'
            };
            userRoles = [{ code: 'user', name: 'User' }];
            userPermissions = [];
            initApp();
            loadDashboard();
        }
    } catch (error) {
        console.error('SSO login error:', error);
        // Fallback to basic user
        currentUser = {
            id: 0,
            username: userInfo.preferred_username || userInfo.email,
            full_name: (userInfo.given_name || '') + ' ' + (userInfo.family_name || ''),
            email: userInfo.email,
            role: 'user'
        };
        initApp();
        loadDashboard();
    }
}

