async function handleLogin(event) {
    event.preventDefault();

    const loginMethod = document.getElementById('loginMethod').value;
    const username = document.getElementById('loginUsername').value;
    const password = document.getElementById('loginPassword').value;
    const btn = document.getElementById('loginBtn');
    const errorDiv = document.getElementById('loginError');

    btn.disabled = true;
    btn.textContent = 'Gözləyin...';
    errorDiv.style.display = 'none';

    let result;

    if (loginMethod === 'ldap') {
        // LDAP login
        result = await loginWithLDAP(username, password);
    } else {
        // Local login
        result = await login(username, password);
    }

    if (result.success) {
        if (result.mustChangePassword) {
            showToast('Parolunuzu dəyişməlisiniz');
        } else {
            initApp();
        }
    } else {
        errorDiv.textContent = result.error || 'Xəta baş verdi';
        errorDiv.style.display = 'block';
        btn.disabled = false;
        btn.textContent = 'Daxil ol';
    }
}

function onLoginMethodChange() {
    var method = document.getElementById('loginMethod').value;
    var usernameInput = document.getElementById('loginUsername');

    if (method === 'ldap') {
        usernameInput.placeholder = 'AD/LDAP istifadəçi adı';
    } else {
        usernameInput.placeholder = 'İstifadəçi adınızı daxil edin';
    }
}

async function loginWithLDAP(username, password) {
    try {
        // First verify with LDAP
        const ldapUrl = localStorage.getItem('ldapUrl');
        const ldapBaseDn = localStorage.getItem('ldapBaseDn');
        const ldapBindDn = localStorage.getItem('ldapBindDn');
        const ldapBindPassword = localStorage.getItem('ldapBindPassword');
        const ldapUsersDn = localStorage.getItem('ldapUsersDn');

        if (!ldapUrl || !ldapBaseDn) {
            return { success: false, error: 'LDAP konfiqurasiyası tamamlanmayıb. Settings-dən LDAP parametrlərini daxil edin.' };
        }

        // Verify LDAP credentials
        const verifyResponse = await fetch(API + '?action=ldap/verify', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                ldap_url: ldapUrl,
                base_dn: ldapBaseDn,
                bind_dn: ldapBindDn,
                bind_password: ldapBindPassword,
                users_dn: ldapUsersDn,
                username: username,
                password: password
            })
        });

        const verifyResult = await verifyResponse.json();

        if (!verifyResult.success) {
            return { success: false, error: verifyResult.error || 'LDAP authentication uğursuz' };
        }

        // If LDAP verified, create/login user in our system
        const defaultRole = localStorage.getItem('ldapDefaultRole') || 'viewer';
        const response = await fetch(API + '?action=auth/sso_login', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                username: username,
                email: verifyResult.data.email || username + '@ldap.local',
                first_name: verifyResult.data.first_name || '',
                last_name: verifyResult.data.last_name || '',
                sso_provider: 'ldap',
                sso_id: verifyResult.data.dn || username,
                default_role: defaultRole
            })
        });

        const result = await response.json();

        if (result.success) {
            authToken = result.data.token;
            currentUser = result.data.user;
            userRoles = result.data.roles || [];
            userPermissions = result.data.permissions || [];
            localStorage.setItem('authToken', authToken);
            invalidateCache('all');
            return { success: true };
        } else {
            return { success: false, error: result.error || 'Login uğursuz' };
        }
    } catch (error) {
        console.error('LDAP login error:', error);
        return { success: false, error: 'LDAP bağlantı xətası' };
    }
}

function showChangePasswordModal(required = false) {
    var existingModal = document.getElementById('changePasswordModal');
    if (existingModal) existingModal.remove();
    
    var modal = document.createElement('div');
    modal.id = 'changePasswordModal';
    modal.style.cssText = 'position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.5); display: flex; align-items: center; justify-content: center; z-index: 10000;';
    
    modal.innerHTML = `
        <div style="background: white; border-radius: 12px; padding: 24px; width: 90%; max-width: 400px; box-shadow: 0 20px 60px rgba(0,0,0,0.3);">
            <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px;">
                <h3 style="margin: 0; font-size: 18px; color: #1e293b;">${svgIcon('key', 18)} Parol Dəyişdir</h3>
                ${required ? '' : '<button onclick="document.getElementById(\'changePasswordModal\').remove()" style="background: none; border: none; font-size: 24px; cursor: pointer; color: #94a3b8;">×</button>'}
            </div>
            
            ${required ? '<p style="background: #fef3c7; color: #92400e; padding: 12px; border-radius: 8px; margin-bottom: 16px; font-size: 13px;">' + svgIcon('alert', 14) + ' İlk dəfə daxil olduğunuz üçün parolunuzu dəyişməlisiniz.</p>' : ''}
            
            <form onsubmit="handleChangePassword(event, ${required})">
                <div style="margin-bottom: 16px;">
                    <label style="display: block; font-size: 13px; font-weight: 600; color: #475569; margin-bottom: 6px;">Cari Parol</label>
                    <input type="password" id="currentPassword" required style="width: 100%; padding: 10px 12px; border: 2px solid #e2e8f0; border-radius: 8px; font-size: 14px; box-sizing: border-box;">
                </div>
                <div style="margin-bottom: 16px;">
                    <label style="display: block; font-size: 13px; font-weight: 600; color: #475569; margin-bottom: 6px;">Yeni Parol</label>
                    <input type="password" id="newPassword" required style="width: 100%; padding: 10px 12px; border: 2px solid #e2e8f0; border-radius: 8px; font-size: 14px; box-sizing: border-box;">
                </div>
                <div style="margin-bottom: 20px;">
                    <label style="display: block; font-size: 13px; font-weight: 600; color: #475569; margin-bottom: 6px;">Yeni Parol (təkrar)</label>
                    <input type="password" id="confirmPassword" required style="width: 100%; padding: 10px 12px; border: 2px solid #e2e8f0; border-radius: 8px; font-size: 14px; box-sizing: border-box;">
                </div>
                
                <div id="passwordError" style="display: none; background: #fef2f2; color: #dc2626; padding: 10px; border-radius: 8px; margin-bottom: 16px; font-size: 13px;"></div>
                
                <div style="background: #f0f9ff; border: 1px solid #bae6fd; border-radius: 8px; padding: 10px; margin-bottom: 16px; font-size: 12px; color: #0369a1;">
                    <strong>Parol tələbləri:</strong><br>
                    • Minimum 8 simvol<br>
                    • Ən az 1 böyük hərf (A-Z)<br>
                    • Ən az 1 kiçik hərf (a-z)<br>
                    • Ən az 1 rəqəm (0-9)<br>
                    • Ən az 1 xüsusi simvol (!@#$%...)
                </div>
                
                <button type="submit" style="width: 100%; padding: 12px; background: #3b82f6; color: white; border: none; border-radius: 8px; font-size: 14px; font-weight: 600; cursor: pointer;">
                    Parolı Dəyiş
                </button>
            </form>
        </div>
    `;
    
    document.body.appendChild(modal);
}

async function handleChangePassword(event, required) {
    event.preventDefault();
    
    const currentPassword = document.getElementById('currentPassword').value;
    const newPassword = document.getElementById('newPassword').value;
    const confirmPassword = document.getElementById('confirmPassword').value;
    const errorDiv = document.getElementById('passwordError');
    
    if (newPassword !== confirmPassword) {
        errorDiv.textContent = 'Parollar uyğun gəlmir';
        errorDiv.style.display = 'block';
        return;
    }
    
    try {
        const response = await fetch(`${API}?action=auth/change-password`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': 'Bearer ' + authToken
            },
            body: JSON.stringify({
                current_password: currentPassword,
                new_password: newPassword
            })
        });
        
        const result = await response.json();
        
        if (result.success) {
            document.getElementById('changePasswordModal').remove();
            showToast('Parol uğurla dəyişdirildi');
            if (required) {
                initApp();
            }
        } else {
            errorDiv.textContent = result.error || 'Xəta baş verdi';
            errorDiv.style.display = 'block';
        }
    } catch (error) {
        errorDiv.textContent = 'Şəbəkə xətası';
        errorDiv.style.display = 'block';
    }
}

