// Download failed rows as CSV
function downloadFailedRows(checkKey, filename) {
    var rows = window._scanFailedRows[checkKey] || [];
    
    if (rows.length === 0) {
        alert('Yükləmək üçün data yoxdur');
        return;
    }
    
    var columns = Object.keys(rows[0]);
    
    // Build CSV
    var csv = columns.join(',') + '\n';
    
    rows.forEach(function(row) {
        var values = columns.map(function(col) {
            var val = row[col];
            if (val === null) return '';
            if (typeof val === 'object') val = JSON.stringify(val);
            // Escape quotes and wrap in quotes if contains comma
            val = String(val).replace(/"/g, '""');
            if (val.indexOf(',') >= 0 || val.indexOf('\n') >= 0 || val.indexOf('"') >= 0) {
                val = '"' + val + '"';
            }
            return val;
        });
        csv += values.join(',') + '\n';
    });
    
    // Download
    var blob = new Blob(['\ufeff' + csv], { type: 'text/csv;charset=utf-8;' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = filename + '_' + new Date().toISOString().split('T')[0] + '.csv';
    a.click();
    URL.revokeObjectURL(url);
}

// Download failed rows as Excel (JSON format that Excel can open)
function downloadFailedRowsExcel(checkKey, filename) {
    var rows = window._scanFailedRows[checkKey] || [];
    
    if (rows.length === 0) {
        alert('Yükləmək üçün data yoxdur');
        return;
    }
    
    var columns = Object.keys(rows[0]);
    
    // Build HTML table for Excel
    var html = '<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel">' +
        '<head><meta charset="UTF-8"><!--[if gte mso 9]><xml><x:ExcelWorkbook><x:ExcelWorksheets><x:ExcelWorksheet>' +
        '<x:Name>Failed Rows</x:Name><x:WorksheetOptions><x:DisplayGridlines/></x:WorksheetOptions>' +
        '</x:ExcelWorksheet></x:ExcelWorksheets></x:ExcelWorkbook></xml><![endif]--></head>' +
        '<body><table border="1">';
    
    // Header
    html += '<tr style="background: #1e293b; color: white; font-weight: bold;">';
    columns.forEach(function(col) {
        html += '<th>' + col + '</th>';
    });
    html += '</tr>';
    
    // Data rows
    rows.forEach(function(row, idx) {
        html += '<tr style="background: ' + (idx % 2 === 0 ? '#fff' : '#f0f0f0') + ';">';
        columns.forEach(function(col) {
            var val = row[col];
            if (val === null) val = '';
            if (typeof val === 'object') val = JSON.stringify(val);
            html += '<td>' + val + '</td>';
        });
        html += '</tr>';
    });
    
    html += '</table></body></html>';
    
    // Download
    var blob = new Blob([html], { type: 'application/vnd.ms-excel;charset=utf-8;' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = filename + '_' + new Date().toISOString().split('T')[0] + '.xls';
    a.click();
    URL.revokeObjectURL(url);
}

// Download ALL failed rows from server (not limited to 100)
async function downloadAllFailedRows(checkId) {
    if (!checkId) {
        alert('Check ID yoxdur');
        return;
    }
    
    // Show loading
    var loadingDiv = document.createElement('div');
    loadingDiv.id = 'downloadLoadingOverlay';
    loadingDiv.style.cssText = 'position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.5); display: flex; align-items: center; justify-content: center; z-index: 99999;';
    loadingDiv.innerHTML = '<div style="background: white; padding: 30px 50px; border-radius: 12px; text-align: center;">' +
        '<div class="spinner" style="margin: 0 auto 15px;"></div>' +
        '<div style="font-weight: 600; color: #1e293b;">Bütün sətirlər yüklənir...</div>' +
        '<div style="font-size: 12px; color: #64748b; margin-top: 8px;">Bu bir az vaxt ala bilər</div>' +
    '</div>';
    document.body.appendChild(loadingDiv);
    
    try {
        var res = await fetch(API + '?action=download_failed_rows', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ check_id: checkId })
        });
        
        // Check if response is CSV (direct download) or JSON (error)
        var contentType = res.headers.get('Content-Type') || '';
        
        if (contentType.includes('text/csv')) {
            // Direct CSV download
            var blob = await res.blob();
            var disposition = res.headers.get('Content-Disposition') || '';
            var filename = 'failed_rows_' + new Date().toISOString().split('T')[0] + '.csv';
            
            // Try to extract filename from header
            var match = disposition.match(/filename="?([^"]+)"?/);
            if (match) {
                filename = match[1];
            }
            
            var url = URL.createObjectURL(blob);
            var a = document.createElement('a');
            a.href = url;
            a.download = filename;
            a.click();
            URL.revokeObjectURL(url);
            
            showNotification('CSV faylı yükləndi', 'success');
        } else {
            // JSON response (probably error)
            var result = await res.json();
            if (result.error) {
                alert('Xəta: ' + result.error);
            } else if (result.success && result.rows && result.rows.length > 0) {
                // Fallback: if somehow we got JSON rows, handle them
                var rows = result.rows;
                var checkName = result.check_name || 'failed_rows';
                
                var columns = Object.keys(rows[0]);
                var csv = columns.join(',') + '\n';
                
                rows.forEach(function(row) {
                    var values = columns.map(function(col) {
                        var val = row[col];
                        if (val === null) return '';
                        if (typeof val === 'object') val = JSON.stringify(val);
                        val = String(val).replace(/"/g, '""');
                        if (val.indexOf(',') >= 0 || val.indexOf('\n') >= 0 || val.indexOf('"') >= 0) {
                            val = '"' + val + '"';
                        }
                        return val;
                    });
                    csv += values.join(',') + '\n';
                });
                
                var blob = new Blob(['\ufeff' + csv], { type: 'text/csv;charset=utf-8;' });
                var url = URL.createObjectURL(blob);
                var a = document.createElement('a');
                a.href = url;
                a.download = checkName.replace(/[^a-zA-Z0-9_-]/g, '_') + '_all_' + new Date().toISOString().split('T')[0] + '.csv';
                a.click();
                URL.revokeObjectURL(url);
                
                showNotification(rows.length + ' sətir yükləndi', 'success');
            } else {
                alert('Xəta: Sətirlər tapılmadı');
            }
        }
    } catch (e) {
        console.error('Download error:', e);
        alert('Yükləmə xətası: ' + e.message);
    } finally {
        var overlay = document.getElementById('downloadLoadingOverlay');
        if (overlay) overlay.remove();
    }
}

