function onCheckColumnChange() {
    var select = document.getElementById('checkColumnSelect');
    var customInput = document.getElementById('checkColumnCustom');
    
    if (select && customInput) {
        if (select.value === '__custom__') {
            customInput.style.display = 'block';
            customInput.focus();
        } else {
            customInput.style.display = 'none';
        }
    }
}

function generateCheckPreview() {
    var type = document.getElementById('checkType').value;
    var tableName = getSelectedTableName() || 'table_name';
    var layerSelect = document.getElementById('checkLayerSelect');
    var layer = layerSelect ? layerSelect.value : '';
    
    // Build full table name with schema/layer
    var fullTableName = tableName;
    if (layer && tableName.indexOf('.') === -1) {
        fullTableName = layer + '.' + tableName;
    }
    
    var yaml = 'checks for ' + fullTableName + ':\n';
    
    switch(type) {
        case 'row_count':
            var op = document.getElementById('checkOperator')?.value || '>';
            var val = document.getElementById('checkValue')?.value || '0';
            yaml += '  - row_count ' + op + ' ' + val;
            break;
        case 'missing':
            var col = getSelectedColumnName() || 'column_name';
            var val = document.getElementById('checkValue')?.value || '0';
            yaml += '  - missing_count(' + col + ') = ' + val;
            break;
        case 'duplicate':
            var col = getSelectedColumnName() || 'column_name';
            var val = document.getElementById('checkValue')?.value || '0';
            yaml += '  - duplicate_count(' + col + ') = ' + val;
            break;
        case 'freshness':
            var col = getSelectedColumnName() || 'created_at';
            var val = document.getElementById('checkValue')?.value || '24';
            var unit = document.getElementById('checkUnit')?.value || 'h';
            yaml += '  - freshness(' + col + ') < ' + val + unit;
            break;
        case 'validity':
            var col = getSelectedColumnName() || 'column_name';
            var vType = document.getElementById('checkValidationType')?.value || 'email';
            if (vType === 'email') {
                yaml += '  - invalid_count(' + col + ') = 0:\n';
                yaml += '      valid format: email';
            } else if (vType === 'uuid') {
                yaml += '  - invalid_count(' + col + ') = 0:\n';
                yaml += '      valid format: uuid';
            } else if (vType === 'values') {
                yaml += '  - invalid_count(' + col + ') = 0:\n';
                yaml += "      valid values: ['value1', 'value2']";
            } else if (vType === 'regex') {
                yaml += '  - invalid_count(' + col + ') = 0:\n';
                yaml += '      valid regex: "^[A-Z]{2}[0-9]+$"';
            }
            break;
        case 'custom':
            var sql = document.getElementById('checkCustomSql')?.value || 'SELECT * FROM table WHERE condition';
            yaml += '  - failed rows:\n';
            yaml += '      fail query: |\n';
            sql.split('\n').forEach(function(line) {
                yaml += '        ' + line + '\n';
            });
            break;
    }
    
    document.getElementById('checkPreview').textContent = yaml;
}

async function testCheckNow() {
    var type = document.getElementById('checkType').value;
    var layer = getSelectedLayerName();
    var table = getSelectedTableName();
    var sourceId = document.getElementById('checkDataSource')?.value || null;
    var resultDiv = document.getElementById('checkTestResult');
    var btn = document.getElementById('testCheckBtn');
    
    if (!table) {
        alert(t('Select Table'));
        return;
    }
    
    // Show loading
    btn.disabled = true;
    btn.innerHTML = '⏳ Test edilir...';
    resultDiv.style.display = 'block';
    resultDiv.innerHTML = '<div style="padding: 16px; background: #f8fafc; border-radius: 8px; text-align: center;"><div class="spinner" style="margin: 0 auto;"></div></div>';
    
    // Build check data
    var checkData = {
        check_type: type,
        layer_name: layer,
        table_name: table,
        source_id: sourceId,
        check_name: 'Test Check',
        target_value: document.getElementById('checkTarget')?.value || 100,
        threshold_value: document.getElementById('checkThreshold')?.value || 90
    };
    
    if (type === 'row_count') {
        checkData.operator = document.getElementById('checkOperator')?.value || '>';
        checkData.threshold_value = document.getElementById('checkValue')?.value || '0';
    } else if (type === 'missing' || type === 'duplicate') {
        checkData.column_name = getSelectedColumnName();
        checkData.threshold_value = document.getElementById('checkValue')?.value || '0';
    } else if (type === 'freshness') {
        checkData.column_name = getSelectedColumnName();
        var val = document.getElementById('checkValue')?.value || '24';
        var unit = document.getElementById('checkUnit')?.value || 'h';
        checkData.threshold_value = val + unit;
    } else if (type === 'custom') {
        checkData.custom_sql = document.getElementById('checkCustomSql')?.value;
    }
    
    try {
        var res = await fetch(API + '?action=run_check', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(checkData)
        });
        var result = await res.json();
        if (result.data) result = result.data;
        
        var technicalStatus = result.technical_status || (result.outcome === 'error' ? 'error' : 'success');
        var qualityStatus = result.quality_status || result.outcome || 'unknown';
        var value = result.value !== undefined ? result.value : '-';
        var message = result.message || '';
        var percentage = result.percentage || 0;
        var totalRows = result.total_rows || 0;
        var validRows = result.valid_rows || 0;
        var invalidRows = result.invalid_rows || value;
        var targetValue = parseFloat(checkData.target_value) || 100;
        var thresholdValue = parseFloat(checkData.threshold_value) || 90;
        
        // Calculate percentage if not provided
        if ((!percentage || percentage === 0) && totalRows > 0) {
            percentage = (validRows / totalRows) * 100;
        }
        
        // Technical status box
        var techBg, techColor, techIcon, techLabel;
        if (technicalStatus === 'success') {
            techBg = '#d1fae5'; techColor = '#047857'; techIcon = svgIcon('check-circle', 20); techLabel = 'SUCCESS';
        } else {
            techBg = '#fee2e2'; techColor = '#dc2626'; techIcon = svgIcon('x', 20); techLabel = 'ERROR';
        }
        
        // Quality status (only if technical success)
        var qualityHtml = '';
        if (technicalStatus === 'success') {
            var qualBg, qualColor, qualIcon, qualLabel;
            
            // Determine quality based on percentage and thresholds
            if (percentage > 0) {
                if (percentage >= targetValue) {
                    qualBg = '#d1fae5'; qualColor = '#047857'; qualIcon = svgIcon('check-circle', 32); qualLabel = 'PASS';
                } else if (percentage >= thresholdValue) {
                    qualBg = '#fef3c7'; qualColor = '#b45309'; qualIcon = svgIcon('alert', 32); qualLabel = 'WARN';
                } else {
                    qualBg = '#fee2e2'; qualColor = '#dc2626'; qualIcon = svgIcon('x', 32); qualLabel = 'FAIL';
                }
            } else {
                // Fallback to outcome
                if (qualityStatus === 'pass') {
                    qualBg = '#d1fae5'; qualColor = '#047857'; qualIcon = svgIcon('check-circle', 32); qualLabel = 'PASS';
                } else if (qualityStatus === 'warn') {
                    qualBg = '#fef3c7'; qualColor = '#b45309'; qualIcon = svgIcon('alert', 32); qualLabel = 'WARN';
                } else {
                    qualBg = '#fee2e2'; qualColor = '#dc2626'; qualIcon = svgIcon('x', 32); qualLabel = 'FAIL';
                }
            }
            
            qualityHtml = '<div style="padding: 16px; background: ' + qualBg + '; border-radius: 8px; border: 1px solid ' + qualColor + '30; margin-top: 8px;">' +
                '<div style="display: flex; align-items: center; gap: 12px;">' +
                    '<div style="font-size: 32px;">' + qualIcon + '</div>' +
                    '<div style="flex: 1;">' +
                        '<div style="font-weight: 700; color: ' + qualColor + '; font-size: 16px;">' + qualLabel + '</div>' +
                        '<div style="color: ' + qualColor + '; font-size: 13px; margin-top: 4px;">' + message + '</div>' +
                    '</div>' +
                    '<div style="text-align: right;">' +
                        (percentage > 0 ? '<div style="font-size: 24px; font-weight: 700; color: ' + qualColor + ';">' + percentage.toFixed(1) + '%</div>' : '') +
                        '<div style="font-size: 20px; font-weight: 700; color: ' + qualColor + ';">' + value + '</div>' +
                        '<div style="font-size: 11px; color: ' + qualColor + '80;">uyğunsuz sətir</div>' +
                    '</div>' +
                '</div>' +
                (totalRows > 0 ? '<div style="margin-top: 8px; font-size: 12px; color: ' + qualColor + ';">' + validRows + ' valid / ' + invalidRows + ' invalid (cəmi: ' + totalRows + ')</div>' : '') +
            '</div>';
            
            // Add failed rows view if available
            var failedRows = result.failed_rows || [];
            if (failedRows.length > 0) {
                window._testFailedRows = failedRows;
                var totalFailedDisplay = invalidRows > 0 ? invalidRows : failedRows.length;
                qualityHtml += '<div style="margin-top: 12px; padding: 12px; background: #f8fafc; border-radius: 8px; border: 1px solid #e2e8f0;">' +
                    '<div style="display: flex; justify-content: space-between; align-items: center;">' +
                        '<span style="font-weight: 600; color: #475569;">' + svgIcon('eye', 14) + ' Uyğunsuz sətirlər: ' + totalFailedDisplay + ' (' + failedRows.length + ' nümunə)</span>' +
                        '<button onclick="showTestFailedRows()" style="padding: 6px 12px; background: #3b82f6; color: white; border: none; border-radius: 6px; cursor: pointer; font-size: 12px;">Göstər</button>' +
                    '</div>' +
                '</div>';
            }
        }
        
        resultDiv.innerHTML = 
            '<div style="padding: 12px; background: ' + techBg + '; border-radius: 8px; border: 1px solid ' + techColor + '30;">' +
                '<div style="display: flex; align-items: center; gap: 8px;">' +
                    '<span style="font-size: 20px;">' + techIcon + '</span>' +
                    '<span style="font-weight: 600; color: ' + techColor + ';">Technical: ' + techLabel + '</span>' +
                '</div>' +
            '</div>' +
            qualityHtml;
        
    } catch (e) {
        resultDiv.innerHTML = 
            '<div style="padding: 16px; background: #fee2e2; border-radius: 8px; color: #dc2626;">' +
                svgIcon('x', 16) + ' Xəta: ' + e.message +
            '</div>';
    } finally {
        btn.disabled = false;
        btn.innerHTML = svgIcon('play', 14) + ' Test Et';
    }
}

function copyCheckYaml() {
    var yaml = document.getElementById('checkPreview').textContent;
    navigator.clipboard.writeText(yaml).then(function() {
        alert('YAML kopyalandı! İndi checks/ qovluğuna yapışdıra bilərsiniz.');
    });
}

function showTestFailedRows() {
    var rows = window._testFailedRows || [];
    if (rows.length === 0) {
        alert('Uyğunsuz sətir yoxdur');
        return;
    }
    
    // Build table HTML
    var columns = Object.keys(rows[0]);
    var tableHtml = '<table style="width: 100%; border-collapse: collapse; font-size: 12px;">' +
        '<thead><tr style="background: #f1f5f9;">';
    
    columns.forEach(function(col) {
        tableHtml += '<th style="padding: 8px 12px; text-align: left; border-bottom: 2px solid #e2e8f0; font-weight: 600; color: #475569;">' + col + '</th>';
    });
    tableHtml += '</tr></thead><tbody>';
    
    rows.forEach(function(row, idx) {
        var bgColor = idx % 2 === 0 ? '#ffffff' : '#f8fafc';
        tableHtml += '<tr style="background: ' + bgColor + ';">';
        columns.forEach(function(col) {
            var val = row[col];
            if (val === null) val = '<span style="color: #dc2626; font-style: italic;">NULL</span>';
            else if (val === '') val = '<span style="color: #f59e0b; font-style: italic;">(boş)</span>';
            tableHtml += '<td style="padding: 8px 12px; border-bottom: 1px solid #e2e8f0; max-width: 200px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">' + val + '</td>';
        });
        tableHtml += '</tr>';
    });
    tableHtml += '</tbody></table>';
    
    // Create modal
    var modal = document.createElement('div');
    modal.className = 'modal-overlay';
    modal.id = 'testFailedRowsModal';
    modal.onclick = function(e) { if (e.target === modal) modal.remove(); };
    
    modal.innerHTML = 
        '<div class="modal-content" style="width: 95%; max-width: 1000px; max-height: 80vh; overflow: auto;">' +
            '<div class="modal-header">' +
                '<h3 style="margin: 0;">' + svgIcon('eye', 18) + ' Uyğunsuz Sətirlər (' + rows.length + ')</h3>' +
                '<button class="modal-close" onclick="document.getElementById(\'testFailedRowsModal\').remove()">×</button>' +
            '</div>' +
            '<div class="modal-body" style="padding: 16px; overflow-x: auto;">' +
                tableHtml +
            '</div>' +
            '<div class="modal-footer">' +
                '<button onclick="downloadTestFailedRows()" style="padding: 10px 20px; background: #10b981; color: white; border: none; border-radius: 8px; cursor: pointer; font-weight: 600;">' + svgIcon('upload', 14) + ' CSV Yüklə</button>' +
                '<button onclick="document.getElementById(\'testFailedRowsModal\').remove()" style="padding: 10px 20px; background: #e2e8f0; color: #475569; border: none; border-radius: 8px; cursor: pointer; margin-left: 8px;">Bağla</button>' +
            '</div>' +
        '</div>';
    
    document.body.appendChild(modal);
}

function downloadTestFailedRows() {
    var rows = window._testFailedRows || [];
    if (rows.length === 0) return;
    
    var columns = Object.keys(rows[0]);
    var csvContent = columns.join(',') + '\n';
    
    rows.forEach(function(row) {
        var rowValues = columns.map(function(col) {
            var val = row[col];
            if (val === null || val === undefined) return '';
            val = String(val).replace(/"/g, '""');
            return '"' + val + '"';
        });
        csvContent += rowValues.join(',') + '\n';
    });
    
    var blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    var link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'uygunsuz_setirler_' + new Date().toISOString().slice(0, 10) + '.csv';
    link.click();
}

async function saveCheck() {
    var type = document.getElementById('checkType').value;
    var layer = getSelectedLayerName();
    var table = getSelectedTableName();
    var sourceId = document.getElementById('checkDataSource')?.value || null;
    var name = document.getElementById('checkName').value;
    var kpiName = document.getElementById('checkKpiName')?.value || '';
    var yaml = document.getElementById('checkPreview').textContent;
    var editCheckId = document.getElementById('editCheckId')?.value;
    var targetValue = document.getElementById('checkTarget')?.value || 100;
    var thresholdValue = document.getElementById('checkThreshold')?.value || 90;
    
    if (!table) {
        alert(t('Select Table'));
        return;
    }
    
    // Check if column is selected (for catalog linking)
    var columnName = getSelectedColumnName();
    if (!columnName && (type === 'missing' || type === 'duplicate' || type === 'freshness' || type === 'validity' || type === 'custom')) {
        var shouldContinue = confirm('Sütun seçilməyib! \n\nCheck kataloqa bağlanmayacaq.\n\nDavam etmək istəyirsiniz?');
        if (!shouldContinue) {
            return;
        }
    }
    
    var checkData = {
        check_type: type,
        layer_name: layer,
        table_name: table,
        source_id: sourceId,
        check_name: name || type + '_' + table,
        kpi_name: kpiName,
        yaml_content: yaml,
        target_value: parseFloat(targetValue),
        threshold_value: parseFloat(thresholdValue),
        status: 'active'
    };
    
    // Get additional fields based on type
    if (type === 'missing' || type === 'duplicate' || type === 'freshness' || type === 'validity') {
        checkData.column_name = getSelectedColumnName();
    }
    if (type === 'row_count' && document.getElementById('checkOperator')) {
        checkData.operator = document.getElementById('checkOperator').value;
    }
    if (type === 'custom') {
        checkData.custom_sql = document.getElementById('checkCustomSql')?.value;
        // Also save column for catalog linking
        checkData.column_name = getSelectedColumnName();
    }
    
    // If editing, add the ID
    if (editCheckId) {
        checkData.id = editCheckId;
    }
    
    try {
        var res = await fetch(API + '?action=soda_checks', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(checkData)
        });
        var json = await res.json();
        
        if (json.success) {
            alert(editCheckId ? 'Check uğurla yeniləndi!' : 'Check uğurla yadda saxlanıldı!');
            document.getElementById('sodaCheckBuilderModal').remove();
            window._editingCheck = null;
            // Refresh the quality page if we're on it
            if (typeof loadSodaChecksForQuality === 'function') {
                loadSodaChecksForQuality();
            }
            loadSodaChecks();
        } else {
            alert('Xəta: ' + (json.error || 'Naməlum xəta'));
        }
    } catch (e) {
        alert('Xəta: ' + e.message);
    }
}

