async function runCheck(checkId) {
    var btn = document.getElementById('run-btn-' + checkId);
    var resultCell = document.getElementById('check-result-' + checkId);
    
    if (btn) {
        btn.disabled = true;
        btn.innerHTML = '⏳';
    }
    if (resultCell) {
        resultCell.innerHTML = '<span style="color: #f59e0b;">⏳ İşləyir...</span>';
    }
    
    try {
        var res = await fetch(API + '?action=run_check', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ check_id: checkId })
        });
        var result = await res.json();
        
        if (result.data) result = result.data;
        
        var outcome = result.outcome || 'error';
        var technicalStatus = result.technical_status || (outcome === 'error' ? 'error' : 'success');
        var qualityStatus = result.quality_status || outcome;
        var percentage = result.percentage !== undefined ? result.percentage : null;
        var kpiName = result.kpi_name || '';
        var failedRowsCount = result.failed_rows_count || result.value || 0;
        var message = result.message || '';
        var totalRows = result.total_rows || 0;
        var validRows = result.valid_rows || 0;
        var invalidRows = result.invalid_rows || failedRowsCount;
        var targetValue = parseFloat(result.target_value) || 100;
        var thresholdValue = parseFloat(result.threshold_value) || 90;
        
        // Calculate percentage from valid/total if not provided or is 0
        if ((!percentage || percentage === 0) && totalRows > 0) {
            percentage = (validRows / totalRows) * 100;
        }
        
        // Technical status badge
        var techHtml = '';
        if (technicalStatus === 'success') {
            techHtml = '<span style="padding: 3px 8px; background: #d1fae5; color: #047857; border-radius: 6px; font-size: 10px; font-weight: 600;">' + svgIcon('check-circle', 10) + ' OK</span>';
        } else {
            techHtml = '<span style="padding: 3px 8px; background: #fee2e2; color: #dc2626; border-radius: 6px; font-size: 10px; font-weight: 600;">' + svgIcon('x', 10) + ' ERROR</span>';
        }
        
        // Quality status badge (only if technical success)
        var qualityHtml = '';
        if (technicalStatus === 'success') {
            var qualIcon, qualBg, qualColor, qualLabel;
            if (qualityStatus === 'pass') {
                qualIcon = svgIcon('check-circle', 10); qualBg = '#d1fae5'; qualColor = '#047857'; qualLabel = 'PASS';
            } else if (qualityStatus === 'warn') {
                qualIcon = svgIcon('alert', 10); qualBg = '#fef3c7'; qualColor = '#b45309'; qualLabel = 'WARN';
            } else {
                qualIcon = svgIcon('x', 10); qualBg = '#fee2e2'; qualColor = '#dc2626'; qualLabel = 'FAIL';
            }
            qualityHtml = '<span style="padding: 3px 8px; background: ' + qualBg + '; color: ' + qualColor + '; border-radius: 6px; font-size: 10px; font-weight: 600; margin-left: 4px;">' + qualIcon + ' ' + qualLabel + '</span>';
        }
        
        // KPI percentage badge - color based on target/threshold
        var kpiHtml = '';
        if (percentage !== null && percentage !== undefined && percentage > 0) {
            var pctColor, pctBg;
            if (percentage >= targetValue) {
                pctColor = '#047857'; pctBg = '#d1fae5'; // Green - meets target
            } else if (percentage >= thresholdValue) {
                pctColor = '#b45309'; pctBg = '#fef3c7'; // Amber - above threshold
            } else {
                pctColor = '#dc2626'; pctBg = '#fee2e2'; // Red - below threshold
            }
            kpiHtml = '<div style="margin-top: 4px;"><span style="padding: 4px 10px; background: ' + pctBg + '; color: ' + pctColor + '; border-radius: 12px; font-size: 13px; font-weight: 700;">' + percentage.toFixed(1) + '%</span></div>';
        }
        
        // Show issue count - always show if there are any invalid rows
        var detailHtml = '';
        if (invalidRows > 0 || failedRowsCount > 0) {
            var issueCount = invalidRows || failedRowsCount;
            detailHtml = '<div style="font-size: 11px; margin-top: 4px;">';
            if (totalRows > 0) {
                detailHtml += '<span style="color: #10b981; font-weight: 600;">' + validRows + '</span> valid / ' +
                    '<span style="color: #dc2626; font-weight: 600;">' + issueCount + '</span> invalid' +
                    ' <span style="color: #94a3b8;">(cəmi: ' + totalRows + ')</span>';
            } else {
                detailHtml += '<span style="color: #dc2626; font-weight: 600;">' + issueCount + ' uyğunsuz sətir</span>';
            }
            detailHtml += '</div>';
        } else if (qualityStatus === 'pass') {
            detailHtml = '<div style="font-size: 11px; color: #10b981; margin-top: 4px;">' + svgIcon('check', 10) + ' Təmiz</div>';
        }
        
        if (resultCell) {
            // Show both technical and quality status
            resultCell.innerHTML = '<div>' + techHtml + qualityHtml + '</div>' + kpiHtml + detailHtml;
            resultCell.title = message;
        }
        
        // Show notification with color based on threshold
        var notifType = 'info';
        if (technicalStatus === 'error') {
            notifType = 'error';
        } else if (percentage >= targetValue) {
            notifType = 'success';
        } else if (percentage >= thresholdValue) {
            notifType = 'warning';
        } else {
            notifType = 'error';
        }
        showNotification(kpiName + ': ' + (percentage ? percentage.toFixed(1) + '%' : qualityStatus), notifType);
        
        // Refresh scans list in background
        fetchSodaScans();
        
        // Refresh Nəticələr tab if on Data Quality page
        if (typeof loadSodaResultsForQuality === 'function') {
            loadSodaResultsForQuality();
        }
        
        // Refresh Check-lər tab to update SON NƏTİCƏ
        if (typeof loadChecksForQuality === 'function') {
            loadChecksForQuality();
        }
        
        // Refresh check detail modal if open
        if (document.getElementById('checkDetailModal')) {
            showCheckDetailModal(checkId);
        }
        
    } catch (e) {
        console.error('Run check error:', e);
        if (resultCell) {
            resultCell.innerHTML = '<span style="color: #dc2626;">' + svgIcon('x', 12) + ' Xəta</span>';
        }
    } finally {
        if (btn) {
            btn.disabled = false;
            btn.innerHTML = svgIcon('play', 14);
        }
    }
}

async function runAllChecks(tableName) {
    if (!confirm('Bütün aktiv check-ləri işlətmək istəyirsiniz?')) return;
    
    // Show loading
    var container = document.getElementById('checksListContainer');
    var originalHtml = container.innerHTML;
    container.innerHTML = '<div style="text-align: center; padding: 40px;">' +
        '<div class="spinner" style="margin: 0 auto 16px;"></div>' +
        '<div style="color: #64748b;">Check-lər işlədilir...</div>' +
    '</div>';
    
    try {
        var res = await fetch(API + '?action=run_all_checks', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ table_name: tableName || null })
        });
        var result = await res.json();
        
        if (result.data) result = result.data;
        
        // Show result summary modal
        showRunResultsModal(result);
        
        // Reload checks list
        loadChecksToManager();
        
        // Refresh scans
        fetchSodaScans();
        
    } catch (e) {
        console.error('Run all checks error:', e);
        alert('Xəta: ' + e.message);
        container.innerHTML = originalHtml;
    }
}

function showRunResultsModal(result) {
    var modal = document.createElement('div');
    modal.className = 'modal-overlay';
    modal.id = 'runResultsModal';
    modal.onclick = function(e) { if (e.target === modal) modal.remove(); };
    
    var score = result.score || 0;
    var scoreColor = score >= 90 ? '#10b981' : score >= 70 ? '#f59e0b' : '#ef4444';
    
    var checksHtml = '';
    if (result.results && result.results.length > 0) {
        checksHtml = '<div style="overflow-x: auto; border: 1px solid #e2e8f0; border-radius: 8px; margin-top: 20px;">' +
            '<table style="width: 100%; border-collapse: collapse; font-size: 13px;">' +
            '<thead><tr style="background: #f1f5f9;">' +
                '<th style="padding: 10px 14px; text-align: left;">CHECK</th>' +
                '<th style="padding: 10px 14px; text-align: left;">CƏDVƏL</th>' +
                '<th style="padding: 10px 14px; text-align: center;">NƏTİCƏ</th>' +
                '<th style="padding: 10px 14px; text-align: right;">DƏYƏR</th>' +
            '</tr></thead><tbody>';
        
        result.results.forEach(function(r, i) {
            var outcome = r.outcome || 'unknown';
            var outcomeHtml = outcome === 'pass' 
                ? '<span style="padding: 4px 10px; background: #d1fae5; color: #047857; border-radius: 12px; font-size: 12px;">🟢</span>'
                : outcome === 'warning'
                ? '<span style="padding: 4px 10px; background: #fef3c7; color: #b45309; border-radius: 12px; font-size: 12px;">🟡</span>'
                : '<span style="padding: 4px 10px; background: #fee2e2; color: #dc2626; border-radius: 12px; font-size: 12px;">🔴</span>';
            
            checksHtml += '<tr style="background: ' + (i % 2 === 0 ? '#fff' : '#f8fafc') + ';">' +
                '<td style="padding: 10px 14px; font-weight: 500;">' + (r.check_name || '-') + '</td>' +
                '<td style="padding: 10px 14px; color: #64748b;">' + (r.table_name || '-') + '</td>' +
                '<td style="padding: 10px 14px; text-align: center;">' + outcomeHtml + '</td>' +
                '<td style="padding: 10px 14px; text-align: right; font-family: monospace;">' + (r.value !== undefined ? r.value : '-') + '</td>' +
            '</tr>';
        });
        checksHtml += '</tbody></table></div>';
    }
    
    modal.innerHTML = 
        '<div class="modal-content" style="width: 95%; max-width: 800px;">' +
            '<div class="modal-header">' +
                '<h3 style="margin: 0;">' + svgIcon('chart', 20) + ' Batch Run Nəticəsi</h3>' +
                '<button class="modal-close" onclick="document.getElementById(\'runResultsModal\').remove()">×</button>' +
            '</div>' +
            '<div class="modal-body" style="padding: 24px;">' +
                // Summary
                '<div style="display: flex; gap: 16px; flex-wrap: wrap; margin-bottom: 20px;">' +
                    '<div style="flex: 1; min-width: 120px; text-align: center; padding: 20px; background: linear-gradient(135deg, ' + scoreColor + '20, ' + scoreColor + '05); border-radius: 12px; border: 2px solid ' + scoreColor + ';">' +
                        '<div style="font-size: 32px; font-weight: 800; color: ' + scoreColor + ';">' + score.toFixed(0) + '%</div>' +
                        '<div style="font-size: 12px; color: #64748b;">Score</div>' +
                    '</div>' +
                    '<div style="flex: 1; min-width: 100px; text-align: center; padding: 20px; background: #f0fdf4; border-radius: 12px;">' +
                        '<div style="font-size: 28px; font-weight: 700; color: #10b981;">' + (result.passed || 0) + '</div>' +
                        '<div style="font-size: 12px; color: #64748b;">' + svgIcon('check-circle', 12) + ' Keçdi</div>' +
                    '</div>' +
                    '<div style="flex: 1; min-width: 100px; text-align: center; padding: 20px; background: #fef2f2; border-radius: 12px;">' +
                        '<div style="font-size: 28px; font-weight: 700; color: #ef4444;">' + (result.failed || 0) + '</div>' +
                        '<div style="font-size: 12px; color: #64748b;">' + svgIcon('x', 12) + ' Uğursuz</div>' +
                    '</div>' +
                    '<div style="flex: 1; min-width: 100px; text-align: center; padding: 20px; background: #f8fafc; border-radius: 12px;">' +
                        '<div style="font-size: 28px; font-weight: 700; color: #1e293b;">' + (result.total_checks || 0) + '</div>' +
                        '<div style="font-size: 12px; color: #64748b;">Cəmi</div>' +
                    '</div>' +
                '</div>' +
                checksHtml +
            '</div>' +
        '</div>';
    
    document.body.appendChild(modal);
}

async function viewCheckYaml(checkId) {
    try {
        var res = await fetch(API + '?action=soda_checks&id=' + checkId);
        var json = await res.json();
        var check = json.data || json;
        
        alert('YAML:\n\n' + (check.yaml_content || 'Məzmun yoxdur'));
    } catch (e) {
        alert('Xəta: ' + e.message);
    }
}

async function deleteCheck(checkId) {
    if (!confirm('Bu check-i silmək istədiyinizə əminsiniz?')) return;
    
    try {
        var res = await fetch(API + '?action=soda_checks&id=' + checkId, {
            method: 'DELETE'
        });
        var json = await res.json();
        
        if (json.success) {
            // Refresh all check lists
            loadChecksToManager();
            if (typeof loadSodaChecksForQuality === 'function') {
                loadSodaChecksForQuality();
            }
            if (typeof loadSodaResultsForQuality === 'function') {
                loadSodaResultsForQuality();
            }
        } else {
            alert('Xəta: ' + json.error);
        }
    } catch (e) {
        alert('Xəta: ' + e.message);
    }
}

async function exportAllChecks() {
    try {
        var res = await fetch(API + '?action=soda_checks');
        var json = await res.json();
        var checks = json.data && json.data.data ? json.data.data : (json.data || []);
        
        var yaml = '# MIM Soda Checks\n# Generated: ' + new Date().toISOString() + '\n\n';
        
        checks.forEach(function(check) {
            yaml += check.yaml_content + '\n\n';
        });
        
        // Download as file
        var blob = new Blob([yaml], { type: 'text/yaml' });
        var url = URL.createObjectURL(blob);
        var a = document.createElement('a');
        a.href = url;
        a.download = 'datarover_checks.yml';
        a.click();
        URL.revokeObjectURL(url);
    } catch (e) {
        alert('Export xətası: ' + e.message);
    }
}

function loadGlossary() {
    setActive('glossary');
    navigateTo('/glossary', true);

    // Reset filters and pagination when loading glossary
    window._glossaryFilters = { search: '', domain: '', status: '' };
    glossaryPagination.currentPage = 1;

    // Load all data from database. Force reload so the visibility filter (which
    // depends on the current user) is always re-applied — cached results from a
    // previous session/user must not leak through.
    loadCatalogFromStorage(true);
    loadDomainsFromDB();
    loadGlossaryFromStorage(true);
    loadGovernanceFromStorage(true);
    
    var html = getGlossaryStyles();

    // Compute stats
    var totalTerms = glossaryData.terms.length;
    var approvedTerms = glossaryData.terms.filter(function(t) { return t.status === 'approved' || t.status === 'published'; }).length;
    var draftTerms = glossaryData.terms.filter(function(t) { return t.status === 'draft'; }).length;
    var reviewTerms = glossaryData.terms.filter(function(t) { return t.status === 'review' || t.status === 'pending'; }).length;
    var totalDomains = glossaryData.domains.length;
    var stakeholderCount = governanceData.stakeholders ? governanceData.stakeholders.length : 0;
    var workflowCount = governanceData.workflowSteps ? governanceData.workflowSteps.length : 0;

    // ===== SINGLE UNIFIED CONTAINER =====
    html += '<div class="glossary-container">';

    // Top bar: stats inline + actions
    html += '<div class="glossary-topbar">' +
        '<div class="glossary-stats-inline">' +
            '<div class="stat-inline"><span class="stat-inline-value">' + totalTerms + '</span><span class="stat-inline-label">' + t('Terms') + '</span></div>' +
            '<div class="stat-inline-divider"></div>' +
            '<div class="stat-inline"><span class="stat-inline-dot" style="background:#2563eb;"></span><span class="stat-inline-value">' + approvedTerms + '</span><span class="stat-inline-label">' + t('Approved') + '</span></div>' +
            '<div class="stat-inline"><span class="stat-inline-dot" style="background:#93c5fd;"></span><span class="stat-inline-value">' + draftTerms + '</span><span class="stat-inline-label">' + t('Draft') + '</span></div>' +
            '<div class="stat-inline"><span class="stat-inline-dot" style="background:#60a5fa;"></span><span class="stat-inline-value">' + reviewTerms + '</span><span class="stat-inline-label">Yoxlamada</span></div>' +
            '<div class="stat-inline"><span class="stat-inline-dot" style="background:#1d4ed8;"></span><span class="stat-inline-value">' + totalDomains + '</span><span class="stat-inline-label">' + t('Domains') + '</span></div>' +
        '</div>' +
        '<div class="glossary-actions">' +
            (canCreateTerm() ? '<button class="glossary-btn" onclick="showAddTermModal()">' + svgIcon('plus', 14) + ' ' + t('Add Term') + '</button>' : '') +
            '<button class="glossary-btn glossary-btn-secondary" onclick="exportGlossary()">' + svgIcon('upload', 14) + ' ' + t('Export') + '</button>' +
        '</div>' +
    '</div>';

    // Tab navigation
    html += '<div class="glossary-nav">' +
        '<div class="glossary-tabs">' +
            '<button class="tab-btn active" data-tab="terms" onclick="showGlossaryTab(\'terms\')">' +
                '<span class="tab-icon">' + svgIcon('book', 15) + '</span><span class="tab-text">' + t('Terms') + '</span>' +
                (totalTerms > 0 ? '<span class="td-tab-count">' + totalTerms + '</span>' : '') +
            '</button>' +
            '<button class="tab-btn" data-tab="domains" onclick="showGlossaryTab(\'domains\')">' +
                '<span class="tab-icon">' + svgIcon('folder', 15) + '</span><span class="tab-text">' + t('Domains') + '</span>' +
                (totalDomains > 0 ? '<span class="td-tab-count">' + totalDomains + '</span>' : '') +
            '</button>' +
            '<button class="tab-btn" data-tab="stakeholders" onclick="showGlossaryTab(\'stakeholders\')">' +
                '<span class="tab-icon">' + svgIcon('users', 15) + '</span><span class="tab-text">' + t('Stakeholders') + '</span>' +
                (stakeholderCount > 0 ? '<span class="td-tab-count">' + stakeholderCount + '</span>' : '') +
            '</button>' +
            '<button class="tab-btn" data-tab="workflow" onclick="showGlossaryTab(\'workflow\')">' +
                '<span class="tab-icon">' + svgIcon('settings', 15) + '</span><span class="tab-text">' + t('Workflow') + '</span>' +
                (workflowCount > 0 ? '<span class="td-tab-count">' + workflowCount + '</span>' : '') +
            '</button>' +
            '<label class="tab-btn governance-tab" style="margin: 0; cursor: pointer; display: flex; align-items: center; gap: 8px;" title="' + t('Governance Mode') + '">' +
                '<input type="checkbox" id="governanceMode" onchange="toggleGovernanceMode()" style="cursor: pointer; margin: 0;">' +
                '<span class="tab-icon">' + svgIcon('crown', 15) + '</span><span class="tab-text">' + t('Governance Mode') + '</span>' +
            '</label>' +
        '</div>' +
    '</div>';

    // Workflow steps for status filter
    var sortedSteps = governanceData.workflowSteps.slice().sort(function(a, b) { return a.order - b.order; });

    // Tab contents - all inside the container
    html += '<div class="glossary-body" id="glossaryContent">';

    // Terms tab
    html += '<div id="tab-terms" class="tab-content active">';
    html += '<div class="glossary-filters">' +
        '<input type="text" id="glossarySearch" placeholder="' + t('Search term...') + '" onkeyup="filterGlossary()">' +
        '<select id="domainFilter" onchange="filterGlossary()"><option value="">' + t('All domains') + '</option>';
    glossaryData.domains.forEach(function(d) {
        html += '<option value="' + d.name + '">' + d.icon + ' ' + d.name + '</option>';
    });
    html += '</select>' +
        '<select id="statusFilter" onchange="filterGlossary()">' +
            '<option value="">' + t('All statuses') + '</option>';
    sortedSteps.forEach(function(step) {
        html += '<option value="' + step.id + '">' + step.icon + ' ' + step.name + '</option>';
    });
    html += '<option value="deleted">' + t('Deleted') + '</option>';
    html += '</select>' +
        '<span class="filter-badge" id="filterCount"><strong>' + getVisibleTermsCount() + '</strong> / ' + glossaryData.terms.length + ' ' + t('terms') + '</span>' +
    '</div>';
    html += '<div id="termsTableWrap">' + renderTermsTable() + '</div>';
    html += '</div>';

    // Domains tab
    html += '<div id="tab-domains" class="tab-content" style="display:none;">';
    html += '<div class="glossary-filters">' +
        '<input type="text" id="domainSearch" placeholder="' + t('Search domain...') + '" onkeyup="filterDomains()">' +
        '<span class="filter-badge" id="domainCount"><strong>' + glossaryData.domains.length + '</strong> ' + t('domains') + '</span>' +
    '</div>';
    html += renderDomainsTab();
    html += '</div>';

    // Stakeholders tab
    html += '<div id="tab-stakeholders" class="tab-content" style="display:none;">';
    html += '<div class="glossary-filters">' +
        '<input type="text" id="stakeholderSearch" placeholder="' + t('Search stakeholder...') + '" onkeyup="filterStakeholders()">' +
        '<select id="roleFilter" onchange="filterStakeholders()">' +
            '<option value="">' + t('All roles') + '</option>' +
            '<option value="domain_owners">Domain Owners</option>' +
            '<option value="data_stewards">Data Stewards</option>' +
            '<option value="data_custodians">Data Custodians</option>' +
            '<option value="data_architects">Data Architects</option>' +
        '</select>' +
    '</div>';
    html += renderStakeholdersTab();
    html += '</div>';

    // Workflow tab
    html += '<div id="tab-workflow" class="tab-content" style="display:none;">';
    html += '<div class="glossary-filters">' +
        '<input type="text" id="workflowSearch" placeholder="' + t('Search workflow...') + '" onkeyup="filterWorkflow()">' +
        '<span class="filter-badge"><strong>' + governanceData.workflowSteps.length + '</strong> ' + t('steps') + '</span>' +
    '</div>';
    html += renderWorkflowTab();
    html += '</div>';

    html += '</div>'; // end glossary-body
    html += '</div>'; // end glossary-container

    // Modal
    html += '<div id="glossaryModal" class="modal" style="display: none;"></div>';

    render(t('Business Glossary'), html);
}

function emojiToSvg(emoji, size) {
    size = size || 16;
    var map = {
        '📖': 'book', '📁': 'folder', '👥': 'users', '⚙️': 'settings', '⚙': 'settings',
        '👑': 'crown', '➕': 'plus', '📤': 'upload', '🔍': 'search', '🔗': 'link',
        '👁️': 'eye', '👁': 'eye', '✏️': 'edit', '✏': 'edit', '🗑️': 'trash', '🗑': 'trash',
        '♻️': 'refresh', '♻': 'refresh', '🔄': 'refresh', '❌': 'x', '✅': 'check-circle',
        '🔒': 'lock', '🛡️': 'shield', '🛡': 'shield', '🔐': 'key', '🏛️': 'building', '🏛': 'building',
        '💻': 'monitor', '📋': 'clipboard', '💡': 'lightbulb', '🔢': 'hash',
        '📌': 'pin', '📊': 'chart', '🏷️': 'tag', '🏷': 'tag', '📜': 'scroll',
        '🗄️': 'database', '🗄': 'database', '🔧': 'wrench', '👤': 'user', '📝': 'pen',
        '📅': 'calendar', 'ℹ️': 'info', 'ℹ': 'info', '🆕': 'sparkle', '⏰': 'clock',
        '▶️': 'play', '▶': 'play', '🌐': 'globe', '🏢': 'office', '⛔': 'ban',
        '💬': 'message', '❗': 'alert', '🎯': 'check', '⏸️': 'clock', '⏸': 'clock',
        '🛠️': 'wrench', '🛠': 'wrench', '📈': 'chart', '📗': 'book', '🔴': 'alert',
        '💾': 'database', '📥': 'upload', '⚠️': 'alert', '⚠': 'alert',
        '📂': 'folder', '🐬': 'database'
    };
    if (!emoji) return svgIcon('clipboard', size);
    var iconName = map[emoji.trim()];
    if (iconName) return svgIcon(iconName, size);
    return svgIcon('clipboard', size);
}

