function loadDomainsFromDB() {
    try {
        var domains = apiCallSync('domains', 'GET');
        if (domains && Array.isArray(domains)) {
            glossaryData.domains = domains;
            console.log('Loaded domains from MySQL:', domains.length);
        }
    } catch (e) {
        console.error('Error loading domains:', e);
    }
}

function loadRolesFromDB() {
    try {
        var roles = apiCallSync('governance_roles', 'GET');
        if (roles && Array.isArray(roles)) {
            // List of system role IDs that cannot be edited
            var systemRoleIds = ['data_owner', 'data_steward', 'business_analyst', 'data_engineer', 'compliance_officer'];
            
            governanceData.roles = roles.map(function(r) {
                return {
                    id: r.role_id,
                    name: r.name,
                    icon: r.icon,
                    color: r.color,
                    description: r.description,
                    isSystem: systemRoleIds.indexOf(r.role_id) !== -1 // Mark system roles
                };
            });
            console.log('Loaded roles from MySQL:', governanceData.roles.length);
        }
    } catch (e) {
        console.error('Error loading roles:', e);
    }
}

function loadWorkflowStepsFromDB() {
    try {
        var steps = apiCallSync('governance_steps', 'GET');
        if (steps && Array.isArray(steps)) {
            governanceData.workflowSteps = steps.map(function(s) {
                var createdBy = null;
                var approvedBy = null;
                try {
                    if (s.created_by) createdBy = typeof s.created_by === 'string' ? JSON.parse(s.created_by) : s.created_by;
                    if (s.approved_by) approvedBy = typeof s.approved_by === 'string' ? JSON.parse(s.approved_by) : s.approved_by;
                } catch(e) {}
                
                return {
                    id: s.step_id,
                    dbId: s.id,
                    name: s.name,
                    icon: s.icon,
                    color: s.color,
                    order: s.order,
                    createdBy: createdBy,
                    approvedBy: approvedBy,
                    nextStep: s.next_step,
                    rejectStep: s.reject_step
                };
            });
            console.log('Loaded workflow steps from MySQL:', governanceData.workflowSteps.length);
        }
    } catch (e) {
        console.error('Error loading workflow steps:', e);
    }
}

function loadStakeholdersFromDB() {
    try {
        var stakeholders = apiCallSync('governance_stakeholders', 'GET');
        if (stakeholders && Array.isArray(stakeholders)) {
            governanceData.stakeholders = stakeholders.map(function(s) {
                var nameParts = s.name.split(' ');
                var avatar = nameParts.map(function(n) { return n[0]; }).join('').substring(0, 2).toUpperCase();
                return {
                    id: s.id,
                    name: s.name,
                    email: s.email,
                    roleId: s.role_id,
                    department: s.department,
                    avatar: avatar
                };
            });
            console.log('Loaded stakeholders from MySQL:', governanceData.stakeholders.length);
        }
    } catch (e) {
        console.error('Error loading stakeholders:', e);
    }
}

function loadAllDataFromDB() {
    console.log('Loading all data from database...');
    loadDomainsFromDB();
    loadRolesFromDB();
    loadWorkflowStepsFromDB();
    loadStakeholdersFromDB();
    console.log('Database loading complete.');
}

function loadGlossaryFromStorage(forceReload) {
    // Skip if already loaded and not forcing reload
    if (glossaryLoaded && !forceReload) {
        console.log('loadGlossaryFromStorage - using cached data');
        return;
    }
    
    console.log('loadGlossaryFromStorage - loading from MySQL, forceReload:', forceReload);
    
    try {
        // Load from MySQL only
        var terms = apiCallSync('glossary_terms', 'GET');
        console.log('Loaded glossary from MySQL - count:', terms ? terms.length : 0);
        
        if (terms && Array.isArray(terms)) {
            glossaryData.terms = terms.map(function(t) {
                // Parse stewards from JSON string
                var stewards = [];
                if (t.stewards) {
                    try {
                        stewards = typeof t.stewards === 'string' ? JSON.parse(t.stewards) : t.stewards;
                    } catch(e) { stewards = []; }
                }
                
                // Parse process comments from JSON string
                var processComments = [];
                if (t.process_comments) {
                    try {
                        processComments = typeof t.process_comments === 'string' ? JSON.parse(t.process_comments) : t.process_comments;
                    } catch(e) { processComments = []; }
                }
                
                // Parse history from JSON string
                var history = [];
                if (t.history) {
                    try {
                        history = typeof t.history === 'string' ? JSON.parse(t.history) : t.history;
                    } catch(e) { history = []; }
                }
                if (!Array.isArray(history)) { history = []; }
                
                // Parse physical attributes from JSON string
                var physicalAttributes = [];
                if (t.physical_attributes) {
                    try {
                        physicalAttributes = typeof t.physical_attributes === 'string' ? JSON.parse(t.physical_attributes) : t.physical_attributes;
                    } catch(e) { 
                        physicalAttributes = []; 
                    }
                }
                if (physicalAttributes && physicalAttributes.length > 0) {
                    console.log('Term', t.name, 'physicalAttributes:', JSON.stringify(physicalAttributes));
                }
                
                // Parse quality rules from JSON string
                var qualityRules = [];
                if (t.quality_rules) {
                    try {
                        qualityRules = typeof t.quality_rules === 'string' ? JSON.parse(t.quality_rules) : t.quality_rules;
                    } catch(e) { qualityRules = []; }
                }
                
                // Parse synonyms from JSON string
                var synonyms = [];
                if (t.synonyms) {
                    try {
                        synonyms = typeof t.synonyms === 'string' ? JSON.parse(t.synonyms) : t.synonyms;
                    } catch(e) { synonyms = []; }
                }
                
                // Parse related terms from JSON string
                var relatedTerms = [];
                if (t.related_terms) {
                    try {
                        relatedTerms = typeof t.related_terms === 'string' ? JSON.parse(t.related_terms) : t.related_terms;
                    } catch(e) { relatedTerms = []; }
                }
                
                return {
                    id: t.id,
                    name: t.name,
                    abbreviation: t.abbreviation || '',
                    definition: t.definition,
                    domain: t.domain,
                    dataType: t.data_type,
                    example: t.example,
                    formula: t.formula,
                    businessLogic: t.business_logic,
                    technicalDescription: t.technical_description,
                    owner: t.owner,
                    stewards: stewards,
                    securityClassification: t.security_classification,
                    physicalAttributes: physicalAttributes,
                    qualityRules: qualityRules,
                    synonyms: synonyms,
                    relatedTerms: relatedTerms,
                    sourceSystem: t.source_system || '',
                    notes: t.notes || '',
                    status: t.status,
                    rejectReason: t.reject_reason,
                    processComments: processComments,
                    history: history,
                    deletedAt: t.deleted_at,
                    deletedBy: t.deleted_by,
                    createdAt: t.created_at,
                    createdBy: t.created_by,
                    updatedAt: t.updated_at
                };
            });
        }
        
        // Mark as loaded
        glossaryLoaded = true;
    } catch (e) {
        console.error('MySQL error:', e);
        glossaryData.terms = [];
    }
}

function saveGlossaryToStorage() {
    // This is now handled by saveTermToDB - kept for compatibility
    console.log('saveGlossaryToStorage called');
}

// Save or update term in database
function saveTermToDB(term, isNew) {
    try {
        // Prepare stewards as JSON string
        var stewardsData = term.stewards || [];
        if (typeof stewardsData !== 'string') {
            stewardsData = JSON.stringify(stewardsData);
        }
        
        // Prepare process comments as JSON string
        var processCommentsData = term.processComments || [];
        if (typeof processCommentsData !== 'string') {
            processCommentsData = JSON.stringify(processCommentsData);
        }
        
        // Prepare physical attributes as JSON string
        var physicalAttributesData = term.physicalAttributes || [];
        if (typeof physicalAttributesData !== 'string') {
            physicalAttributesData = JSON.stringify(physicalAttributesData);
        }
        
        // Prepare quality rules as JSON string
        var qualityRulesData = term.qualityRules || [];
        if (typeof qualityRulesData !== 'string') {
            qualityRulesData = JSON.stringify(qualityRulesData);
        }
        
        // Prepare synonyms as JSON string
        var synonymsData = term.synonyms || [];
        if (typeof synonymsData !== 'string') {
            synonymsData = JSON.stringify(synonymsData);
        }
        
        // Prepare related terms as JSON string
        var relatedTermsData = term.relatedTerms || [];
        if (typeof relatedTermsData !== 'string') {
            relatedTermsData = JSON.stringify(relatedTermsData);
        }
        
        // Prepare history as JSON string
        var historyData = term.history || [];
        if (typeof historyData !== 'string') {
            historyData = JSON.stringify(historyData);
        }
        
        var termData = {
            name: term.name,
            abbreviation: term.abbreviation || '',
            definition: term.definition,
            domain: term.domain,
            dataType: term.dataType || '',
            example: term.example || '',
            formula: term.formula || '',
            businessLogic: term.businessLogic || '',
            technicalDescription: term.technicalDescription || '',
            owner: term.owner || '',
            stewards: stewardsData,
            securityClassification: term.securityClassification || '',
            status: term.status || 'draft',
            rejectReason: term.rejectReason || '',
            processComments: processCommentsData,
            physicalAttributes: physicalAttributesData,
            qualityRules: qualityRulesData,
            synonyms: synonymsData,
            relatedTerms: relatedTermsData,
            sourceSystem: term.sourceSystem || '',
            notes: term.notes || '',
            history: historyData
        };
        
        console.log('Saving term to DB:', termData, 'isNew:', isNew);
        
        if (isNew) {
            // POST - create new term
            var result = apiCallSync('glossary_terms', 'POST', termData);
            console.log('POST result:', result);
            if (result && result.id) {
                term.id = result.id;
                return result.id;
            }
        } else {
            // PUT - update existing term
            var result = apiCallSync('glossary_terms', 'PUT', termData, term.id);
            console.log('PUT result:', result);
            return term.id;
        }
    } catch (e) {
        console.error('saveTermToDB error:', e);
        throw e;
    }
}

// Wrapper function for updating term by index
function updateTermInDB(index) {
    var term = glossaryData.terms[index];
    if (term) {
        saveTermToDB(term, false);
    }
}

// Cache flags to prevent repeated API calls
var governanceLoaded = false;
var catalogLoaded = false;
var glossaryLoaded = false;

// Invalidate cache when data changes
function invalidateCache(cacheType) {
    if (cacheType === 'governance' || cacheType === 'all') {
        governanceLoaded = false;
    }
    if (cacheType === 'catalog' || cacheType === 'all') {
        catalogLoaded = false;
    }
    if (cacheType === 'glossary' || cacheType === 'all') {
        glossaryLoaded = false;
    }
}

function loadGovernanceFromStorage(forceReload) {
    // Skip if already loaded and not forcing reload
    if (governanceLoaded && !forceReload) {
        return;
    }
    
    try {
        // Load roles
        var roles = apiCallSync('governance_roles', 'GET');
        console.log('Loaded roles from MySQL:', roles);
        
        if (roles && Array.isArray(roles) && roles.length > 0) {
            governanceData.roles = roles.map(function(r) {
                return {
                    id: r.role_id,
                    name: r.name,
                    icon: r.icon || svgIcon('user', 14),
                    color: r.color || '#6366f1',
                    description: r.description,
                    dbId: r.id
                };
            });
        }
        
        // Load workflow steps
        var steps = apiCallSync('governance_steps', 'GET');
        console.log('Loaded steps from MySQL:', steps);
        
        if (steps && Array.isArray(steps) && steps.length > 0) {
            governanceData.workflowSteps = steps.map(function(s) {
                return {
                    id: s.step_id,
                    name: s.name,
                    icon: s.icon || svgIcon('clipboard', 14),
                    color: s.color || '#6366f1',
                    order: s.order,
                    createdBy: s.createdBy || [],
                    approvedBy: s.approvedBy || [],
                    nextStep: s.next_step,
                    rejectStep: s.reject_step,
                    dbId: s.id
                };
            });
        }
        
        // Load stakeholders
        var stakeholders = apiCallSync('governance_stakeholders', 'GET');
        console.log('Loaded stakeholders from MySQL:', stakeholders);
        
        if (stakeholders && Array.isArray(stakeholders)) {
            governanceData.stakeholders = stakeholders.map(function(s) {
                // Generate avatar from name initials
                var initials = s.name ? s.name.split(' ').map(function(n) { return n[0]; }).join('').substring(0, 2).toUpperCase() : '??';
                return {
                    id: s.id,
                    name: s.name,
                    role: s.role_id,
                    email: s.email,
                    department: s.department,
                    avatar: initials
                };
            });
        }
        
        // Load quality rules from MySQL
        var qualityRulesFromDB = apiCallSync('quality_rules', 'GET');
        console.log('Loaded quality rules from MySQL:', qualityRulesFromDB);
        
        if (qualityRulesFromDB && Array.isArray(qualityRulesFromDB) && qualityRulesFromDB.length > 0) {
            governanceData.qualityRules = qualityRulesFromDB.map(function(r) {
                // Parse linkedColumns from JSON if needed
                var linkedColumns = [];
                if (r.linked_columns) {
                    console.log('Rule', r.rule_id, 'linked_columns raw:', r.linked_columns);
                    try {
                        linkedColumns = typeof r.linked_columns === 'string' ? JSON.parse(r.linked_columns) : r.linked_columns;
                    } catch(e) { 
                        console.error('Error parsing linked_columns for rule', r.rule_id, e);
                        linkedColumns = []; 
                    }
                }
                console.log('Rule', r.rule_id, 'linkedColumns parsed:', linkedColumns);
                
                return {
                    id: r.id || r.rule_id,
                    rule_id: r.rule_id,
                    name: r.name,
                    type: r.type,
                    description: r.description,
                    expression: r.expression,
                    status: r.status || 'active',
                    severity: r.severity || 'medium',
                    passRate: parseFloat(r.pass_rate) || 0,
                    lastRun: r.last_run,
                    linkedColumns: linkedColumns,
                    createdAt: r.created_at,
                    updatedAt: r.updated_at
                };
            });
            console.log('Mapped quality rules:', governanceData.qualityRules.length);
        }
        
        // Create default quality rules if empty and save to DB
        if (!governanceData.qualityRules || governanceData.qualityRules.length === 0) {
            governanceData.qualityRules = getDefaultQualityRules();
            // Save defaults to database
            governanceData.qualityRules.forEach(function(rule) {
                saveQualityRuleToDB(rule, true);
            });
            console.log('Created default quality rules:', governanceData.qualityRules.length);
        }
        
        // Mark as loaded
        governanceLoaded = true;
    } catch (e) {
        console.error('MySQL governance load error:', e);
    }
}

