// Save quality rule to database
function saveQualityRuleToDB(rule, isNew) {
    try {
        var linkedColumnsData = rule.linkedColumns || [];
        console.log('saveQualityRuleToDB - rule.id:', rule.id, 'rule.rule_id:', rule.rule_id);
        console.log('saveQualityRuleToDB - linkedColumns before stringify:', linkedColumnsData);
        
        if (typeof linkedColumnsData !== 'string') {
            linkedColumnsData = JSON.stringify(linkedColumnsData);
        }
        console.log('saveQualityRuleToDB - linkedColumns after stringify:', linkedColumnsData);
        
        var ruleData = {
            rule_id: rule.rule_id || rule.id || ('rule_' + Date.now()),
            name: rule.name,
            type: rule.type,
            description: rule.description || '',
            expression: rule.expression || '',
            status: rule.status || 'active',
            severity: rule.severity || 'medium',
            pass_rate: rule.passRate || 0,
            linked_columns: linkedColumnsData
        };
        
        console.log('Saving quality rule to DB - full ruleData:', JSON.stringify(ruleData));
        console.log('isNew:', isNew);
        
        if (isNew) {
            var result = apiCallSync('quality_rules', 'POST', ruleData);
            console.log('POST quality rule result:', result);
            if (result && result.id) {
                rule.id = result.id;
                return result.id;
            }
        } else {
            var ruleId = rule.id || rule.rule_id;
            console.log('PUT to quality_rules with id:', ruleId, 'data:', JSON.stringify(ruleData));
            var updateResult = apiCallSync('quality_rules', 'PUT', ruleData, ruleId);
            console.log('PUT quality rule result:', updateResult);
            return rule.id;
        }
    } catch(e) {
        console.error('Error saving quality rule to DB:', e);
    }
    return null;
}

