function getGlossaryStats() {
    var stats = { total: 0 };
    
    // Initialize stats for each workflow step
    governanceData.workflowSteps.forEach(function(step) {
        stats[step.id] = 0;
    });
    
    // Also keep legacy counts for backwards compatibility
    stats.draft = 0;
    stats.pending = 0;
    stats.approved = 0;
    stats.published = 0;
    stats.rejected = 0;
    stats.deprecated = 0;
    stats.deleted = 0;
    
    glossaryData.terms.forEach(function(t) {
        stats.total++;
        
        // Count by step id
        if (stats.hasOwnProperty(t.status)) {
            stats[t.status]++;
        }
        
        // Legacy mapping
        if (t.status === 'draft' || t.status === 'Draft') stats.draft++;
        else if (t.status === 'review' || t.status === 'Pending Review') stats.pending++;
        else if (t.status === 'approved' || t.status === 'Approved') stats.approved++;
        else if (t.status === 'published' || t.status === 'Published') stats.published++;
        else if (t.status === 'rejected' || t.status === 'Rejected') stats.rejected++;
        else if (t.status === 'deprecated' || t.status === 'Deprecated') stats.deprecated++;
        else if (t.status === 'deleted' || t.status === 'Deleted') stats.deleted++;
    });
    return stats;
}

function showGlossaryTab(tab) {
    document.querySelectorAll('.tab-btn').forEach(function(btn) {
        btn.classList.remove('active');
    });
    document.querySelectorAll('.tab-content').forEach(function(content) {
        content.classList.remove('active');
        content.style.display = 'none';
    });
    
    // Find the correct button by data-tab attribute
    var activeBtn = document.querySelector('.tab-btn[data-tab="' + tab + '"]');
    if (activeBtn) {
        activeBtn.classList.add('active');
    }
    
    var tabEl = document.getElementById('tab-' + tab);
    if (tabEl) {
        tabEl.classList.add('active');
        tabEl.style.display = 'block';
    }
}

function renderTermsTable() {
    var isGovernance = isGovernanceMode();
    var filters = window._glossaryFilters || { search: '', domain: '', status: '' };

    var visibleTerms = glossaryData.terms.filter(function(t, idx) {
        t._originalIndex = idx; // Store original index for actions

        // Hide soft-deleted and deprecated terms from regular listing — only governance
        // mode (audit / archive view) shows them. Status filter still overrides this.
        if (!filters.status && !isGovernance && (t.status === 'deleted' || t.status === 'deprecated')) {
            return false;
        }

        // Apply search filter
        if (filters.search) {
            var searchMatch = t.name.toLowerCase().includes(filters.search) ||
                (t.definition || '').toLowerCase().includes(filters.search);
            if (!searchMatch) return false;
        }

        // Apply domain filter
        if (filters.domain && t.domain !== filters.domain) {
            return false;
        }

        // Apply status filter
        if (filters.status && t.status !== filters.status) {
            return false;
        }

        return true;
    });

    if (visibleTerms.length === 0) {
        return '<div class="empty-state"><div class="empty-icon">' + svgIcon('book', 40) + '</div><p style="font-size: 16px; font-weight: 600; color: #64748b;">' + t('No terms found') + '</p><p style="font-size: 14px; margin: 12px 0;">' + t('Click the button above to add the first term') + '</p>' + (canCreateTerm() ? '<button class="glossary-btn" onclick="showAddTermModal()">' + svgIcon('plus', 14) + ' ' + t('Add Term') + '</button>' : '') + '</div>';
    }

    // Pagination setup
    var pageSize = glossaryPagination.pageSize || 10;
    glossaryPagination.totalItems = visibleTerms.length;
    glossaryPagination.totalPages = Math.ceil(visibleTerms.length / pageSize);

    if (glossaryPagination.currentPage > glossaryPagination.totalPages) {
        glossaryPagination.currentPage = Math.max(1, glossaryPagination.totalPages);
    }

    var startIndex = (glossaryPagination.currentPage - 1) * pageSize;
    var endIndex = startIndex + pageSize;
    var paginatedTerms = visibleTerms.slice(startIndex, endIndex);

    var html = '<div class="terms-table-wrap"><table class="terms-table"><thead><tr>' +
        '<th style="width: 80px;">ID</th><th>' + t('Term') + '</th><th>' + t('Domain') + '</th><th>' + t('Status') + '</th><th>' + svgIcon('lock', 13) + ' ' + t('Security') + '</th><th>' + t('Stewards') + '</th><th style="width: 130px;">' + t('Actions') + '</th>' +
    '</tr></thead><tbody id="termsTableBody">';

    paginatedTerms.forEach(function(term, pIdx) {
        var idx = term._originalIndex; // Use original index for actions
        var rowNum = startIndex + pIdx + 1;

        var domain = glossaryData.domains.find(function(d) { return d.name === term.domain; });
        var domainStyle = domain ? 'background: #dbeafe; color: #1d4ed8;' : '';
        var domainIcon = domain ? domain.icon : svgIcon('folder', 14);

        // Find current workflow step
        var currentStep = governanceData.workflowSteps.find(function(s) { return s.id === term.status || s.name === term.status; });
        var stepColor = '#3b82f6';
        if (term.status === 'deleted') stepColor = '#334155';
        else if (term.status === 'draft') stepColor = '#94a3b8';
        else if (term.status === 'review' || term.status === 'pending') stepColor = '#60a5fa';
        else if (term.status === 'approved') stepColor = '#2563eb';
        else if (term.status === 'published') stepColor = '#1d4ed8';
        else if (term.status === 'rejected') stepColor = '#1e40af';
        else if (term.status === 'deprecated') stepColor = '#475569';
        var stepIcon = currentStep ? currentStep.icon : (term.status === 'deleted' ? svgIcon('trash', 14) : svgIcon('clipboard', 14));
        var stepName = currentStep ? currentStep.name : (term.status === 'deleted' ? 'Silinmiş' : term.status);
        
        // Get security classification
        var securityInfo = term.securityClassification ? getSecurityClassifications().find(function(s) { return s.id === term.securityClassification; }) : null;
        
        // Parse stewards
        var stewards = term.stewards || [];
        if (typeof stewards === 'string') {
            try { stewards = JSON.parse(stewards); } catch(e) { stewards = []; }
        }
        
        // Add special styling for deleted terms
        var rowStyle = term.status === 'deleted' ? 'opacity: 0.6; background: #f8fafc;' : '';
        
        var termCode = term.code || (term.id ? 'Gloss-' + term.id : '');
        html += '<tr data-index="' + idx + '" data-term-id="' + (term.id || idx) + '" onclick="viewTerm(' + idx + ')" style="cursor: pointer; ' + rowStyle + '">' +
            '<td><span class="row-num" style="font-family: monospace; font-size: 11px; color: #64748b;">' + (termCode || rowNum) + '</span></td>' +
            '<td><div class="term-name">' + term.name + '</div><div class="term-definition">' + (term.definition || '').substring(0, 80) + (term.definition && term.definition.length > 80 ? '...' : '') + '</div></td>';
        
        html += '<td><span class="term-domain" style="' + domainStyle + '">' + domainIcon + ' ' + term.domain + '</span></td>';
        html += '<td><span class="term-status" style="background: ' + stepColor + '20; color: ' + stepColor + ';">' + stepIcon + ' ' + stepName + '</span></td>';
        
        // Security Classification cell
        if (securityInfo) {
            var secBlue = securityInfo.id === 'public' ? '#93c5fd' : securityInfo.id === 'internal' ? '#3b82f6' : securityInfo.id === 'confidential' ? '#2563eb' : '#1e40af';
            html += '<td><span style="background: ' + secBlue + '15; color: ' + secBlue + '; padding: 4px 8px; border-radius: 4px; font-size: 11px; font-weight: 600; white-space: nowrap;">' + securityInfo.icon + ' ' + securityInfo.id.charAt(0).toUpperCase() + securityInfo.id.slice(1) + '</span></td>';
        } else {
            html += '<td><span style="color: #94a3b8; font-size: 11px;">-</span></td>';
        }
        
        // Stewards cell (multiple)
        if (stewards.length > 0) {
            var stewardNames = stewards.map(function(s) { return typeof s === 'string' ? s : s.name; });
            if (stewardNames.length <= 2) {
                html += '<td><div style="display: flex; flex-wrap: wrap; gap: 4px;">';
                stewardNames.forEach(function(name) {
                    var initials = name.split(' ').map(function(n) { return n[0]; }).join('').substring(0, 2).toUpperCase();
                    html += '<span style="display: inline-flex; align-items: center; gap: 4px; background: #eff6ff; padding: 2px 8px; border-radius: 12px; font-size: 11px; color: #2563eb;">' +
                        '<span style="width: 18px; height: 18px; background: #3b82f6; color: #fff; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 9px; font-weight: 600;">' + initials + '</span>' +
                        name.split(' ')[0] + '</span>';
                });
                html += '</div></td>';
            } else {
                html += '<td><span style="background: #eff6ff; padding: 4px 8px; border-radius: 12px; font-size: 11px; color: #2563eb;">' + svgIcon('users', 12) + ' ' + stewardNames.length + ' nəfər</span></td>';
            }
        } else {
            html += '<td><span style="color: #94a3b8; font-size: 11px;">-</span></td>';
        }
        
        html += '<td onclick="event.stopPropagation();"><div class="term-actions">' +
            '<button onclick="copyElementLink(\'/glossary/term/' + (term.id || idx) + '\')" title="Linki kopyala">' + svgIcon('link', 14) + '</button>' +
            '<button onclick="viewTerm(' + idx + ')" title="Bax">' + svgIcon('eye', 14) + '</button>';
        
        // Show restore button for deleted terms, otherwise show normal actions
        if (term.status === 'deleted') {
            html += '<button onclick="restoreTerm(' + idx + ')" title="Bərpa et" style="background: #dbeafe; color: #2563eb;">' + svgIcon('refresh', 14) + '</button>';
            html += '<button class="delete" onclick="permanentDeleteTerm(' + idx + ')" title="Həmişəlik sil" style="background: #bfdbfe; color: #1e40af;">' + svgIcon('trash', 14) + '</button>';
        } else {
            if (canEditTerm(term)) {
                html += '<button onclick="editTerm(' + idx + ')" title="Redaktə">' + svgIcon('edit', 14) + '</button>';
            }

            // Dynamic workflow action buttons
            if (currentStep && canActOnStep(term, currentStep)) {
                // Approve button (move to next step)
                if (currentStep.nextStep) {
                    var nextStep = governanceData.workflowSteps.find(function(s) { return s.id === currentStep.nextStep; });
                    if (nextStep) {
                        html += '<button class="approve" onclick="advanceTermStatus(' + idx + ')" title="' + nextStep.name + ' et">' + nextStep.icon + '</button>';
                    }
                }

                // Reject button (move to reject step)
                if (currentStep.rejectStep) {
                    html += '<button class="reject" onclick="rejectTermStatus(' + idx + ')" title="İmtina et" style="background: #bfdbfe; color: #1e40af;">' + svgIcon('x', 14) + '</button>';
                }
                
                // Resubmit button for rejected terms
                if (term.status === 'rejected') {
                    html += '<button class="resubmit" onclick="resubmitTerm(' + idx + ')" title="Yenidən göndər" style="background: #dbeafe; color: #3b82f6;">' + svgIcon('refresh', 14) + '</button>';
                }
            }
            
            // Delete only for admin or assigned stewards on a draft. Domain owners cannot delete.
            if (canDeleteTerm(term)) {
                html += '<button class="delete" onclick="deleteTerm(' + idx + ')" title="Sil">' + svgIcon('trash', 14) + '</button>';
            }
        }
        
        html += '</div></td></tr>';
    });

    html += '</tbody></table></div>';

    // Add pagination UI
    html += renderTermsPagination();

    return html;
}

function renderTermsPagination() {
    if (glossaryPagination.totalPages <= 1) return '';

    var currentPage = glossaryPagination.currentPage;
    var totalPages = glossaryPagination.totalPages;
    var startItem = (currentPage - 1) * glossaryPagination.pageSize + 1;
    var endItem = Math.min(currentPage * glossaryPagination.pageSize, glossaryPagination.totalItems);

    var html = '<div class="glossary-pagination">';

    // Info
    html += '<div class="pagination-info">' +
        t('Showing') + ': <strong>' + startItem + '-' + endItem + '</strong> / ' +
        '<strong>' + glossaryPagination.totalItems + '</strong> ' + t('terms') +
    '</div>';

    // Page buttons
    html += '<div class="pagination-btns">';

    // Prev button
    html += '<button class="page-btn" onclick="termsGoToPage(' + (currentPage - 1) + ')" ' +
        (currentPage === 1 ? 'disabled' : '') + '>←</button>';

    // Page numbers
    var startPage = Math.max(1, currentPage - 2);
    var endPage = Math.min(totalPages, startPage + 4);
    if (endPage - startPage < 4) {
        startPage = Math.max(1, endPage - 4);
    }

    if (startPage > 1) {
        html += '<button class="page-btn" onclick="termsGoToPage(1)">1</button>';
        if (startPage > 2) {
            html += '<span style="color: #cbd5e1; font-size: 12px;">...</span>';
        }
    }

    for (var i = startPage; i <= endPage; i++) {
        html += '<button class="page-btn' + (i === currentPage ? ' active' : '') + '" onclick="termsGoToPage(' + i + ')">' + i + '</button>';
    }

    if (endPage < totalPages) {
        if (endPage < totalPages - 1) {
            html += '<span style="color: #cbd5e1; font-size: 12px;">...</span>';
        }
        html += '<button class="page-btn" onclick="termsGoToPage(' + totalPages + ')">' + totalPages + '</button>';
    }

    // Next button
    html += '<button class="page-btn" onclick="termsGoToPage(' + (currentPage + 1) + ')" ' +
        (currentPage === totalPages ? 'disabled' : '') + '>→</button>';

    html += '</div></div>';

    return html;
}

function termsGoToPage(page) {
    if (page < 1 || page > glossaryPagination.totalPages) return;
    glossaryPagination.currentPage = page;

    // Refresh terms table
    var termsTab = document.getElementById('tab-terms');
    if (termsTab) {
        var filters = termsTab.querySelector('.glossary-filters');
        if (filters) {
            termsTab.innerHTML = filters.outerHTML + renderTermsTable();
        }
    }

    // Scroll to top of terms
    var termsTable = document.querySelector('.terms-table');
    if (termsTable) {
        termsTable.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
}

function advanceTermStatus(index) {
    var term = glossaryData.terms[index];
    var currentStep = governanceData.workflowSteps.find(function(s) { return s.id === term.status || s.name === term.status; });
    
    if (!currentStep || !currentStep.nextStep) {
        alert('Bu termin son statusdadır.');
        return;
    }
    
    var nextStep = governanceData.workflowSteps.find(function(s) { return s.id === currentStep.nextStep; });
    if (!nextStep) return;
    
    // Get domain stakeholders
    var domain = glossaryData.domains.find(function(d) { return d.name === term.domain; });

    // The label "Təsdiqləyəcək" means "the person who will act on this term at the
    // NEXT step" — so we show stakeholders from `nextStep.approvedBy`. For terminal
    // steps (no next-approver) we fall back to the current step's actor.
    var displayRoles = (nextStep.approvedBy && nextStep.approvedBy.length) ? nextStep.approvedBy : (currentStep.approvedBy || []);
    var approvers = [];
    if (domain && domain.stakeholders) {
        displayRoles.forEach(function(roleId) {
            var roleKey = roleId + 's'; // 'domain_owner' -> 'domain_owners'
            if (domain.stakeholders[roleKey]) {
                domain.stakeholders[roleKey].forEach(function(name) {
                    var role = governanceData.roles.find(function(r) { return r.id === roleId; });
                    approvers.push({ name: name, role: role });
                });
            }
        });
    }
    
    // Show modal for selecting approver
    var modal = document.getElementById('glossaryModal');
    
    // Create modal if it doesn't exist
    if (!modal) {
        modal = document.createElement('div');
        modal.id = 'glossaryModal';
        modal.className = 'modal';
        document.body.appendChild(modal);
    }
    
    // Reset modal display
    modal.style.cssText = 'display:flex;position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);z-index:9999;justify-content:center;align-items:center;';
    
    var isAdminUser = currentUser && currentUser.username === 'admin';

    var approverSection = '';
    if (isAdminUser) {
        // Admin keeps the explicit approver picker.
        var approverOptions = '';
        if (approvers.length > 0) {
            approvers.forEach(function(a, idx) {
                approverOptions += '<label style="display: flex; align-items: center; gap: 10px; padding: 10px 14px; cursor: pointer; background: ' + (idx === 0 ? '#eff6ff' : '#f8fafc') + '; border: 2px solid ' + (idx === 0 ? '#3b82f6' : '#e5e7eb') + '; border-radius: 10px; margin-bottom: 8px; transition: all 0.2s;">' +
                    '<input type="radio" name="approverSelect" value="' + a.name + '" ' + (idx === 0 ? 'checked' : '') + ' style="width: 18px; height: 18px;">' +
                    '<div style="width: 36px; height: 36px; background: #3b82f6; color: #fff; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 13px; font-weight: 600;">' + getInitials(a.name) + '</div>' +
                    '<div><div style="font-size: 14px; font-weight: 600;">' + a.name + '</div>' +
                    '<div style="font-size: 12px; color: #64748b;">' + a.role.icon + ' ' + a.role.name + '</div></div>' +
                '</label>';
            });
        } else {
            approverOptions = '<div style="padding: 20px; text-align: center; color: #94a3b8;">Bu mərhələ üçün təsdiqləyici təyin edilməyib</div>';
        }
        approverSection =
            '<div style="margin-bottom: 16px;">' +
                '<label style="font-size: 12px; font-weight: 600; color: #475569; display: block; margin-bottom: 8px;">' + svgIcon('user', 12) + ' Təsdiqləyən şəxs seçin:</label>' +
                approverOptions +
            '</div>';
    } else {
        // Non-admin path: no approver picker / no "kim ediləcək" line — the current
        // logged-in user is implicitly the actor. The header already conveys the
        // transition (e.g. "Approved → Published") which is enough confirmation.
        approverSection = '';
    }

    modal.innerHTML = '<div style="width: 90%; max-width: 500px; background: white; border-radius: 12px; box-shadow: 0 25px 50px rgba(0,0,0,0.25); overflow: hidden;">' +
        '<div style="padding: 16px 20px; background: linear-gradient(135deg, #eff6ff, #dbeafe); border-bottom: 1px solid #e5e7eb; display: flex; justify-content: space-between; align-items: center;">' +
            '<span style="font-size: 16px; font-weight: 600; color: #1e293b;">' + nextStep.icon + ' ' + currentStep.name + ' → ' + nextStep.name + '</span>' +
            '<button onclick="closeGlossaryModal()" style="background: none; border: none; font-size: 24px; cursor: pointer; color: #64748b;">×</button>' +
        '</div>' +
        '<div style="padding: 20px;">' +
            '<div style="background: #eff6ff; border: 1px solid #93c5fd; border-radius: 10px; padding: 14px; margin-bottom: 16px;">' +
                '<div style="font-size: 13px; color: #1e40af;"><strong>"' + term.name + '"</strong> terminini <strong>' + nextStep.name + '</strong> mərhələsinə keçirmək istəyirsiniz?</div>' +
            '</div>' +
            approverSection +
            '<div>' +
                '<label style="display: block; font-size: 12px; font-weight: 600; color: #475569; margin-bottom: 6px;">' + svgIcon('message', 12) + ' Komment (istəyə bağlı)</label>' +
                '<textarea id="approveComment" rows="2" placeholder="Təsdiq haqqında qeyd..." style="width: 100%; padding: 10px 12px; border: 1px solid #e5e7eb; border-radius: 8px; font-size: 14px; resize: vertical;"></textarea>' +
            '</div>' +
        '</div>' +
        '<div style="padding: 16px 20px; background: #f9fafb; border-top: 1px solid #e5e7eb; display: flex; justify-content: flex-end; gap: 10px;">' +
            '<button onclick="closeGlossaryModal()" style="padding: 10px 20px; border: 1px solid #d1d5db; border-radius: 8px; background: white; font-size: 14px; cursor: pointer;">Ləğv et</button>' +
            '<button onclick="confirmAdvanceStatus(' + index + ', \'' + currentStep.id + '\', \'' + nextStep.id + '\')" style="padding: 10px 20px; border: none; border-radius: 8px; background: #2563eb; color: white; font-size: 14px; font-weight: 600; cursor: pointer; display:inline-flex; align-items:center; gap:6px;">' + svgIcon('check-circle', 14) + ' Təsdiqlə</button>' +
        '</div>' +
    '</div>';
}

function confirmAdvanceStatus(index, fromStepId, toStepId) {
    var approverRadio = document.querySelector('input[name="approverSelect"]:checked');
    var approver;
    if (approverRadio) {
        // Admin explicitly picked someone (e.g. acting on behalf of an owner)
        approver = approverRadio.value;
    } else {
        // Non-admin: the current logged-in user is the actor performing the transition.
        approver = currentUser
            ? (((currentUser.first_name || '') + ' ' + (currentUser.last_name || '')).trim() || currentUser.username || 'System')
            : 'System';
    }
    var comment = document.getElementById('approveComment').value.trim();
    
    var fromStep = governanceData.workflowSteps.find(function(s) { return s.id === fromStepId; });
    var toStep = governanceData.workflowSteps.find(function(s) { return s.id === toStepId; });
    
    var term = glossaryData.terms[index];
    glossaryData.terms[index].status = toStepId;
    glossaryData.terms[index].updatedAt = new Date().toLocaleDateString('az-AZ');
    glossaryData.terms[index].history = glossaryData.terms[index].history || [];
    glossaryData.terms[index].history.push({
        action: fromStep.name + ' → ' + toStep.name,
        date: new Date().toLocaleString('az-AZ'),
        user: approver,
        comment: comment || null
    });
    
    // Add process comment
    glossaryData.terms[index].processComments = glossaryData.terms[index].processComments || [];
    glossaryData.terms[index].processComments.push({
        step: toStep.id,
        comment: comment || 'Təsdiqləndi və ' + toStep.name + ' mərhələsinə keçirildi',
        date: new Date().toLocaleString('az-AZ'),
        user: approver
    });
    
    updateTermInDB(index);
    closeGlossaryModal();
    showNotification(toStep.name + ' mərhələsinə keçirildi', 'success');
    // Refresh term detail
    loadTermDetail(term.id || index);
}

function rejectTermStatus(index) {
    var term = glossaryData.terms[index];
    var currentStep = governanceData.workflowSteps.find(function(s) { return s.id === term.status || s.name === term.status; });
    
    if (!currentStep || !currentStep.rejectStep) {
        alert('Bu addımda imtina mümkün deyil.');
        return;
    }
    
    var rejectStep = governanceData.workflowSteps.find(function(s) { return s.id === currentStep.rejectStep; });
    
    // Get domain stakeholders who can reject (same as approvers for current step)
    var domain = glossaryData.domains.find(function(d) { return d.name === term.domain; });
    var rejecters = [];
    
    if (currentStep.approvedBy && domain && domain.stakeholders) {
        currentStep.approvedBy.forEach(function(roleId) {
            var roleKey = roleId + 's';
            if (domain.stakeholders[roleKey]) {
                domain.stakeholders[roleKey].forEach(function(name) {
                    var role = governanceData.roles.find(function(r) { return r.id === roleId; });
                    rejecters.push({ name: name, role: role });
                });
            }
        });
    }
    
    var rejecterOptions = '';
    if (rejecters.length > 0) {
        rejecters.forEach(function(r, idx) {
            rejecterOptions += '<label style="display: flex; align-items: center; gap: 10px; padding: 10px 14px; cursor: pointer; background: ' + (idx === 0 ? '#eff6ff' : '#f8fafc') + '; border: 2px solid ' + (idx === 0 ? '#3b82f6' : '#e5e7eb') + '; border-radius: 10px; margin-bottom: 8px;">' +
                '<input type="radio" name="rejecterSelect" value="' + r.name + '" ' + (idx === 0 ? 'checked' : '') + ' style="width: 18px; height: 18px;">' +
                '<div style="width: 36px; height: 36px; background: #3b82f6; color: #fff; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 13px; font-weight: 600;">' + getInitials(r.name) + '</div>' +
                '<div><div style="font-size: 14px; font-weight: 600;">' + r.name + '</div>' +
                '<div style="font-size: 12px; color: #64748b;">' + r.role.icon + ' ' + r.role.name + '</div></div>' +
            '</label>';
        });
    }
    
    var modal = document.getElementById('glossaryModal');
    
    // Create modal if it doesn't exist
    if (!modal) {
        modal = document.createElement('div');
        modal.id = 'glossaryModal';
        modal.className = 'modal';
        document.body.appendChild(modal);
    }
    
    // Reset modal display
    modal.style.cssText = 'display:flex;position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);z-index:9999;justify-content:center;align-items:center;';
    
    modal.innerHTML = '<div style="width: 90%; max-width: 500px; background: white; border-radius: 12px; box-shadow: 0 25px 50px rgba(0,0,0,0.25); overflow: hidden;">' +
        '<div style="padding: 16px 20px; background: linear-gradient(135deg, #eff6ff, #dbeafe); border-bottom: 1px solid #bfdbfe; display: flex; justify-content: space-between; align-items: center;">' +
            '<span style="font-size: 16px; font-weight: 600; color: #1e40af; display:flex; align-items:center; gap:6px;">' + svgIcon('x', 16) + ' ' + currentStep.name + ' → ' + rejectStep.name + '</span>' +
            '<button onclick="closeGlossaryModal()" style="background: none; border: none; font-size: 24px; cursor: pointer; color: #64748b;">×</button>' +
        '</div>' +
        '<div style="padding: 20px;">' +
            '<div style="background: #eff6ff; border: 1px solid #93c5fd; border-radius: 10px; padding: 14px; margin-bottom: 16px;">' +
                '<div style="font-size: 13px; color: #1e40af;"><strong>"' + term.name + '"</strong> terminini imtina etmək istəyirsiniz?</div>' +
            '</div>' +
            (rejecterOptions ? '<div style="margin-bottom: 16px;"><label style="font-size: 12px; font-weight: 600; color: #475569; display: block; margin-bottom: 8px;">' + svgIcon('user', 12) + ' İmtina edən şəxs:</label>' + rejecterOptions + '</div>' : '') +
            '<div>' +
                '<label style="display: block; font-size: 12px; font-weight: 600; color: #1e40af; margin-bottom: 6px;">' + svgIcon('alert', 12) + ' İmtina səbəbi *</label>' +
                '<textarea id="rejectReason" rows="4" placeholder="Niyə imtina edirsiniz? Təkmilləşdirmə təklifləri..." style="width: 100%; padding: 10px 12px; border: 1px solid #93c5fd; border-radius: 8px; font-size: 14px; resize: vertical;"></textarea>' +
            '</div>' +
        '</div>' +
        '<div style="padding: 16px 20px; background: #f9fafb; border-top: 1px solid #e5e7eb; display: flex; justify-content: flex-end; gap: 10px;">' +
            '<button onclick="closeGlossaryModal()" style="padding: 10px 20px; border: 1px solid #d1d5db; border-radius: 8px; background: white; font-size: 14px; cursor: pointer;">Ləğv et</button>' +
            '<button onclick="confirmReject(' + index + ', \'' + currentStep.id + '\', \'' + rejectStep.id + '\')" style="padding: 10px 20px; border: none; border-radius: 8px; background: #2563eb; color: white; font-size: 14px; font-weight: 600; cursor: pointer; display:inline-flex; align-items:center; gap:6px;">' + svgIcon('x', 14) + ' İmtina et</button>' +
        '</div>' +
    '</div>';
}

function confirmReject(index, fromStepId, toStepId) {
    var reason = document.getElementById('rejectReason').value.trim();
    if (!reason) {
        alert('İmtina səbəbini daxil edin');
        return;
    }
    
    var rejecterRadio = document.querySelector('input[name="rejecterSelect"]:checked');
    var rejecter = rejecterRadio ? rejecterRadio.value : 'Reviewer';
    
    var fromStep = governanceData.workflowSteps.find(function(s) { return s.id === fromStepId; });
    var toStep = governanceData.workflowSteps.find(function(s) { return s.id === toStepId; });
    
    var term = glossaryData.terms[index];
    glossaryData.terms[index].status = toStepId;
    glossaryData.terms[index].rejectReason = reason;
    glossaryData.terms[index].updatedAt = new Date().toLocaleDateString('az-AZ');
    glossaryData.terms[index].history = glossaryData.terms[index].history || [];
    glossaryData.terms[index].history.push({
        action: fromStep.name + ' → ' + toStep.name + ': ' + reason,
        date: new Date().toLocaleString('az-AZ'),
        user: rejecter,
        comment: reason
    });
    
    // Add process comment
    glossaryData.terms[index].processComments = glossaryData.terms[index].processComments || [];
    glossaryData.terms[index].processComments.push({
        step: toStepId,
        comment: 'İmtina edildi: ' + reason,
        date: new Date().toLocaleString('az-AZ'),
        user: rejecter
    });
    
    updateTermInDB(index);
    closeGlossaryModal();
    showNotification('İmtina edildi', 'warning');
    // Refresh term detail
    loadTermDetail(term.id || index);
}

function resubmitTerm(index) {
    var term = glossaryData.terms[index];
    
    // Get steward names
    var stewards = term.stewards || [];
    if (typeof stewards === 'string') {
        try { stewards = JSON.parse(stewards); } catch(e) { stewards = []; }
    }
    var stewardNames = stewards.map(function(s) { return typeof s === 'string' ? s : s.name; }).join(', ');
    
    glossaryData.terms[index].status = 'draft';
    glossaryData.terms[index].rejectReason = null;
    glossaryData.terms[index].updatedAt = new Date().toLocaleDateString('az-AZ');
    glossaryData.terms[index].history = glossaryData.terms[index].history || [];
    glossaryData.terms[index].history.push({
        action: 'Yenidən göndərildi',
        date: new Date().toLocaleString('az-AZ'),
        user: stewardNames || 'System'
    });
    
    // Add process comment
    glossaryData.terms[index].processComments = glossaryData.terms[index].processComments || [];
    glossaryData.terms[index].processComments.push({
        step: 'draft',
        comment: 'Düzəliş edilərək yenidən draft mərhələsinə göndərildi',
        date: new Date().toLocaleString('az-AZ'),
        user: stewardNames || 'System'
    });
    
    updateTermInDB(index);
    loadGlossary();
}

function renderDomainsTab() {
    var canManage = canManageGovernance();
    var html = '<div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px;">' +
        '<div style="font-size: 14px; font-weight: 600; color: #0f172a;">' + svgIcon('folder', 16) + ' ' + t('Business Domains') +
            (canManage ? '' : ' <span style="background:#f1f5f9;color:#64748b;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:500;margin-left:8px;">Read-only</span>') +
        '</div>' +
        (canManage ? '<button class="glossary-btn" onclick="showAddDomainModal()" style="padding: 7px 14px; font-size: 12px;">' + svgIcon('plus', 13) + ' ' + t('Add Domain') + '</button>' : '') +
    '</div>';

    if (glossaryData.domains.length === 0) {
        return html + '<div class="empty-state"><div class="empty-icon">' + svgIcon('folder', 40) + '</div><p style="font-size: 16px; font-weight: 600; color: #64748b;">' + t('No domains found') + '</p>' + (canManage ? '<button class="glossary-btn" onclick="showAddDomainModal()">' + svgIcon('plus', 14) + ' ' + t('Add Domain') + '</button>' : '') + '</div>';
    }

    html += '<div class="domains-table-wrap"><table class="domains-table"><thead><tr>' +
        '<th style="width: 36px;">#</th>' +
        '<th>' + t('Domain') + '</th>' +
        '<th>' + t('Description') + '</th>' +
        '<th style="text-align: center;">' + t('Terms') + '</th>' +
        '<th style="width: 100px;">' + t('Actions') + '</th>' +
    '</tr></thead><tbody>';

    glossaryData.domains.forEach(function(domain, idx) {
        var count = glossaryData.terms.filter(function(t) { return t.domain === domain.name; }).length;
        var pct = glossaryData.terms.length > 0 ? Math.round((count / glossaryData.terms.length) * 100) : 0;

        html += '<tr data-domain="' + domain.name + '" onclick="navigateTo(\'/glossary/domain/' + encodeURIComponent(domain.name) + '\')" style="cursor: pointer;">' +
            '<td><span class="row-num">' + (idx + 1) + '</span></td>' +
            '<td><div style="display: flex; align-items: center; gap: 10px;">' +
                '<div class="domain-icon" style="background: #dbeafe; color: #2563eb;">' + domain.icon + '</div>' +
                '<div class="domain-name">' + domain.name + '</div>' +
            '</div></td>' +
            '<td><span style="color: #64748b; font-size: 12px;">' + (domain.description || '-') + '</span></td>' +
            '<td style="text-align: center;">' +
                '<div style="display: flex; flex-direction: column; align-items: center; gap: 4px;">' +
                    '<span style="font-weight: 700; color: #0f172a; font-size: 15px;">' + count + '</span>' +
                    '<div style="width: 60px; height: 4px; background: #f1f5f9; border-radius: 2px; overflow: hidden;">' +
                        '<div style="width: ' + pct + '%; height: 100%; background: #3b82f6; border-radius: 2px;"></div>' +
                    '</div>' +
                '</div>' +
            '</td>' +
            '<td><div class="term-actions">' +
                '<button onclick="event.stopPropagation(); copyElementLink(\'/glossary/domain/' + encodeURIComponent(domain.name) + '\')" title="' + t('Copy link') + '">' + svgIcon('link', 14) + '</button>' +
                (canManage ? '<button class="delete" onclick="event.stopPropagation(); deleteDomain(' + idx + ')" title="' + t('Delete') + '">' + svgIcon('trash', 14) + '</button>' : '') +
            '</div></td>' +
        '</tr>';
    });

    html += '</tbody></table></div>';
    return html;
}

