                '<span style="font-size:12px;"><span style="color:#94a3b8;">' + col.layer + '.</span><span style="color:#3b82f6;">' + col.table + '</span>.<span style="color:#7c3aed;font-weight:600;">' + col.column + '</span></span>' +
                '<button onclick="removeLinkedColumn(' + ruleIndex + ', ' + idx + ')" style="background:#fee2e2;border:none;color:#dc2626;width:20px;height:20px;border-radius:4px;cursor:pointer;font-size:12px;">✕</button>' +
            '</div>';
