function selectStepIcon(icon) {
    document.getElementById('stepIcon').value = icon;
    document.getElementById('selectedIconPreview').textContent = icon;
    
    // Update button styles
    document.querySelectorAll('.icon-option').forEach(function(btn) {
        btn.style.background = 'white';
        btn.style.color = 'inherit';
    });
    event.target.style.background = '#3b82f6';
    event.target.style.color = 'white';
}

function editWorkflowStep(stepId) {
    showAddWorkflowStepModal(stepId);
}

function saveWorkflowStep(editId) {
    var id = document.getElementById('stepId').value.trim().toLowerCase().replace(/\s+/g, '_');
    var name = document.getElementById('stepName').value.trim();
    var icon = document.getElementById('stepIcon').value.trim() || '📋';
    var color = document.getElementById('stepColor').value;
    var order = parseInt(document.getElementById('stepOrder').value) || 1;
    var nextStep = document.getElementById('stepNextStep').value || null;
    var rejectStep = document.getElementById('stepRejectStep').value || null;
    
    if (!id || !name) {
        alert('ID və Ad mütləqdir!');
        return;
    }
    
    var createdBy = [];
    document.querySelectorAll('.create-role-check:checked').forEach(function(cb) {
        createdBy.push(cb.value);
    });
    
    var approvedBy = [];
    document.querySelectorAll('.approve-role-check:checked').forEach(function(cb) {
        approvedBy.push(cb.value);
    });
    
    var stepData = {
        id: id,
        name: name,
        icon: icon,
        color: color,
        order: order,
        createdBy: createdBy.length > 0 ? createdBy : null,
        approvedBy: approvedBy.length > 0 ? approvedBy : null,
        nextStep: nextStep,
        rejectStep: rejectStep
    };
    
    if (editId) {
        var idx = governanceData.workflowSteps.findIndex(function(s) { return s.id === editId; });
        if (idx !== -1) {
            governanceData.workflowSteps[idx] = stepData;
        }
    } else {
        if (governanceData.workflowSteps.some(function(s) { return s.id === id; })) {
            alert('Bu ID artıq mövcuddur!');
            return;
        }
        governanceData.workflowSteps.push(stepData);
    }
    
    saveGovernanceToStorage();
    closeGlossaryModal();
    loadGlossary();
    setTimeout(function() { showGlossaryTab('workflow'); }, 100);
}

async function deleteWorkflowStep(stepId) {
    if (!confirm('Bu workflow addımını silmək istəyirsiniz?')) return;

    var step = governanceData.workflowSteps.find(function(s) { return s.id === stepId; });
    if (step && step.dbId) {
        try {
            await apiCall('governance_steps', 'DELETE', null, step.dbId);
        } catch (e) {
            alert('Silinmə uğursuz: ' + (e && e.message ? e.message : 'naməlum'));
            return;
        }
    }

    governanceData.workflowSteps = governanceData.workflowSteps.filter(function(s) { return s.id !== stepId; });
    closeGlossaryModal();
    if (typeof loadWorkflowStepsFromDB === 'function') loadWorkflowStepsFromDB();
    loadGlossary();
    setTimeout(function() { showGlossaryTab('workflow'); }, 100);
}

