function editRole(roleId) {
    // Check if this is a system role (readonly)
    var role = governanceData.roles.find(function(r) { return r.id === roleId; });
    if (role && role.isSystem) {
        alert('⚠️ System rolları dəyişdirmək mümkün deyil!\n\nSystem rolları: Data Owner, Data Steward, Business Analyst, Data Engineer, Compliance Officer');
        return;
    }
    showAddRoleModal(roleId);
}

function saveRole(editId) {
    var id = document.getElementById('roleId').value.trim().toLowerCase().replace(/\s+/g, '_');
    var name = document.getElementById('roleName').value.trim();
    var icon = document.getElementById('roleIcon').value.trim() || '👤';
    var color = document.getElementById('roleColor').value;
    var description = document.getElementById('roleDescription').value.trim();
    
    if (!id || !name) {
        alert('ID və Ad mütləqdir!');
        return;
    }
    
    // Check if editing a system role
    if (editId) {
        var existingRole = governanceData.roles.find(function(r) { return r.id === editId; });
        if (existingRole && existingRole.isSystem) {
            alert('⚠️ System rolları dəyişdirmək mümkün deyil!');
            return;
        }
    }
    
    var roleData = {
        id: id,
        name: name,
        icon: icon,
        color: color,
        description: description,
        isSystem: false // User-created roles are never system
    };
    
    if (editId) {
        var idx = governanceData.roles.findIndex(function(r) { return r.id === editId; });
        if (idx !== -1) {
            governanceData.roles[idx] = roleData;
        }
    } else {
        if (governanceData.roles.some(function(r) { return r.id === id; })) {
            alert('Bu ID artıq mövcuddur!');
            return;
        }
        governanceData.roles.push(roleData);
    }
    
    saveGovernanceToStorage();
    closeGlossaryModal();
    loadGlossary();
    setTimeout(function() { showGlossaryTab('workflow'); }, 100);
}

function deleteRole(roleId) {
    // Check if this is a system role
    var role = governanceData.roles.find(function(r) { return r.id === roleId; });
    if (role && role.isSystem) {
        alert('⚠️ System rolları silmək mümkün deyil!');
        return;
    }
    
    var stakeholderCount = governanceData.stakeholders.filter(function(s) { return s.role === roleId; }).length;
    if (stakeholderCount > 0) {
        alert('Bu rol ' + stakeholderCount + ' stakeholder tərəfindən istifadə olunur. Əvvəlcə onları başqa rola köçürün.');
        return;
    }
    
    if (!confirm('Bu rolu silmək istəyirsiniz?')) return;
    
    governanceData.roles = governanceData.roles.filter(function(r) { return r.id !== roleId; });
    
    // Remove from workflow steps
    governanceData.workflowSteps.forEach(function(step) {
        if (step.createdBy) step.createdBy = step.createdBy.filter(function(r) { return r !== roleId; });
        if (step.approvedBy) step.approvedBy = step.approvedBy.filter(function(r) { return r !== roleId; });
    });
    
    saveGovernanceToStorage();
    closeGlossaryModal();
    loadGlossary();
    setTimeout(function() { showGlossaryTab('workflow'); }, 100);
}

