function confirmRestoreTerm(index) {
    var term = glossaryData.terms[index];
    var newStatus = document.getElementById('restoreStatus').value;
    var now = new Date();
    var dateStr = now.getFullYear() + '-' + String(now.getMonth() + 1).padStart(2, '0') + '-' + String(now.getDate()).padStart(2, '0') + ' ' + String(now.getHours()).padStart(2, '0') + ':' + String(now.getMinutes()).padStart(2, '0') + ':' + String(now.getSeconds()).padStart(2, '0');
    
    term.status = newStatus;
    term.restoredAt = dateStr;
    term.restoredBy = 'Current User';
    
    // Add to history - ensure it's an array
    if (!term.history || typeof term.history === 'string') {
        try { term.history = typeof term.history === 'string' ? JSON.parse(term.history) : []; } catch(e) { term.history = []; }
    }
    if (!Array.isArray(term.history)) term.history = [];
    term.history.push({
        date: dateStr,
        action: '♻️ Termin bərpa edildi',
        user: 'Current User',
        fromStep: 'deleted',
        toStep: newStatus
    });
    
    saveGlossaryToStorage();
    closeGlossaryModal();
    loadGlossary();
    
    showNotification('Termin uğurla bərpa edildi', 'success');
}

