async function confirmPermanentDelete(index) {
    var term = glossaryData.terms[index];

    if (term.id) {
        try {
            var response = await fetch(API + '?action=glossary_terms&id=' + term.id, {
                method: 'DELETE',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({ soft: false })
            });
            var result = await response.json();
            if (result.error) {
                showNotification('Silinmə uğursuz: ' + result.error, 'error');
                return;
            }
        } catch (e) {
            console.error('Permanent delete MySQL error:', e);
            showNotification('Silinmə uğursuz: ' + e.message, 'error');
            return;
        }
    }

    glossaryData.terms.splice(index, 1);
    saveGlossaryToStorage();
    closeGlossaryModal();
    loadGlossary();

    showNotification('Termin həmişəlik silindi', 'success');
}

