function quickFillTerm(termName) {
    document.getElementById('aiTermPrompt').value = termName;
    generateTermWithAI();
}

async function generateTermWithAI() {
    var promptInput = document.getElementById('aiTermPrompt');
    var termName = promptInput.value.trim();
    
    if (!termName) {
        alert('Zəhmət olmasa termin adını daxil edin');
        return;
    }
    
    var btn = document.getElementById('aiGenerateBtn');
    var btnText = document.getElementById('aiBtnText');
    var spinner = document.getElementById('aiSpinner');
    
    // Show loading
    btn.disabled = true;
    btn.style.opacity = '0.7';
    btnText.textContent = 'Yüklənir...';
    spinner.style.display = 'inline-block';
    
    try {
        var response = await fetch('backend.php?action=ai_generate_term', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ term_name: termName })
        });
        
        var result = await response.json();
        
        if (result.success && result.data) {
            fillTermFormWithAI(result.data);
            showToast('✨ AI termini uğurla doldurdu!', 'success');
        } else {
            throw new Error(result.error || 'AI xətası');
        }
    } catch (e) {
        console.error('AI generate error:', e);
        showToast('AI xətası: ' + e.message, 'error');
    } finally {
        // Reset button
        btn.disabled = false;
        btn.style.opacity = '1';
        btnText.textContent = '✨ AI ilə Doldur';
        spinner.style.display = 'none';
    }
}

function fillTermFormWithAI(data) {
    // Helper to set value and add AI indicator
    function setField(id, value) {
        var el = document.getElementById(id);
        if (el && value) {
            el.value = value;
            el.style.borderColor = '#14b8a6';
            el.style.background = '#f0fdfa';
            // Add AI badge
            var label = el.parentElement.querySelector('label');
            if (label && !label.querySelector('.ai-badge')) {
                var badge = document.createElement('span');
                badge.className = 'ai-badge';
                badge.style.cssText = 'margin-left: 8px; padding: 2px 8px; background: #ccfbf1; border-radius: 4px; font-size: 10px; color: #0d9488; font-weight: 500;';
                badge.textContent = '🤖 AI';
                label.appendChild(badge);
            }
        }
    }
    
    // Fill basic fields
    setField('termName', data.name);
    setField('termAbbreviation', data.abbreviation);
    setField('termDefinition', data.definition);
    setField('termDataType', data.dataType);
    setField('termExample', data.example);
    setField('termFormula', data.formula);
    setField('termBusinessLogic', data.businessLogic);
    setField('termTechnicalDesc', data.technicalDesc);
    setField('termSynonyms', data.synonyms);
    setField('termRelated', data.relatedTerms);
    setField('termSource', data.sourceSystem);
    
    // Set domain dropdown
    if (data.domain) {
        var domainSelect = document.getElementById('termDomain');
        if (domainSelect) {
            var domainMapping = {
                'Finance': 'Maliyyə',
                'HR': 'HR',
                'Sales': 'Satış',
                'Marketing': 'Marketinq',
                'Analytics': 'Analitika',
                'Operations': 'Əməliyyatlar'
            };
            var mappedDomain = domainMapping[data.domain] || data.domain;
            
            // Try to find matching option
            for (var i = 0; i < domainSelect.options.length; i++) {
                if (domainSelect.options[i].value === mappedDomain || 
                    domainSelect.options[i].text.includes(mappedDomain) ||
                    domainSelect.options[i].text.includes(data.domain)) {
                    domainSelect.selectedIndex = i;
                    domainSelect.style.borderColor = '#14b8a6';
                    domainSelect.style.background = '#f0fdfa';
                    // Trigger stakeholders update
                    updateDomainStakeholders();
                    break;
                }
            }
        }
    }
    
    // Switch to basic tab to show filled fields
    switchFormTab('basic');
}

function closeGlossaryModal() {
    var modal = document.getElementById('glossaryModal');
    if (modal) {
        modal.style.display = 'none';
    }
}

