// Catalog Data Management
var catalogData = {
    layers: ['SOURCE', 'ODS', 'STAGE', 'DWH', 'OBIEE'],
    tables: {}
};

var defaultLayerColors = {
    'SOURCE': { bg: '#fee2e2', border: '#ef4444', text: '#b91c1c', icon: '🗄️' },
    'ODS': { bg: '#fef3c7', border: '#f59e0b', text: '#b45309', icon: '📥' },
    'STAGE': { bg: '#dbeafe', border: '#3b82f6', text: '#1d4ed8', icon: '⚙️' },
    'DWH': { bg: '#d1fae5', border: '#10b981', text: '#047857', icon: '🏛️' },
    'OBIEE': { bg: '#e9d5ff', border: '#a855f7', text: '#7c3aed', icon: '📊' }
};

function getLayerColor(layer) {
    return defaultLayerColors[layer] || { bg: '#f1f5f9', border: '#94a3b8', text: '#475569', icon: '📁' };
}

function loadCatalogFromStorage(forceReload) {
    // Skip if already loaded and not forcing reload
    if (catalogLoaded && !forceReload) {
        return;
    }
    
    // Always initialize layerDetails
    if (!catalogData.layerDetails) catalogData.layerDetails = {};
    if (!catalogData.layerIdToName) catalogData.layerIdToName = {};
    
    try {
        // Load layers from MySQL
        var layers = apiCallSync('catalog_layers', 'GET');
        console.log('Loaded layers from MySQL:', layers);
        
        if (layers && Array.isArray(layers) && layers.length > 0) {
            catalogData.layers = layers.map(function(l) { return l.name; });
            catalogData.layerDetails = {};
            catalogData.layerIdToName = {}; // Map layer_id to layer name
            
            layers.forEach(function(l) {
                catalogData.layerDetails[l.name] = {
                    id: l.id,
                    icon: l.icon,
                    color: l.color,
                    description: l.description,
                    order: l.order
                };
                catalogData.layerIdToName[l.id] = l.name;
                
                // Update defaultLayerColors from DB
                if (l.icon || l.color) {
                    var bgColor = l.color ? l.color + '20' : '#f1f5f9';
                    // Map color to background
                    var colorToBg = {
                        '#3b82f6': '#dbeafe',
                        '#10b981': '#d1fae5',
                        '#f59e0b': '#fef3c7',
                        '#8b5cf6': '#ede9fe',
                        '#ef4444': '#fee2e2',
                        '#06b6d4': '#cffafe',
                        '#ec4899': '#fce7f3',
                        '#64748b': '#f1f5f9'
                    };
                    defaultLayerColors[l.name] = {
                        bg: colorToBg[l.color] || '#f1f5f9',
                        border: l.color || '#94a3b8',
                        text: l.color || '#475569',
                        icon: l.icon || '📁'
                    };
                }
            });
            
            // Load tables with columns from MySQL
            var tables = apiCallSync('catalog_tables', 'GET');
            console.log('Loaded tables from MySQL:', tables);
            
            if (tables && Array.isArray(tables) && tables.length > 0) {
                catalogData.tables = {};
                // Initialize all layers with empty arrays
                catalogData.layers.forEach(function(layer) {
                    catalogData.tables[layer] = [];
                });
                
                tables.forEach(function(t) {
                    // Get layer name - prefer layer_name, fallback to lookup by layer_id
                    var layerName = t.layer_name;
                    if (!layerName && t.layer_id && catalogData.layerIdToName[t.layer_id]) {
                        layerName = catalogData.layerIdToName[t.layer_id];
                    }
                    
                    console.log('Table:', t.name, 'Layer:', layerName, 'Columns:', (t.columns || []).length);
                    
                    if (layerName) {
                        if (!catalogData.tables[layerName]) {
                            catalogData.tables[layerName] = [];
                        }
                        catalogData.tables[layerName].push({
                            id: t.id,
                            name: t.name,
                            description: t.description,
                            owner: t.owner,
                            rowCount: t.row_count,
                            columns: (t.columns || []).map(function(c) {
                                return {
                                    id: c.id,
                                    name: c.name,
                                    type: c.data_type,
                                    dataType: c.data_type, // Also add as dataType for compatibility
                                    description: c.description,
                                    icon: c.icon || '📊',
                                    isPk: c.is_pk,
                                    isFk: c.is_fk
                                };
                            })
                        });
                    }
                });
                
                console.log('Final catalogData.tables:', catalogData.tables);
                catalogLoaded = true;
                return; // Success - exit function
            } else {
                // Tables empty from MySQL - just initialize empty tables for each layer
                console.warn('MySQL tables empty, keeping MySQL layers with empty tables');
                catalogData.tables = {};
                catalogData.layers.forEach(function(layer) {
                    catalogData.tables[layer] = [];
                });
                catalogLoaded = true;
                return;
            }
        }
        
        // If MySQL returned empty or null, fallback to sample data
        console.warn('MySQL returned empty data, using sample data');
        initializeSampleCatalogData();
        catalogLoaded = true;
    } catch (e) {
        console.error('MySQL error, falling back to sample data:', e);
        initializeSampleCatalogData();
        catalogLoaded = true;
    }
}

