// Filter catalog by layer
function filterCatalogByLayer(layer) {
    // Convert empty string to null
    if (layer === '' || layer === 'null') layer = null;
    
    // Clear search when filtering by layer
    var searchInput = document.getElementById('catalogSearch');
    if (searchInput) searchInput.value = '';
    var searchInfo = document.getElementById('catalogSearchInfo');
    if (searchInfo) searchInfo.style.display = 'none';
    var clearBtn = document.getElementById('catalogSearchClear');
    if (clearBtn) clearBtn.style.display = 'none';
    
    var layerSections = document.querySelectorAll('.catalog-layer-section');
    
    // Reset all table cards visibility
    document.querySelectorAll('.catalog-table-card').forEach(function(card) {
        card.style.display = 'block';
        card.classList.remove('search-highlight');
    });
    
    // Update select box if exists
    var selectBox = document.getElementById('layerFilterSelect');
    if (selectBox) {
        selectBox.value = layer || '';
    }
    
    if (layer === null) {
        // Show all layers
        layerSections.forEach(function(section) {
            section.style.display = 'block';
        });
        showNotification('Bütün layer-lər göstərilir', 'info');
    } else {
        // Show only selected layer
        layerSections.forEach(function(section) {
            if (section.dataset.layer === layer) {
                section.style.display = 'block';
            } else {
                section.style.display = 'none';
            }
        });
        
        showNotification(layer + ' layer-i filtrələndi', 'success');
    }
}

// Search catalog by table name or column name
function searchCatalog(query) {
    var searchInfo = document.getElementById('catalogSearchInfo');
    var clearBtn = document.getElementById('catalogSearchClear');
    
    query = (query || '').toLowerCase().trim();
    
    if (!query) {
        clearCatalogSearch();
        return;
    }
    
    if (clearBtn) clearBtn.style.display = 'block';
    
    var layerSections = document.querySelectorAll('.catalog-layer-section');
    var tableCards = document.querySelectorAll('.catalog-table-card');
    var matchedTables = 0;
    var matchedColumns = 0;
    var visibleLayers = new Set();
    
    console.log('Searching for:', query, 'Found', tableCards.length, 'table cards');
    
    // First hide all, then show matches
    tableCards.forEach(function(card) {
        var tableName = (card.getAttribute('data-table') || '').toLowerCase();
        var layer = card.getAttribute('data-layer') || '';
        var tableMatched = tableName.includes(query);
        var columnMatched = false;
        
        // Check columns
        var columns = card.querySelectorAll('.columns-table td code');
        columns.forEach(function(col) {
            if (col.textContent.toLowerCase().includes(query)) {
                columnMatched = true;
                col.style.background = '#fef3c7';
                col.style.padding = '2px 6px';
                col.style.borderRadius = '4px';
            } else {
                col.style.background = '';
                col.style.padding = '';
            }
        });
        
        var tableNameEl = card.querySelector('.table-name');
        
        if (tableMatched || columnMatched) {
            card.style.display = 'block';
            visibleLayers.add(layer);
            
            if (tableMatched) {
                matchedTables++;
                if (tableNameEl) {
                    tableNameEl.style.background = '#dbeafe';
                    tableNameEl.style.padding = '2px 8px';
                    tableNameEl.style.borderRadius = '4px';
                }
            } else {
                if (tableNameEl) {
                    tableNameEl.style.background = '';
                    tableNameEl.style.padding = '';
                }
            }
            
            if (columnMatched) {
                matchedColumns++;
                // Expand columns section to show matched columns
                var colSection = card.querySelector('.table-columns');
                if (colSection) colSection.style.display = 'block';
            }
        } else {
            card.style.display = 'none';
            if (tableNameEl) {
                tableNameEl.style.background = '';
            }
        }
    });
    
    // Show/hide layer sections based on matches
    layerSections.forEach(function(section) {
        var sectionLayer = section.getAttribute('data-layer');
        if (visibleLayers.has(sectionLayer)) {
            section.style.display = 'block';
        } else {
            section.style.display = 'none';
        }
    });
    
    // Update search info
    var totalMatches = matchedTables + matchedColumns;
    if (searchInfo) {
        if (totalMatches > 0) {
            searchInfo.innerHTML = '🔍 <strong>' + matchedTables + '</strong> cədvəl, <strong>' + matchedColumns + '</strong> sütun tapıldı';
            searchInfo.style.display = 'block';
            searchInfo.style.color = '#059669';
        } else {
            searchInfo.innerHTML = '😕 "<strong>' + query + '</strong>" üçün nəticə tapılmadı';
            searchInfo.style.display = 'block';
            searchInfo.style.color = '#dc2626';
        }
    }
    
    console.log('Search results:', matchedTables, 'tables,', matchedColumns, 'columns');
}

function clearCatalogSearch() {
    var searchInput = document.getElementById('catalogSearch');
    var searchInfo = document.getElementById('catalogSearchInfo');
    var clearBtn = document.getElementById('catalogSearchClear');
    
    if (searchInput) searchInput.value = '';
    if (searchInfo) searchInfo.style.display = 'none';
    if (clearBtn) clearBtn.style.display = 'none';
    
    // Show all tables
    document.querySelectorAll('.catalog-layer-section').forEach(function(section) {
        section.style.display = 'block';
    });
    
    document.querySelectorAll('.catalog-table-card').forEach(function(card) {
        card.style.display = 'block';
        var tableName = card.querySelector('.table-name');
        if (tableName) {
            tableName.style.background = '';
            tableName.style.padding = '';
        }
    });
    
    // Reset column highlights
    document.querySelectorAll('.columns-table td code').forEach(function(col) {
        col.style.background = '';
        col.style.padding = '';
    });
    
    // Collapse all column sections
    document.querySelectorAll('.table-columns').forEach(function(section) {
        section.style.display = 'none';
    });
    
    // Reset layer badges
    document.querySelectorAll('.catalog-layer-badge').forEach(function(badge) {
        badge.style.opacity = '1';
        badge.style.transform = 'scale(1)';
        badge.style.boxShadow = 'none';
    });
}

function toggleLayerSection(el) {
    el.classList.toggle('collapsed');
    var content = el.nextElementSibling;
    
    // Toggle display
    if (content.style.display === 'none') {
        content.style.display = '';
    } else {
        content.style.display = 'none';
    }
}

function toggleTableColumns(el) {
    el.classList.toggle('open');
    var columns = el.nextElementSibling;
    columns.style.display = columns.style.display === 'none' ? 'block' : 'none';
}

