function addLayer() {
    var name = document.getElementById('newLayerName').value.trim().toUpperCase();
    var icon = document.getElementById('newLayerIcon').value || '📁';
    var color = document.getElementById('newLayerColor').value || '#64748b';
    var desc = document.getElementById('newLayerDesc').value.trim();
    
    if (!name) { alert('Layer adı daxil edin'); return; }
    if (catalogData.layers.indexOf(name) !== -1) { alert('Bu layer artıq mövcuddur'); return; }
    
    // Get background color from selected option
    var colorSelect = document.getElementById('newLayerColor');
    var bgColor = colorSelect.options[colorSelect.selectedIndex].getAttribute('data-bg') || '#f1f5f9';
    
    // Try to save to MySQL
    var savedId = null;
    try {
        var result = apiCallSync('catalog_layers', 'POST', {
            name: name,
            icon: icon,
            color: color,
            description: desc,
            order: catalogData.layers.length + 1
        });
        
        console.log('Layer saved to MySQL:', result);
        
        if (result && result.id) {
            savedId = result.id;
        }
    } catch (e) {
        console.error('addLayer MySQL error:', e);
    }
    
    // Add to local data (with or without MySQL id)
    catalogData.layers.push(name);
    catalogData.tables[name] = [];
    
    if (!catalogData.layerDetails) catalogData.layerDetails = {};
    catalogData.layerDetails[name] = {
        id: savedId,
        icon: icon,
        color: color,
        description: desc
    };
    
    defaultLayerColors[name] = { 
        bg: bgColor, 
        border: color, 
        text: color, 
        icon: icon 
    };
    
    // Note: Layer already saved to MySQL via API call above
    
    closeModal();
    loadCatalog();
    showNotification(savedId ? 'Layer uğurla əlavə edildi' : 'Layer əlavə edildi (yerli)', savedId ? 'success' : 'info');
}

// Confirm and Delete Layer (helper to avoid string escaping issues)
function confirmDeleteLayer(layerName, layerId) {
    closeCatalogModal();
    deleteLayer(layerName, layerId);
}

// Delete Layer
async function deleteLayer(layerName, layerId) {
    var tableCount = catalogData.tables[layerName] ? catalogData.tables[layerName].length : 0;
    
    var message = 'Bu layer-i silmək istədiyinizə əminsiniz?\n\n📂 ' + layerName;
    if (tableCount > 0) {
        message += '\n⚠️ Bu layer-də ' + tableCount + ' cədvəl var. Layer silinsə cədvəllər də silinəcək!';
    }
    
    if (!confirm(message)) return;
    
    // Delete from MySQL if has ID
    if (layerId) {
        try {
            var res = await fetch(API + '?action=catalog_layers&id=' + layerId, {
                method: 'DELETE'
            });
            var json = await res.json();
            console.log('Layer deleted from MySQL:', json);
        } catch (e) {
            console.error('deleteLayer MySQL error:', e);
            alert('Layer silinmədi: ' + e.message);
            return; // Don't continue if API failed
        }
    }
    
    // Remove from local data
    var idx = catalogData.layers.indexOf(layerName);
    if (idx !== -1) {
        catalogData.layers.splice(idx, 1);
    }
    delete catalogData.tables[layerName];
    if (catalogData.layerDetails) {
        delete catalogData.layerDetails[layerName];
    }
    if (defaultLayerColors[layerName]) {
        delete defaultLayerColors[layerName];
    }
    
    // Note: Layer already deleted from MySQL via API call above
    
    loadCatalog();
    showNotification('Layer silindi: ' + layerName, 'success');
}

