function loadDomainsForReportFilter() {
    apiCall('domains', 'GET').then(function(domains) {
        var select = document.getElementById('reportDomainFilter');
        if (select && domains) {
            select.innerHTML = '<option value="">Bütün domenlər</option>';
            domains.forEach(function(d) {
                select.innerHTML += '<option value="' + d.id + '">' + d.icon + ' ' + d.name + '</option>';
            });
        }
    });
}

async function fetchReportsNew() {
    try {
        var search = document.getElementById('reportSearch')?.value || '';
        var domain = document.getElementById('reportDomainFilter')?.value || '';
        var tool = document.getElementById('reportToolFilter')?.value || '';
        var status = document.getElementById('reportStatusFilter')?.value || '';
        
        var url = API + '?action=reports';
        if (search) url += '&search=' + encodeURIComponent(search);
        if (domain) url += '&domain=' + domain;
        if (tool) url += '&bi_tool=' + tool;
        if (status) url += '&status=' + status;
        
        var res = await fetch(url);
        var json = await res.json();
        
        if (json.success) {
            renderReportsGrid(json.data);
            updateReportStats(json.data);
        }
    } catch (e) {
        console.error('Error loading reports:', e);
        document.getElementById('reportsGrid').innerHTML = '<div class="empty-reports"><div style="font-size: 48px; margin-bottom: 16px;">⚠️</div><div>Hesabatlar yüklənərkən xəta baş verdi</div></div>';
    }
}

function filterReports() {
    fetchReportsNew();
}

function updateReportStats(reports) {
    var total = reports.length;
    var certified = reports.filter(function(r) { return r.certification_status === 'certified'; }).length;
    var avgQuality = reports.length > 0 ? reports.reduce(function(sum, r) { return sum + (parseFloat(r.overall_quality_score) || 0); }, 0) / reports.length : 0;
    
    // Count by BI tool
    var biToolCounts = {};
    var biToolMeta = {
        'power_bi': { icon: '📊', name: 'Power BI', color: '#F2C811' },
        'tableau': { icon: '📈', name: 'Tableau', color: '#E97627' },
        'looker': { icon: '👁️', name: 'Looker', color: '#4285F4' },
        'qlik': { icon: '🟢', name: 'Qlik', color: '#009845' },
        'obiee': { icon: '🔴', name: 'OBIEE', color: '#C74634' },
        'excel': { icon: '📗', name: 'Excel', color: '#217346' },
        'custom': { icon: '⚙️', name: 'Custom', color: '#6366f1' },
        'other': { icon: '📋', name: 'Digər', color: '#94a3b8' }
    };
    
    reports.forEach(function(r) {
        var tool = r.bi_tool || 'other';
        biToolCounts[tool] = (biToolCounts[tool] || 0) + 1;
    });
    
    // Build BI tools HTML
    var biToolsHtml = '';
    Object.keys(biToolCounts).sort(function(a, b) { return biToolCounts[b] - biToolCounts[a]; }).forEach(function(tool) {
        var meta = biToolMeta[tool] || biToolMeta['other'];
        biToolsHtml += '<div class="report-stat" style="min-width: 80px;">' +
            '<div class="report-stat-value" style="color: ' + meta.color + '; display: flex; align-items: center; justify-content: center; gap: 6px;">' + 
                '<span style="font-size: 18px;">' + meta.icon + '</span>' + biToolCounts[tool] + 
            '</div>' +
            '<div class="report-stat-label">' + meta.name + '</div>' +
        '</div>';
    });
    
    var statsHtml = '<div class="report-stat"><div class="report-stat-value" style="color: #6366f1;">' + total + '</div><div class="report-stat-label">Ümumi Hesabatlar</div></div>' +
        '<div class="report-stat"><div class="report-stat-value" style="color: #10b981;">' + certified + '</div><div class="report-stat-label">Certified</div></div>' +
        biToolsHtml +
        '<div class="report-stat"><div class="report-stat-value" style="color: ' + (avgQuality >= 90 ? '#10b981' : avgQuality >= 70 ? '#f59e0b' : '#ef4444') + ';">' + avgQuality.toFixed(1) + '%</div><div class="report-stat-label">Orta Keyfiyyət</div></div>';
    
    document.getElementById('reportStats').innerHTML = statsHtml;
}

function renderReportsGrid(reports) {
    var grid = document.getElementById('reportsGrid');
    if (!grid) return;
    
    if (reports.length === 0) {
        grid.innerHTML = '<div class="empty-reports" style="grid-column: 1/-1;">' +
            '<div style="font-size: 48px; margin-bottom: 16px;">📊</div>' +
            '<div style="font-size: 18px; font-weight: 700; color: #64748b; margin-bottom: 10px;">Heç bir hesabat yoxdur</div>' +
            '<div style="font-size: 14px; color: #94a3b8; margin-bottom: 20px;">İlk hesabatı əlavə edərək başlayın</div>' +
            '<button onclick="showAddReportModal()" style="padding: 12px 24px; background: linear-gradient(135deg, #3b82f6, #1d4ed8); color: white; border: none; border-radius: 8px; font-size: 14px; cursor: pointer; font-weight: 600;">➕ İlk hesabatı yarat</button>' +
        '</div>';
        return;
    }
    
    var html = '';
    
    reports.forEach(function(report) {
        var toolColors = {
            'power_bi': { bg: '#fff3cd', color: '#856404', icon: '📊', name: 'Power BI' },
            'tableau': { bg: '#d1ecf1', color: '#0c5460', icon: '📈', name: 'Tableau' },
            'looker': { bg: '#d4edda', color: '#155724', icon: '👁️', name: 'Looker' },
            'qlik': { bg: '#cce5ff', color: '#004085', icon: '🔮', name: 'Qlik' },
            'obiee': { bg: '#f8d7da', color: '#721c24', icon: '🔴', name: 'OBIEE' },
            'excel': { bg: '#d4edda', color: '#155724', icon: '📗', name: 'Excel' },
            'custom': { bg: '#e2e3e5', color: '#383d41', icon: '⚙️', name: 'Custom' }
        };
        
        var statusColors = {
            'certified': { bg: '#dcfce7', color: '#166534', icon: '✅', text: 'Certified' },
            'under_review': { bg: '#fef3c7', color: '#92400e', icon: '🔄', text: 'Review' },
            'draft': { bg: '#f1f5f9', color: '#475569', icon: '📝', text: 'Draft' },
            'deprecated': { bg: '#fee2e2', color: '#991b1b', icon: '⚠️', text: 'Deprecated' }
        };
        
        var tool = toolColors[report.bi_tool] || toolColors['custom'];
        var status = statusColors[report.certification_status] || statusColors['draft'];
        
        var qualityScore = parseFloat(report.overall_quality_score) || 0;
        var qualityColor = qualityScore >= 90 ? '#10b981' : qualityScore >= 70 ? '#f59e0b' : '#ef4444';
        
        var ownerInitials = report.business_owner ? report.business_owner.split(' ').map(function(n) { return n[0]; }).join('').substring(0, 2).toUpperCase() : '??';
        
        html += '<div class="report-card" onclick="viewReport(' + report.id + ')">' +
            '<div class="report-card-header">' +
                '<div style="flex: 1;">' +
                    '<div class="report-card-title">' + report.report_name + '</div>' +
                    '<div class="report-card-id">' + report.report_id + '</div>' +
                '</div>' +
                '<div class="report-card-actions" style="display: flex; gap: 4px;">' +
                    '<button onclick="event.stopPropagation(); showAddReportModal(' + report.id + ')" title="Redaktə et" style="padding: 6px 8px; background: #dbeafe; color: #3b82f6; border: none; border-radius: 6px; cursor: pointer; font-size: 12px;">✏️</button>' +
                    '<button onclick="event.stopPropagation(); deleteReport(' + report.id + ', \'' + report.report_name.replace(/'/g, "\\'") + '\')" title="Sil" style="padding: 6px 8px; background: #fee2e2; color: #ef4444; border: none; border-radius: 6px; cursor: pointer; font-size: 12px;">🗑️</button>' +
                '</div>' +
            '</div>' +
            '<div class="report-card-body">' +
                '<div class="report-card-desc">' + (report.short_description || 'Təsvir yoxdur') + '</div>' +
                '<div class="report-card-meta">' +
                    '<div class="report-meta-item"><span class="report-meta-icon">🏢</span> ' + (report.domain_name || '-') + '</div>' +
                    '<div class="report-meta-item"><span class="report-meta-icon">🔄</span> ' + formatFrequency(report.update_frequency) + '</div>' +
                    '<div class="report-meta-item"><span class="report-meta-icon">🎯</span> ' + (report.target_audience || '-') + '</div>' +
                    '<div class="report-meta-item"><span class="report-meta-icon">🔒</span> ' + formatAccessLevel(report.access_level) + '</div>' +
                '</div>' +
            '</div>' +
            '<div class="report-card-footer">' +
                '<div style="display: flex; align-items: center; gap: 8px;">' +
                    (report.business_owner ?
                        '<div class="report-owner">' +
                            '<div class="report-owner-avatar">' + ownerInitials + '</div>' +
                            '<div class="report-owner-name">' + report.business_owner + '</div>' +
                        '</div>' : '') +
                    '<div class="report-card-badges">' +
                        '<span class="report-badge" style="background: ' + tool.bg + '; color: ' + tool.color + ';">' + tool.icon + ' ' + tool.name + '</span>' +
                        '<span class="report-badge" style="background: ' + status.bg + '; color: ' + status.color + ';">' + status.icon + ' ' + status.text + '</span>' +
                    '</div>' +
                '</div>' +
                '<div style="display: flex; align-items: center; gap: 12px;">' +
                    '<div class="report-quality">' +
                        '<div class="report-quality-bar"><div class="report-quality-fill" style="width: ' + qualityScore + '%; background: ' + qualityColor + ';"></div></div>' +
                        '<span class="report-quality-text" style="color: ' + qualityColor + ';">' + qualityScore.toFixed(0) + '%</span>' +
                    '</div>' +
                    '<div class="report-views">👁️ ' + (report.views_count || 0) + '</div>' +
                '</div>' +
            '</div>' +
        '</div>';
    });
    
    grid.innerHTML = html;
}

function formatFrequency(freq) {
    var map = {
        'real_time': 'Real-time',
        'hourly': 'Saatlıq',
        'daily': 'Gündəlik',
        'weekly': 'Həftəlik',
        'monthly': 'Aylıq',
        'quarterly': 'Rüblük',
        'yearly': 'İllik',
        'on_demand': 'Tələb üzrə'
    };
    return map[freq] || freq || '-';
}

function formatAccessLevel(level) {
    var map = {
        'public': 'Açıq',
        'restricted': 'Məhdud',
        'confidential': 'Gizli',
        'top_secret': 'Ən gizli'
    };
    return map[level] || level || '-';
}

