function closeUserModal() { var m = document.getElementById('userModal'); if(m) m.remove(); }

async function saveReportUser() {
    var reportId = document.getElementById('userReportId').value;
    var userName = document.getElementById('userName').value.trim();
    if (!userName) { showToast('İstifadəçi adı tələb olunur', 'error'); return; }
    
    var data = {
        report_id: reportId,
        user_name: userName,
        user_email: document.getElementById('userEmail').value.trim(),
        user_role: document.getElementById('userRole').value,
        department: document.getElementById('userDept').value.trim()
    };
    
    try {
        await apiCall('report_users', 'POST', data);
        showToast('İstifadəçi əlavə edildi', 'success');
        closeUserModal();
        viewReport(reportId);
    } catch(e) { showToast('Xəta baş verdi', 'error'); }
}

// --- LINK TERM MODAL (Glossary Integration) ---
async function showLinkReportTermModal(reportId) {
    // First, get already linked terms for this report
    var linkedTermIds = [];
    try {
        var res = await fetch(API + '?action=report_terms&report_id=' + reportId);
        var json = await res.json();
        if (json.success && json.data && Array.isArray(json.data)) {
            linkedTermIds = json.data.map(function(rt) { return parseInt(rt.term_id); });
        }
    } catch(e) {
        console.error('Error fetching linked terms:', e);
    }

    var modalHtml = '<div id="termModal" style="display:flex;position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);z-index:10001;align-items:center;justify-content:center;">' +
        '<div style="background:white;border-radius:12px;width:90%;max-width:600px;max-height:90vh;overflow:hidden;display:flex;flex-direction:column;">' +
            '<div style="padding:20px;border-bottom:1px solid #e5e7eb;display:flex;justify-content:space-between;align-items:center;">' +
                '<h3 style="font-size:18px;font-weight:700;">📖 Terminləri Bağla</h3>' +
                '<button onclick="closeTermModal()" style="background:none;border:none;font-size:24px;cursor:pointer;">×</button>' +
            '</div>' +
            '<div style="padding:20px;overflow-y:auto;flex:1;">' +
                '<input type="hidden" id="termReportId" value="' + reportId + '">' +
                '<div style="display:grid;gap:16px;">' +
                    '<div>' +
                        '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">' +
                            '<label style="font-size:12px;font-weight:600;color:#475569;">Terminlər *</label>' +
                            '<div style="display:flex;gap:8px;">' +
                                '<button type="button" onclick="selectAllTerms()" style="padding:4px 10px;font-size:11px;background:#dbeafe;color:#1d4ed8;border:none;border-radius:6px;cursor:pointer;">✓ Hamısını seç</button>' +
                                '<button type="button" onclick="deselectAllTerms()" style="padding:4px 10px;font-size:11px;background:#f1f5f9;color:#64748b;border:none;border-radius:6px;cursor:pointer;">✕ Heç birini</button>' +
                            '</div>' +
                        '</div>' +
                        '<div id="termCheckboxList" style="max-height:250px;overflow-y:auto;border:1px solid #e5e7eb;border-radius:8px;padding:8px;">Yüklənir...</div>' +
                        '<div id="selectedTermCount" style="font-size:11px;color:#64748b;margin-top:6px;">0 termin seçilib</div>' +
                    '</div>' +
                    '<div><label style="display:block;font-size:12px;font-weight:600;color:#475569;margin-bottom:6px;">Əlaqə Tipi (hamısı üçün)</label>' +
                        '<select id="termRelation" style="width:100%;padding:10px;border:1px solid #e5e7eb;border-radius:8px;">' +
                            '<option value="uses">📊 Uses (istifadə edir)</option><option value="defines">📝 Defines (təyin edir)</option>' +
                            '<option value="displays">👁️ Displays (göstərir)</option><option value="calculates">🔢 Calculates (hesablayır)</option>' +
                        '</select></div>' +
                '</div>' +
            '</div>' +
            '<div style="padding:16px 20px;border-top:1px solid #e5e7eb;display:flex;justify-content:flex-end;gap:12px;">' +
                '<button onclick="closeTermModal()" style="padding:10px 20px;background:#f1f5f9;border:none;border-radius:8px;cursor:pointer;">Ləğv et</button>' +
                '<button onclick="linkReportTerms()" style="padding:10px 20px;background:linear-gradient(135deg,#f59e0b,#d97706);color:white;border:none;border-radius:8px;cursor:pointer;font-weight:600;">🔗 Seçilənləri Bağla</button>' +
            '</div>' +
        '</div></div>';
    document.body.insertAdjacentHTML('beforeend', modalHtml);

    // Load glossary terms as checkboxes (excluding already linked ones)
    apiCall('glossary_terms', 'GET').then(function(terms) {
        var container = document.getElementById('termCheckboxList');
        if (container && terms) {
            var html = '';
            var availableCount = 0;
            terms.forEach(function(t) {
                // Show approved and draft terms (exclude deleted and already linked)
                if (t.status !== 'deleted' && linkedTermIds.indexOf(parseInt(t.id)) === -1) {
                    var statusBadge = t.status === 'draft' ? '<span style="background:#fef3c7;color:#92400e;padding:1px 6px;border-radius:4px;font-size:9px;margin-left:6px;">Draft</span>' : '';
                    html += '<label style="display:flex;align-items:center;padding:8px 10px;border-radius:6px;cursor:pointer;transition:background 0.2s;" onmouseover="this.style.background=\'#f8fafc\'" onmouseout="this.style.background=\'transparent\'">' +
                        '<input type="checkbox" class="term-checkbox" value="' + t.id + '" data-name="' + t.name + '" onchange="updateTermCount()" style="width:16px;height:16px;margin-right:10px;cursor:pointer;">' +
                        '<span style="flex:1;">' +
                            '<span style="font-size:13px;font-weight:500;color:#1e293b;">' + t.name + '</span>' + statusBadge +
                            '<span style="display:block;font-size:11px;color:#94a3b8;">' + (t.domain || 'N/A') + '</span>' +
                        '</span>' +
                    '</label>';
                    availableCount++;
                }
            });
            if (availableCount === 0) {
                html = '<div style="text-align:center;padding:30px;color:#94a3b8;">Bütün terminlər artıq bağlanıb</div>';
            }
            container.innerHTML = html;
            updateTermCount();
        }
    });
}

function selectAllTerms() {
    document.querySelectorAll('.term-checkbox').forEach(function(cb) { cb.checked = true; });
    updateTermCount();
}

function deselectAllTerms() {
    document.querySelectorAll('.term-checkbox').forEach(function(cb) { cb.checked = false; });
    updateTermCount();
}

function updateTermCount() {
    var count = document.querySelectorAll('.term-checkbox:checked').length;
    var el = document.getElementById('selectedTermCount');
    if (el) el.textContent = count + ' termin seçilib';
}

function closeTermModal() { var m = document.getElementById('termModal'); if(m) m.remove(); }

async function linkReportTerms() {
    var reportId = document.getElementById('termReportId').value;
    var selectedTerms = document.querySelectorAll('.term-checkbox:checked');

    if (selectedTerms.length === 0) {
        showToast('Ən azı bir termin seçin', 'error');
        return;
    }

    var relationshipType = document.getElementById('termRelation').value;
    var successCount = 0;
    var errorCount = 0;

    for (var i = 0; i < selectedTerms.length; i++) {
        var termId = selectedTerms[i].value;
        var data = {
            report_id: reportId,
            term_id: termId,
            relationship_type: relationshipType,
            notes: ''
        };

        try {
            await apiCall('report_terms', 'POST', data);
            successCount++;
        } catch(e) {
            errorCount++;
            console.error('Error linking term:', termId, e);
        }
    }

    if (successCount > 0) {
        showToast(successCount + ' termin bağlandı', 'success');
        closeTermModal();
        await viewReport(reportId);
        // Stay on terms tab
        setTimeout(function() {
            var termsTab = document.querySelector('.rd-tab[onclick*="terms"]');
            if (termsTab) termsTab.click();
        }, 100);
    }

    if (errorCount > 0) {
        showToast(errorCount + ' termin bağlana bilmədi', 'error');
    }
}

// --- LINK DATA CATALOG TABLE (Integration) ---
function showLinkCatalogTableModal(reportId) {
    var modalHtml = '<div id="catalogModal" style="display:flex;position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);z-index:10001;align-items:center;justify-content:center;">' +
        '<div style="background:white;border-radius:12px;width:90%;max-width:600px;max-height:90vh;overflow-y:auto;">' +
            '<div style="padding:20px;border-bottom:1px solid #e5e7eb;display:flex;justify-content:space-between;align-items:center;">' +
                '<h3 style="font-size:18px;font-weight:700;">🗄️ Data Catalog-dan Cədvəl Seç</h3>' +
                '<button onclick="closeCatalogModal()" style="background:none;border:none;font-size:24px;cursor:pointer;">×</button>' +
            '</div>' +
            '<div style="padding:20px;">' +
                '<input type="hidden" id="catalogReportId" value="' + reportId + '">' +
                '<div id="catalogTableList" style="max-height:400px;overflow-y:auto;"><div style="text-align:center;padding:20px;"><div class="spinner"></div></div></div>' +
            '</div>' +
            '<div style="padding:16px 20px;border-top:1px solid #e5e7eb;display:flex;justify-content:flex-end;">' +
                '<button onclick="closeCatalogModal()" style="padding:10px 20px;background:#f1f5f9;border:none;border-radius:8px;cursor:pointer;">Bağla</button>' +
            '</div>' +
        '</div></div>';
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    loadCatalogTablesForSelection(reportId);
}

async function loadCatalogTablesForSelection(reportId) {
    try {
        var [layers, tables] = await Promise.all([
            apiCall('catalog_layers', 'GET'),
            apiCall('catalog_tables', 'GET')
        ]);
        
        var html = '';
        layers.forEach(function(layer) {
            var layerTables = tables.filter(function(t) { return t.layer_id == layer.id; });
            if (layerTables.length > 0) {
                html += '<div style="margin-bottom:16px;">' +
                    '<div style="font-size:13px;font-weight:700;color:#64748b;margin-bottom:8px;padding:8px;background:#f8fafc;border-radius:6px;">' + layer.icon + ' ' + layer.name + '</div>';
                layerTables.forEach(function(t) {
                    html += '<div onclick="addCatalogTableAsSource(' + reportId + ',' + t.id + ',\'' + layer.name + '\',\'' + t.name + '\')" style="padding:12px 16px;border:1px solid #e5e7eb;border-radius:8px;margin-bottom:8px;cursor:pointer;transition:all 0.2s;" onmouseover="this.style.borderColor=\'#3b82f6\';this.style.background=\'#f0f9ff\'" onmouseout="this.style.borderColor=\'#e5e7eb\';this.style.background=\'white\'">' +
                        '<div style="font-weight:600;color:#1e293b;">' + t.name + '</div>' +
                        '<div style="font-size:12px;color:#64748b;">' + (t.description || 'Təsvir yoxdur') + '</div>' +
                    '</div>';
                });
                html += '</div>';
            }
        });
        
        document.getElementById('catalogTableList').innerHTML = html || '<div style="text-align:center;padding:20px;color:#94a3b8;">Heç bir cədvəl tapılmadı</div>';
    } catch(e) {
        document.getElementById('catalogTableList').innerHTML = '<div style="text-align:center;padding:20px;color:#ef4444;">Xəta baş verdi</div>';
    }
}

async function addCatalogTableAsSource(reportId, tableId, layerName, tableName) {
    var data = {
        report_id: reportId,
        source_type: 'table',
        layer_name: layerName,
        table_id: tableId,
        table_name: tableName
    };
    
    try {
        await apiCall('report_data_sources', 'POST', data);
        showToast(tableName + ' əlavə edildi', 'success');
        closeCatalogModal();
        viewReport(reportId);
    } catch(e) { showToast('Xəta baş verdi', 'error'); }
}

function closeCatalogModal() { var m = document.getElementById('catalogModal'); if(m) m.remove(); }

