function switchQualityTab(tabId, el) {
    // Update tab styles
    document.querySelectorAll('.quality-tab').forEach(function(tab) {
        tab.classList.remove('active');
    });
    el.classList.add('active');
    
    // Show/hide sections
    document.querySelectorAll('.quality-section').forEach(function(section) {
        section.classList.remove('active');
    });
    document.getElementById('quality-section-' + tabId).classList.add('active');
    
    // Load data for schedule tab
    if (tabId === 'schedule') {
        loadQualitySchedules();
        loadQualityExecutions();
    }
}

async function loadSodaChecksForQuality() {
    try {
        var res = await fetch(API + '?action=soda_checks');
        var json = await res.json();
        var checks = json.data && json.data.data ? json.data.data : (json.data || []);
        var container = document.getElementById('soda-checks-quality-container');
        
        if (!container) return;
        
        // Update stats
        var activeChecks = checks.filter(function(c) { return c.status === 'active'; }).length;
        document.getElementById('stat-total-checks').textContent = checks.length;
        document.getElementById('stat-active-checks').textContent = activeChecks;
        
        var html = '<div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px;">' +
            '<div>' +
                '<h3 style="font-size: 16px; font-weight: 700; color: #1e293b; margin: 0 0 4px 0;">🔍 Data Quality Check-ləri</h3>' +
                '<div style="font-size: 12px; color: #64748b;">Database-də avtomatik işlədilən keyfiyyət qaydaları</div>' +
            '</div>' +
            '<div style="display: flex; gap: 8px;">' +
                '<button onclick="runAllChecks()" style="padding: 10px 18px; background: #10b981; color: white; border: none; border-radius: 8px; font-size: 13px; cursor: pointer; font-weight: 600;">▶️ Hamısını İşlət</button>' +
                '<button onclick="showSodaCheckBuilder()" style="padding: 10px 18px; background: linear-gradient(135deg, #6366f1, #4f46e5); color: white; border: none; border-radius: 8px; font-size: 13px; cursor: pointer; font-weight: 600;">➕ Yeni Check</button>' +
            '</div>' +
        '</div>';
        
        if (checks.length === 0) {
            html += '<div style="background: white; border: 2px dashed #e5e7eb; border-radius: 12px; padding: 50px 40px; text-align: center;">' +
                '<div style="font-size: 48px; margin-bottom: 16px;">🔍</div>' +
                '<div style="font-size: 18px; font-weight: 700; color: #64748b; margin-bottom: 10px;">Heç bir check yoxdur</div>' +
                '<div style="font-size: 14px; color: #94a3b8; margin-bottom: 20px;">İlk check-i yaradaraq data keyfiyyətini avtomatik yoxlamağa başlayın</div>' +
                '<button onclick="showSodaCheckBuilder()" style="padding: 12px 24px; background: linear-gradient(135deg, #6366f1, #4f46e5); color: white; border: none; border-radius: 8px; font-size: 14px; cursor: pointer; font-weight: 600;">➕ İlk Check-i Yarat</button>' +
            '</div>';
        } else {
            html += '<table class="quality-table">' +
                '<thead><tr>' +
                    '<th style="width: 50px;">' + t('Type') + '</th>' +
                    '<th>' + t('Check Name') + '</th>' +
                    '<th>' + t('Table') + '</th>' +
                    '<th style="width: 100px;">' + t('Column') + '</th>' +
                    '<th style="width: 80px;">' + t('Status') + '</th>' +
                    '<th style="width: 120px; text-align: center;">' + t('Last Result') + '</th>' +
                    '<th style="width: 150px; text-align: center;">' + t('Actions') + '</th>' +
                '</tr></thead>' +
                '<tbody>';
            
            var typeIcons = {
                'row_count': '📊',
                'missing': '🔍',
                'duplicate': '👥',
                'freshness': '⏰',
                'validity': '✅',
                'custom': '⚙️'
            };
            
            var typeColors = {
                'row_count': { bg: '#dbeafe', color: '#1d4ed8' },
                'missing': { bg: '#fef3c7', color: '#b45309' },
                'duplicate': { bg: '#fce7f3', color: '#be185d' },
                'freshness': { bg: '#d1fae5', color: '#047857' },
                'validity': { bg: '#e0e7ff', color: '#4338ca' },
                'custom': { bg: '#f3e8ff', color: '#7c3aed' }
            };
            
            checks.forEach(function(check) {
                var icon = typeIcons[check.check_type] || svgIcon('clipboard', 14);
                var typeStyle = typeColors[check.check_type] || { bg: '#f3f4f6', color: '#374151' };
                var statusColor = check.status === 'active' ? '#10b981' : '#94a3b8';
                var statusBg = check.status === 'active' ? '#f0fdf4' : '#f8fafc';
                var statusText = check.status === 'active' ? 'Aktiv' : 'Deaktiv';
                
                // Get target and threshold for color calculation
                var targetVal = parseFloat(check.target_value) || 100;
                var thresholdVal = parseFloat(check.threshold_value) || 90;
                
                // Get last result from check if available
                var lastResultHtml = '<span style="color: #cbd5e1; font-size: 20px;">—</span>';
                if (check.last_outcome) {
                    var pct = check.last_percentage || 0;
                    
                    // Determine color based on target/threshold
                    var pctColor, pctBg;
                    if (pct >= targetVal) {
                        pctColor = '#047857'; pctBg = '#d1fae5'; // Green
                    } else if (pct >= thresholdVal) {
                        pctColor = '#b45309'; pctBg = '#fef3c7'; // Amber
                    } else {
                        pctColor = '#dc2626'; pctBg = '#fee2e2'; // Red
                    }
                    
                    // Better UI - compact badge with percentage
                    if (pct > 0) {
                        lastResultHtml = '<div style="display: inline-flex; align-items: center; gap: 6px; padding: 6px 10px; background: ' + pctBg + '; border-radius: 8px;">' +
                            '<span style="font-size: 14px; font-weight: 700; color: ' + pctColor + ';">' + pct.toFixed(1) + '%</span>' +
                        '</div>';
                    } else {
                        var outcomeIcon = check.last_outcome === 'pass' ? '🟢' : check.last_outcome === 'fail' ? '🔴' : '🟡';
                        lastResultHtml = '<span style="font-size: 18px;">' + outcomeIcon + '</span>';
                    }
                }
                
                html += '<tr>' +
                    '<td><span style="font-size: 22px;" title="' + check.check_type + '">' + icon + '</span></td>' +
                    '<td>' +
                        '<div style="font-weight: 600; color: #1e293b;">' + (check.check_name || 'Unnamed') + '</div>' +
                        '<div style="font-size: 11px; color: #64748b;"><span style="padding: 2px 6px; background: ' + typeStyle.bg + '; color: ' + typeStyle.color + '; border-radius: 8px; font-size: 10px;">' + check.check_type + '</span></div>' +
                    '</td>' +
                    '<td style="color: #3b82f6; font-weight: 500;">' + (check.table_name || '-') + '</td>' +
                    '<td style="color: #64748b; font-size: 12px;">' + (check.column_name || '-') + '</td>' +
                    '<td><span class="quality-badge" style="background: ' + statusBg + '; color: ' + statusColor + ';">' + statusText + '</span></td>' +
                    '<td id="check-result-' + check.id + '" style="text-align: center;">' + lastResultHtml + '</td>' +
                    '<td>' +
                        '<div class="quality-actions" style="justify-content: center;">' +
                            '<button onclick="runCheck(' + check.id + ')" title="İşlət" style="background: #d1fae5; color: #047857; border-color: #a7f3d0;">▶️</button>' +
                            '<button onclick="editSodaCheck(' + check.id + ')" title="Redaktə">✏️</button>' +
                            '<button onclick="deleteCheck(' + check.id + ')" title="Sil" style="color: #ef4444; border-color: #fee2e2;">🗑️</button>' +
                        '</div>' +
                    '</td>' +
                '</tr>';
            });
            
            html += '</tbody></table>';
        }
        
        container.innerHTML = html;
    } catch (e) {
        console.error('Error loading Soda checks:', e);
        var container = document.getElementById('soda-checks-quality-container');
        if (container) container.innerHTML = '<div class="dash-empty">Check-lər yüklənə bilmədi</div>';
    }
}

async function loadSodaResultsForQuality() {
    try {
        var res = await fetch(API + '?action=soda_scans&limit=50');
        var json = await res.json();
        var scans = json.data && json.data.data ? json.data.data : [];
        var container = document.getElementById('soda-results-quality-container');
        
        if (!container) return;
        
        // Calculate stats from results
        var totalRuns = 0;
        var totalPassed = 0;
        var totalFailed = 0;
        
        scans.forEach(function(scan) {
            var results = scan.results || {};
            var checks = results.checks || [];
            checks.forEach(function(check) {
                totalRuns++;
                if (check.outcome === 'pass') totalPassed++;
                else if (check.outcome === 'fail') totalFailed++;
            });
        });
        
        var passRate = totalRuns > 0 ? Math.round((totalPassed / totalRuns) * 100) : 0;
        var passRateColor = passRate >= 90 ? '#10b981' : passRate >= 70 ? '#f59e0b' : '#ef4444';
        
        // Update stats
        document.getElementById('stat-total-runs').textContent = totalRuns;
        document.getElementById('stat-pass-rate').textContent = passRate + '%';
        document.getElementById('stat-pass-rate').style.color = passRateColor;
        document.getElementById('stat-failed').textContent = totalFailed;
        
        var html = '<div style="margin-bottom: 20px;">' +
            '<h3 style="font-size: 16px; font-weight: 700; color: #1e293b; margin: 0 0 4px 0;">📊 Scan Nəticələri</h3>' +
            '<div style="font-size: 12px; color: #64748b;">Check-lərin işlədilmə tarixçəsi və nəticələri</div>' +
        '</div>';
        
        if (scans.length === 0) {
            html += '<div style="background: white; border: 2px dashed #e5e7eb; border-radius: 12px; padding: 50px 40px; text-align: center;">' +
                '<div style="font-size: 48px; margin-bottom: 16px;">📊</div>' +
                '<div style="font-size: 18px; font-weight: 700; color: #64748b; margin-bottom: 10px;">Hələ heç bir nəticə yoxdur</div>' +
                '<div style="font-size: 14px; color: #94a3b8;">Check-ləri işlətdikdən sonra nəticələr burada görünəcək</div>' +
            '</div>';
        } else {
            html += '<div id="quality-soda-results-list"></div>';
        }
        
        container.innerHTML = html;
        
        // Render scans using existing function
        if (scans.length > 0) {
            var resultsContainer = document.getElementById('quality-soda-results-list');
            if (resultsContainer) {
                renderSodaScans(scans, resultsContainer);
            }
        }
    } catch (e) {
        console.error('Error loading Soda results:', e);
        var container = document.getElementById('soda-results-quality-container');
        if (container) container.innerHTML = '<div class="dash-empty">Nəticələr yüklənə bilmədi</div>';
    }
}

