async function loadQualitySchedules() {
    try {
        var res = await fetch(API + '?action=quality_schedules');
        var json = await res.json();
        var schedules = json.data || [];
        var container = document.getElementById('schedules-list-container');
        
        if (!container) return;
        
        if (schedules.length === 0) {
            container.innerHTML = '<div style="background: white; border: 2px dashed #e5e7eb; border-radius: 12px; padding: 40px; text-align: center;">' +
                '<div style="font-size: 40px; margin-bottom: 12px;">⏰</div>' +
                '<div style="font-size: 16px; font-weight: 600; color: #64748b; margin-bottom: 8px;">' + t('No schedules found') + '</div>' +
                '<div style="font-size: 13px; color: #94a3b8;">' + t('Create a schedule to run quality checks automatically') + '</div>' +
            '</div>';
            return;
        }
        
        var html = '<div style="display: grid; gap: 16px;">';
        
        schedules.forEach(function(schedule) {
            var statusColor = schedule.enabled ? '#10b981' : '#94a3b8';
            var statusText = schedule.enabled ? t('Active') : t('Inactive');
            
            html += '<div style="background: white; border: 1px solid #e5e7eb; border-radius: 12px; padding: 20px;">' +
                '<div style="display: flex; justify-content: space-between; align-items: start; margin-bottom: 12px;">' +
                    '<div>' +
                        '<h4 style="margin: 0 0 4px; font-size: 15px; font-weight: 700;">' + schedule.name + '</h4>' +
                        '<div style="font-size: 12px; color: #64748b;">' +
                            '<span style="display: inline-flex; align-items: center; gap: 4px; padding: 2px 8px; background: ' + statusColor + '; color: white; border-radius: 12px; font-size: 11px; font-weight: 600; margin-right: 8px;">' + statusText + '</span>' +
                            schedule.frequency + ' @ ' + schedule.run_time +
                        '</div>' +
                    '</div>' +
                    '<div style="display: flex; gap: 6px;">' +
                        '<button onclick="runScheduleNow(' + schedule.id + ')" style="padding: 6px 12px; border-radius: 6px; font-size: 12px; cursor: pointer; border: 1px solid #e5e7eb; background: white;">▶ ' + t('Run Now') + '</button>' +
                        '<button onclick="editSchedule(' + schedule.id + ')" style="padding: 6px 12px; border-radius: 6px; font-size: 12px; cursor: pointer; border: 1px solid #e5e7eb; background: white;">✏️</button>' +
                        '<button onclick="deleteSchedule(' + schedule.id + ')" style="padding: 6px 12px; border-radius: 6px; font-size: 12px; cursor: pointer; border: 1px solid #fca5a5; background: white; color: #ef4444;">🗑️</button>' +
                    '</div>' +
                '</div>' +
                '<div style="font-size: 12px; color: #64748b;">' + t('Checks') + ': ' + (schedule.rule_ids ? (Array.isArray(schedule.rule_ids) ? schedule.rule_ids.length : JSON.parse(schedule.rule_ids || '[]').length) : 0) + '</div>' +
            '</div>';
        });
        
        html += '</div>';
        container.innerHTML = html;
        
    } catch (e) {
        console.error('Error loading schedules:', e);
        var container = document.getElementById('schedules-list-container');
        if (container) container.innerHTML = '<div class="dash-empty">' + t('Could not load schedules') + '</div>';
    }
}

async function loadQualityExecutions() {
    try {
        var res = await fetch(API + '?action=quality_executions');
        var json = await res.json();
        var executions = json.data || [];
        var container = document.getElementById('executions-list-container');
        
        if (!container) return;
        
        if (executions.length === 0) {
            container.innerHTML = '<div class="dash-empty">' + t('No executions found') + '</div>';
            return;
        }
        
        // Group executions by schedule_name
        var groupedExecutions = {};
        executions.forEach(function(exec) {
            var scheduleName = exec.schedule_name || t('Schedule') + ' #' + exec.schedule_id;
            if (!groupedExecutions[scheduleName]) {
                groupedExecutions[scheduleName] = [];
            }
            groupedExecutions[scheduleName].push(exec);
        });
        
        // Build accordion HTML
        var html = '<div class="execution-accordion">';
        
        Object.keys(groupedExecutions).forEach(function(scheduleName, index) {
            var execs = groupedExecutions[scheduleName];
            var latestExec = execs[0]; // Most recent
            
            // Calculate summary stats
            var totalPassed = execs.reduce(function(sum, e) { return sum + (e.passed_rules || 0); }, 0);
            var totalFailed = execs.reduce(function(sum, e) { return sum + (e.failed_rules || 0); }, 0);
            var completedCount = execs.filter(function(e) { return e.status === 'completed'; }).length;
            
            // Status badge for latest
            var statusColor = latestExec.status === 'completed' ? '#10b981' : latestExec.status === 'failed' ? '#ef4444' : '#f59e0b';
            var statusText = latestExec.status === 'completed' ? t('completed') : latestExec.status === 'failed' ? t('failed') : t('running');
            
            html += '<div class="exec-accordion-item" style="border: 1px solid #e5e7eb; border-radius: 12px; margin-bottom: 12px; overflow: hidden;">' +
                '<div class="exec-accordion-header" onclick="toggleExecAccordion(this)" style="padding: 16px 20px; background: #f8fafc; cursor: pointer; display: flex; justify-content: space-between; align-items: center;">' +
                    '<div style="display: flex; align-items: center; gap: 16px;">' +
                        '<span style="font-size: 18px;">📋</span>' +
                        '<div>' +
                            '<div style="font-weight: 600; font-size: 15px;">' + scheduleName + '</div>' +
                            '<div style="font-size: 12px; color: #64748b;">' + execs.length + ' ' + t('executions') + ' • ' + t('Last run') + ': ' + (latestExec.started_at || '-') + '</div>' +
                        '</div>' +
                    '</div>' +
                    '<div style="display: flex; align-items: center; gap: 16px;">' +
                        '<div style="display: flex; gap: 12px;">' +
                            '<span style="background: #d1fae5; color: #065f46; padding: 4px 10px; border-radius: 6px; font-size: 12px; font-weight: 600;">✓ ' + totalPassed + '</span>' +
                            '<span style="background: #fee2e2; color: #991b1b; padding: 4px 10px; border-radius: 6px; font-size: 12px; font-weight: 600;">✗ ' + totalFailed + '</span>' +
                        '</div>' +
                        '<span style="color: ' + statusColor + '; font-weight: 600; font-size: 13px;">' + statusText + '</span>' +
                        '<svg class="exec-accordion-arrow" style="width: 20px; height: 20px; transition: transform 0.2s;" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z"/></svg>' +
                    '</div>' +
                '</div>' +
                '<div class="exec-accordion-content" style="display: none; padding: 0;">' +
                    '<table style="width: 100%; border-collapse: collapse;">' +
                        '<thead><tr style="background: #f1f5f9;">' +
                            '<th style="padding: 10px 16px; text-align: left; font-size: 12px; font-weight: 600; color: #64748b;">' + t('Start Time') + '</th>' +
                            '<th style="padding: 10px 16px; text-align: left; font-size: 12px; font-weight: 600; color: #64748b;">' + t('Status') + '</th>' +
                            '<th style="padding: 10px 16px; text-align: center; font-size: 12px; font-weight: 600; color: #64748b;">' + t('Rules') + '</th>' +
                            '<th style="padding: 10px 16px; text-align: center; font-size: 12px; font-weight: 600; color: #64748b;">' + t('Passed') + '</th>' +
                            '<th style="padding: 10px 16px; text-align: center; font-size: 12px; font-weight: 600; color: #64748b;">' + t('Failed') + '</th>' +
                            '<th style="padding: 10px 16px; text-align: left; font-size: 12px; font-weight: 600; color: #64748b;">' + t('Note') + '</th>' +
                        '</tr></thead>' +
                        '<tbody>';
            
            execs.forEach(function(exec) {
                var execStatusColor = exec.status === 'completed' ? '#10b981' : exec.status === 'failed' ? '#ef4444' : '#f59e0b';
                var execStatusText = exec.status === 'completed' ? t('completed') : exec.status === 'failed' ? t('failed') : t('running');
                var successCount = exec.passed_rules || 0;
                var errorCount = exec.failed_rules || 0;
                var totalRules = exec.total_rules || 0;
                var successStyle = successCount > 0 ? 'color: #10b981; font-weight: 600;' : 'color: #94a3b8;';
                var errorStyle = errorCount > 0 ? 'color: #ef4444; font-weight: 600;' : 'color: #94a3b8;';
                var errorMsg = exec.error_message ? exec.error_message.substring(0, 40) + '...' : '-';
                
                html += '<tr style="border-top: 1px solid #f1f5f9;">' +
                    '<td style="padding: 12px 16px; font-size: 13px;">' + (exec.started_at || '-') + '</td>' +
                    '<td style="padding: 12px 16px;"><span style="color: ' + execStatusColor + '; font-weight: 600; font-size: 13px;">' + execStatusText + '</span></td>' +
                    '<td style="padding: 12px 16px; text-align: center; font-size: 13px;">' + totalRules + '</td>' +
                    '<td style="padding: 12px 16px; text-align: center; font-size: 13px; ' + successStyle + '">' + successCount + '</td>' +
                    '<td style="padding: 12px 16px; text-align: center; font-size: 13px; ' + errorStyle + '">' + errorCount + '</td>' +
                    '<td style="padding: 12px 16px; font-size: 11px; color: #64748b; max-width: 150px; overflow: hidden; text-overflow: ellipsis;" title="' + (exec.error_message || '') + '">' + errorMsg + '</td>' +
                '</tr>';
            });
            
            html += '</tbody></table></div></div>';
        });
        
        html += '</div>';
        container.innerHTML = html;
        
    } catch (e) {
        console.error('Error loading executions:', e);
    }
}

// Toggle execution accordion
function toggleExecAccordion(header) {
    var content = header.nextElementSibling;
    var arrow = header.querySelector('.exec-accordion-arrow');
    var isOpen = content.style.display !== 'none';
    
    if (isOpen) {
        content.style.display = 'none';
        arrow.style.transform = 'rotate(0deg)';
    } else {
        content.style.display = 'block';
        arrow.style.transform = 'rotate(180deg)';
    }
}

function showCreateScheduleModal() {
    // First load available checks
    loadChecksForSchedule();
    
    showModal(t('Create New Schedule'), `
        <form onsubmit="createQualitySchedule(event); return false;">
            <div style="display: grid; gap: 16px;">
                <div>
                    <label class="form-label">${t('Name')} *</label>
                    <input type="text" id="scheduleName" required class="form-input" placeholder="Daily Production Check">
                </div>
                <div>
                    <label class="form-label">${t('Checks')} * (${t('select at least 1')})</label>
                    <div id="scheduleChecksContainer" style="max-height: 200px; overflow-y: auto; border: 1px solid #e5e7eb; border-radius: 8px; padding: 12px; background: #f8fafc;">
                        <div style="color: #64748b; font-size: 13px;">${t('Loading checks...')}</div>
                    </div>
                    <small style="color: #64748b; font-size: 11px;">${t('These checks will run automatically when schedule executes')}</small>
                </div>
                <div>
                    <label class="form-label">${t('Frequency')} *</label>
                    <select id="scheduleFrequency" required class="form-input">
                        <option value="hourly">${t('Hourly')}</option>
                        <option value="daily" selected>${t('Daily')}</option>
                        <option value="weekly">${t('Weekly')}</option>
                        <option value="monthly">${t('Monthly')}</option>
                    </select>
                </div>
                <div>
                    <label class="form-label">${t('Time (24h format)')} *</label>
                    <input type="time" id="scheduleTime" required class="form-input" value="09:00">
                    <small style="color: #64748b; font-size: 11px;">${t('Example')}: 09:00, 14:30, 23:00</small>
                </div>
                <div>
                    <label class="form-label">${t('Email Notification')}</label>
                    <input type="email" id="scheduleEmail" class="form-input" placeholder="admin@company.az">
                </div>
            </div>
            <div style="margin-top: 20px; display: flex; gap: 12px; justify-content: flex-end;">
                <button type="button" onclick="closeModal()" class="btn-secondary">${t('Cancel')}</button>
                <button type="submit" class="btn-primary">${t('Create')}</button>
            </div>
        </form>
    `);
}

async function loadChecksForSchedule() {
    try {
        var res = await fetch(API + '?action=soda_checks');
        var json = await res.json();
        
        var container = document.getElementById('scheduleChecksContainer');
        if (!container) return;
        
        if (!json.success || !json.data || json.data.length === 0) {
            container.innerHTML = '<div style="color: #ef4444; font-size: 13px;">⚠️ ' + t('No checks found. Create a check first.') + '</div>';
            return;
        }
        
        var html = '<div style="margin-bottom: 8px;"><label style="display: flex; align-items: center; gap: 8px; cursor: pointer;"><input type="checkbox" id="selectAllChecks" onchange="toggleAllScheduleChecks(this.checked)"> <strong>' + t('Select all') + '</strong></label></div>';
        
        json.data.forEach(function(check) {
            if (check.status === 'active') {
                html += '<label style="display: flex; align-items: center; gap: 8px; padding: 6px 0; cursor: pointer; border-bottom: 1px solid #e5e7eb;">' +
                    '<input type="checkbox" class="schedule-check-item" value="' + check.id + '">' +
                    '<span style="flex: 1;">' + check.check_name + '</span>' +
                    '<span style="font-size: 11px; color: #64748b;">' + (check.table_name || '') + '</span>' +
                '</label>';
            }
        });
        
        container.innerHTML = html;
        
    } catch (e) {
        console.error('Error loading checks:', e);
        var container = document.getElementById('scheduleChecksContainer');
        if (container) {
            container.innerHTML = '<div style="color: #ef4444; font-size: 13px;">Check-lər yüklənə bilmədi</div>';
        }
    }
}

function toggleAllScheduleChecks(checked) {
    document.querySelectorAll('.schedule-check-item').forEach(function(cb) {
        cb.checked = checked;
    });
}

async function createQualitySchedule(event) {
    event.preventDefault();
    
    // Get selected check IDs
    var selectedChecks = [];
    document.querySelectorAll('.schedule-check-item:checked').forEach(function(cb) {
        selectedChecks.push(parseInt(cb.value));
    });
    
    if (selectedChecks.length === 0) {
        alert('Ən azı 1 check seçməlisiniz!');
        return;
    }
    
    var data = {
        name: document.getElementById('scheduleName').value,
        enabled: true,
        frequency: document.getElementById('scheduleFrequency').value,
        run_time: document.getElementById('scheduleTime').value,
        rule_ids: selectedChecks,
        notify_email: document.getElementById('scheduleEmail').value || null
    };
    
    console.log('Creating schedule with data:', data);
    
    try {
        var res = await fetch(API + '?action=quality_schedules', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify(data)
        });
        
        var json = await res.json();
        
        if (json.success) {
            closeModal();
            showToast('Schedule yaradıldı! ' + selectedChecks.length + ' check əlavə edildi.');
            loadQualitySchedules();
        } else {
            alert('Xəta: ' + (json.message || 'Schedule yaradıla bilmədi'));
        }
    } catch (e) {
        console.error('Error creating schedule:', e);
        alert('Schedule yaradıla bilmədi');
    }
}

async function runScheduleNow(scheduleId) {
    if (!confirm('Bu schedule-i indi işlətmək istəyirsiniz?')) return;
    
    try {
        var res = await fetch(API + '?action=run_schedule', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ schedule_id: scheduleId })
        });
        
        var json = await res.json();
        
        if (json.success) {
            showToast('Schedule işə salındı!');
            setTimeout(loadQualityExecutions, 2000);
        } else {
            alert('Xəta: ' + (json.message || 'Schedule işlədilə bilmədi'));
        }
    } catch (e) {
        console.error('Error running schedule:', e);
        alert('Schedule işlədilə bilmədi');
    }
}

async function deleteSchedule(scheduleId) {
    if (!confirm('Bu schedule-i silmək istəyirsiniz?')) return;
    
    try {
        var res = await fetch(API + '?action=quality_schedules&id=' + scheduleId, {
            method: 'DELETE'
        });
        
        var json = await res.json();
        
        if (json.success) {
            showToast('Schedule silindi');
            loadQualitySchedules();
        } else {
            alert('Xəta: ' + (json.message || 'Schedule silinə bilmədi'));
        }
    } catch (e) {
        console.error('Error deleting schedule:', e);
        alert('Schedule silinə bilmədi');
    }
}

async function editSchedule(scheduleId) {
    try {
        // Get schedule data
        var res = await fetch(API + '?action=quality_schedules&id=' + scheduleId);
        var json = await res.json();
        var schedule = json.data || json;
        
        if (!schedule || !schedule.id) {
            alert(t('Schedule not found'));
            return;
        }
        
        // Parse rule_ids
        var ruleIds = [];
        if (schedule.rule_ids) {
            ruleIds = Array.isArray(schedule.rule_ids) ? schedule.rule_ids : JSON.parse(schedule.rule_ids || '[]');
        }
        
        // Load checks for selection
        var checksRes = await fetch(API + '?action=soda_checks');
        var checksJson = await checksRes.json();
        var checks = checksJson.data || [];
        
        var checksHtml = '<div style="margin-bottom: 8px;"><label style="display: flex; align-items: center; gap: 8px; cursor: pointer;"><input type="checkbox" id="editSelectAllChecks" onchange="toggleAllScheduleChecks(this.checked)"> <strong>' + t('Select all') + '</strong></label></div>';
        
        checks.forEach(function(check) {
            if (check.status === 'active') {
                var isChecked = ruleIds.includes(check.id) || ruleIds.includes(String(check.id)) ? 'checked' : '';
                checksHtml += '<label style="display: flex; align-items: center; gap: 8px; padding: 6px 0; cursor: pointer; border-bottom: 1px solid #e5e7eb;">' +
                    '<input type="checkbox" class="schedule-check-item" value="' + check.id + '" ' + isChecked + '>' +
                    '<span style="flex: 1;">' + check.check_name + '</span>' +
                    '<span style="font-size: 11px; color: #64748b;">' + (check.table_name || '') + '</span>' +
                '</label>';
            }
        });
        
        showModal(t('Edit Schedule'), `
            <form onsubmit="updateQualitySchedule(event, ${scheduleId}); return false;">
                <div style="display: grid; gap: 16px;">
                    <div>
                        <label class="form-label">${t('Name')} *</label>
                        <input type="text" id="editScheduleName" required class="form-input" value="${schedule.name || ''}">
                    </div>
                    <div>
                        <label class="form-label">${t('Checks')} * (${t('select at least 1')})</label>
                        <div id="editScheduleChecksContainer" style="max-height: 200px; overflow-y: auto; border: 1px solid #e5e7eb; border-radius: 8px; padding: 12px; background: #f8fafc;">
                            ${checksHtml}
                        </div>
                    </div>
                    <div>
                        <label class="form-label">${t('Frequency')} *</label>
                        <select id="editScheduleFrequency" required class="form-input">
                            <option value="hourly" ${schedule.frequency === 'hourly' ? 'selected' : ''}>${t('Hourly')}</option>
                            <option value="daily" ${schedule.frequency === 'daily' ? 'selected' : ''}>${t('Daily')}</option>
                            <option value="weekly" ${schedule.frequency === 'weekly' ? 'selected' : ''}>${t('Weekly')}</option>
                            <option value="monthly" ${schedule.frequency === 'monthly' ? 'selected' : ''}>${t('Monthly')}</option>
                        </select>
                    </div>
                    <div>
                        <label class="form-label">${t('Time (24h format)')} *</label>
                        <input type="time" id="editScheduleTime" required class="form-input" value="${schedule.run_time || '09:00'}">
                    </div>
                    <div>
                        <label class="form-label">${t('Email Notification')}</label>
                        <input type="email" id="editScheduleEmail" class="form-input" value="${schedule.notify_email || ''}" placeholder="admin@company.az">
                    </div>
                    <div>
                        <label style="display: flex; align-items: center; gap: 8px; cursor: pointer;">
                            <input type="checkbox" id="editScheduleEnabled" ${schedule.enabled ? 'checked' : ''}>
                            <span>${t('Active')}</span>
                        </label>
                    </div>
                </div>
                <div style="margin-top: 20px; display: flex; gap: 12px; justify-content: flex-end;">
                    <button type="button" onclick="closeModal()" class="btn-secondary">${t('Cancel')}</button>
                    <button type="submit" class="btn-primary">${t('Save')}</button>
                </div>
            </form>
        `);
    } catch (e) {
        console.error('Error loading schedule:', e);
        alert(t('Could not load schedule'));
    }
}

async function updateQualitySchedule(event, scheduleId) {
    event.preventDefault();
    
    var name = document.getElementById('editScheduleName').value;
    var frequency = document.getElementById('editScheduleFrequency').value;
    var runTime = document.getElementById('editScheduleTime').value;
    var email = document.getElementById('editScheduleEmail').value;
    var enabled = document.getElementById('editScheduleEnabled').checked;
    
    var selectedChecks = Array.from(document.querySelectorAll('.schedule-check-item:checked')).map(function(cb) {
        return parseInt(cb.value);
    });
    
    if (selectedChecks.length === 0) {
        alert(t('Select at least one check'));
        return;
    }
    
    try {
        var res = await fetch(API + '?action=quality_schedules&id=' + scheduleId, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                name: name,
                frequency: frequency,
                run_time: runTime,
                notify_email: email,
                enabled: enabled ? 1 : 0,
                rule_ids: selectedChecks
            })
        });
        
        var json = await res.json();
        
        if (json.success) {
            closeModal();
            showToast(t('Schedule updated successfully'));
            loadQualitySchedules();
        } else {
            alert(t('Error') + ': ' + (json.message || t('Could not update schedule')));
        }
    } catch (e) {
        console.error('Error updating schedule:', e);
        alert(t('Could not update schedule'));
    }
}

// ============================================================
async function editSodaCheck(checkId) {
    try {
        var res = await fetch(API + '?action=soda_checks&id=' + checkId);
        var json = await res.json();
        var check = json.data || json;
        
        if (!check || !check.id) {
            alert('Check tapılmadı');
            return;
        }
        
        // Force reload catalog data before opening builder
        loadCatalogFromStorage(true);
        
        // Open check builder with existing data
        showSodaCheckBuilder(check);
    } catch (e) {
        console.error('Error loading check:', e);
        alert('Check yüklənə bilmədi');
    }
}

