function showTableDetailsPanel(tableName) {
    // Check if panel exists
    var existingPanel = document.getElementById('tableDetailsPanel');
    if (existingPanel) {
        existingPanel.remove();
    }
    
    // Find table data
    var table = null;
    var tableElement = document.querySelector('.flow-table[data-table="' + tableName + '"]');
    if (!tableElement) return;
    
    var layer = tableElement.dataset.layer;
    var columns = Array.from(tableElement.querySelectorAll('.flow-column')).map(function(c) {
        return c.dataset.column;
    });
    
    // Find connections
    var incomingConnections = [];
    var outgoingConnections = [];
    
    columnMappings.forEach(function(m) {
        if (m.targetTable === tableName) {
            incomingConnections.push(m);
        }
        if (m.sourceTable === tableName) {
            outgoingConnections.push(m);
        }
    });
    
    var color = getLayerColor(layer);
    
    // Create panel
    var panel = document.createElement('div');
    panel.id = 'tableDetailsPanel';
    panel.style.cssText = 'position: fixed; right: 0; top: 60px; bottom: 0; width: 400px; ' +
        'background: white; border-left: 2px solid #e5e7eb; box-shadow: -4px 0 12px rgba(0,0,0,0.1); ' +
        'z-index: 999; overflow-y: auto; padding: 24px;';
    
    var html = '<div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px;">' +
        '<h3 style="margin: 0; font-size: 18px; color: #1e293b;">📊 Cədvəl Detalları</h3>' +
        '<button onclick="closeTableDetailsPanel()" style="width: 32px; height: 32px; border: none; border-radius: 8px; background: #f1f5f9; cursor: pointer; font-size: 18px;">✕</button>' +
    '</div>';
    
    // Table info
    html += '<div style="background: ' + color.bg + '; border: 2px solid ' + color.border + '; border-radius: 12px; padding: 16px; margin-bottom: 20px;">' +
        '<div style="background: ' + color.border + '; color: white; display: inline-block; padding: 4px 12px; border-radius: 6px; font-size: 11px; font-weight: 700; margin-bottom: 8px;">' + layer + '</div>' +
        '<div style="font-size: 16px; font-weight: 700; color: #1e293b; word-break: break-all;">' + tableName + '</div>' +
    '</div>';
    
    // Columns
    html += '<div style="margin-bottom: 24px;">' +
        '<div style="font-size: 14px; font-weight: 700; color: #475569; margin-bottom: 12px;">📋 Sütunlar (' + columns.length + ')</div>' +
        '<div style="background: #f8fafc; border-radius: 8px; padding: 12px; max-height: 200px; overflow-y: auto;">';
    
    columns.forEach(function(col) {
        html += '<div style="padding: 6px 12px; font-family: monospace; font-size: 12px; color: #1e293b; border-bottom: 1px solid #e5e7eb;">' +
            '<span style="display: inline-block; width: 8px; height: 8px; border-radius: 50%; background: ' + color.border + '; margin-right: 8px;"></span>' +
            col +
        '</div>';
    });
    
    html += '</div></div>';
    
    // Incoming connections
    html += '<div style="margin-bottom: 24px;">' +
        '<div style="font-size: 14px; font-weight: 700; color: #475569; margin-bottom: 12px;">⬇️ Gələn Bağlantılar (' + incomingConnections.length + ')</div>';
    
    if (incomingConnections.length > 0) {
        html += '<div style="background: #f8fafc; border-radius: 8px; padding: 12px; max-height: 200px; overflow-y: auto;">';
        incomingConnections.forEach(function(conn) {
            var srcColor = getLayerColor(conn.sourceLayer);
            html += '<div style="padding: 10px; background: white; border-radius: 6px; margin-bottom: 8px; border-left: 3px solid ' + srcColor.border + ';">' +
                '<div style="font-size: 11px; color: #64748b; margin-bottom: 4px;">' + srcColor.icon + ' ' + conn.sourceLayer + '</div>' +
                '<div style="font-size: 13px; font-weight: 600; color: #1e293b; margin-bottom: 6px;">' + conn.sourceTable + '</div>' +
                '<div style="font-size: 11px; font-family: monospace; color: #64748b;">' + conn.sourceColumn + ' → ' + conn.targetColumn + '</div>' +
                (conn.transformation && conn.transformation !== 'Direct Copy' ? 
                    '<div style="font-size: 10px; color: #f59e0b; margin-top: 4px;">🔄 ' + conn.transformation + '</div>' : '') +
            '</div>';
        });
        html += '</div>';
    } else {
        html += '<div style="text-align: center; padding: 20px; color: #94a3b8; font-size: 13px;">Gələn bağlantı yoxdur</div>';
    }
    
    html += '</div>';
    
    // Outgoing connections
    html += '<div>' +
        '<div style="font-size: 14px; font-weight: 700; color: #475569; margin-bottom: 12px;">⬆️ Gedən Bağlantılar (' + outgoingConnections.length + ')</div>';
    
    if (outgoingConnections.length > 0) {
        html += '<div style="background: #f8fafc; border-radius: 8px; padding: 12px; max-height: 200px; overflow-y: auto;">';
        outgoingConnections.forEach(function(conn) {
            var tgtColor = getLayerColor(conn.targetLayer);
            html += '<div style="padding: 10px; background: white; border-radius: 6px; margin-bottom: 8px; border-left: 3px solid ' + tgtColor.border + ';">' +
                '<div style="font-size: 11px; color: #64748b; margin-bottom: 4px;">' + tgtColor.icon + ' ' + conn.targetLayer + '</div>' +
                '<div style="font-size: 13px; font-weight: 600; color: #1e293b; margin-bottom: 6px;">' + conn.targetTable + '</div>' +
                '<div style="font-size: 11px; font-family: monospace; color: #64748b;">' + conn.sourceColumn + ' → ' + conn.targetColumn + '</div>' +
                (conn.transformation && conn.transformation !== 'Direct Copy' ? 
                    '<div style="font-size: 10px; color: #f59e0b; margin-top: 4px;">🔄 ' + conn.transformation + '</div>' : '') +
            '</div>';
        });
        html += '</div>';
    } else {
        html += '<div style="text-align: center; padding: 20px; color: #94a3b8; font-size: 13px;">Gedən bağlantı yoxdur</div>';
    }
    
    html += '</div>';
    
    panel.innerHTML = html;
    document.body.appendChild(panel);
}

