function askAI(question) {
    var input = document.getElementById('aiInput');
    if (input) {
        input.value = question;
        sendAIMessage();
    }
}

function sendAIMessage() {
    var input = document.getElementById('aiInput');
    var message = input.value.trim();
    if (!message) return;
    
    addAIMessage(message, 'user');
    input.value = '';
    
    showTypingIndicator();
    
    setTimeout(function() {
        hideTypingIndicator();
        var response = generateAIResponse(message);
        addAIMessage(response, 'assistant');
    }, 1500);
}

function addAIMessage(message, type) {
    var container = document.getElementById('aiChatContainer');
    if (!container) return;
    
    var div = document.createElement('div');
    div.className = 'ai-message ai-message-' + type;
    
    if (type === 'assistant') {
        div.innerHTML = '<div class="ai-avatar">🤖</div><div class="ai-message-content">' + formatAIResponse(message) + '</div>';
    } else {
        div.innerHTML = '<div class="ai-message-content">' + message + '</div><div class="ai-avatar">👤</div>';
    }
    
    container.appendChild(div);
    container.scrollTop = container.scrollHeight;
}

function showTypingIndicator() {
    var container = document.getElementById('aiChatContainer');
    if (!container) return;
    
    var typing = document.createElement('div');
    typing.className = 'ai-typing-indicator';
    typing.id = 'typingIndicator';
    typing.innerHTML = '<div class="ai-avatar">🤖</div><div class="typing-dots"><span></span><span></span><span></span></div>';
    container.appendChild(typing);
    container.scrollTop = container.scrollHeight;
}

function hideTypingIndicator() {
    var typing = document.getElementById('typingIndicator');
    if (typing) typing.remove();
}

function formatAIResponse(text) {
    text = text.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
    text = text.replace(/\n/g, '<br>');
    return text;
}

function generateAIResponse(question) {
    var q = question.toLowerCase();
    loadMappingsFromStorage();
    
    if (q.includes('mapping') || q.includes('column')) {
        if (columnMappings.length === 0) {
            return '**Column Mappings:**\n\nHazırda heç bir mapping yoxdur.\n\nColumn Mapper-ə keçib yeni mapping yarada bilərsiniz.';
        }
        var list = '';
        columnMappings.forEach(function(m) {
            list += '\n• **' + m.sourceColumn + '** → **' + m.targetColumn + '** (' + m.transformation + ')';
        });
        return '**Column Mappings (' + columnMappings.length + '):**' + list + '\n\nLineage-ə keçib qrafik görüntüsünü görə bilərsiniz.';
    }
    
    if (q.includes('table') || q.includes('cədvəl')) {
        return '**Verilənlər bazasında 6 cədvəl var:**\n\n📊 **customers** - 150K rows\n📊 **orders** - 2.3M rows\n📊 **products** - 5K rows\n📊 **order_items** - 8.1M rows\n📊 **payments** - 2.2M rows\n📊 **shipments** - 1.8M rows';
    }
    
    if (q.includes('quality') || q.includes('keyfiyyət')) {
        return '**Data Quality Summary:**\n\n✅ **Healthy:** 4 tables\n⚠️ **Warning:** 1 table (orders)\n❌ **Critical:** 1 table (payments)\n\n**Top Issues:**\n1. payments.transaction_id - duplicates\n2. orders.customer_email - null values';
    }
    
    if (q.includes('lineage')) {
        return '**Data Lineage:**\n\n' + columnMappings.length + ' column mapping mövcuddur.\n\nLineage səhifəsinə keçib Mermaid diagramını görə bilərsiniz.';
    }
    
    return '**"' + question + '"** sualınızı başa düşdüm.\n\nMən aşağıdakılarda kömək edə bilərəm:\n• 📊 Data Catalog\n• 🔗 Lineage\n• ✅ Quality\n• ⚡ Column Mappings';
}

// ============================================================
// HELPERS
// ============================================================

function setActive(page) {
    var items = document.querySelectorAll('.menu-item');
    items.forEach(function(item) {
        if (item.dataset.page === page) {
            item.classList.add('active');
        } else {
            item.classList.remove('active');
        }
    });
    
    // Cleanup: remove lineage minimap when leaving lineage page
    if (page !== 'lineage') {
        removeLineageMinimap();
    }
}

function render(title, content) {
    document.getElementById('main').innerHTML = content;
}

// ============================================================
// API CALLS
// ============================================================

async function fetchStats() {
    try {
        var res = await fetch(API + '?action=stats');
        var json = await res.json();
        if (json.success && json.data) {
            document.getElementById('stat-glossary').textContent = json.data.glossary || 0;
            document.getElementById('stat-catalog').textContent = json.data.catalog || 0;
            document.getElementById('stat-reports').textContent = json.data.reports || 0;
            document.getElementById('stat-quality').textContent = json.data.quality || 0;
        }
    } catch (e) {
        console.log('Stats error:', e);
    }
    
    // Show mappings count
    loadMappingsFromStorage();
    var mappingsEl = document.getElementById('stat-mappings');
    if (mappingsEl) mappingsEl.textContent = columnMappings.length;
}

async function fetchGlossary(search) {
    try {
        var res = await fetch(API + '?action=glossary&search=' + encodeURIComponent(search));
        var json = await res.json();
        if (json.success) {
            var html = '';
            json.data.forEach(function(item) {
                html += '<tr><td><strong>' + item.term + '</strong></td><td><span class="badge badge-info">' + item.domain + '</span></td><td>' + item.definition + '</td><td>' + item.owner + '</td></tr>';
            });
            document.getElementById('tbody').innerHTML = html || '<tr><td colspan="4">Nəticə yoxdur</td></tr>';
        }
    } catch (e) {
        document.getElementById('tbody').innerHTML = '<tr><td colspan="4">Məlumat yüklənə bilmədi</td></tr>';
    }
}

function searchGlossary(val) {
    fetchGlossary(val);
}

async function fetchCatalog(search) {
    try {
        var res = await fetch(API + '?action=catalog&search=' + encodeURIComponent(search));
        var json = await res.json();
        if (json.success) {
            var html = '';
            json.data.forEach(function(item) {
                html += '<tr><td><strong>📊 ' + item.table_name + '</strong></td><td><span class="badge badge-purple">' + item.schema_name + '</span></td><td>' + item.source_system + '</td><td>' + item.owner + '</td><td>' + (item.row_count || '-') + '</td></tr>';
            });
            document.getElementById('tbody').innerHTML = html || '<tr><td colspan="5">Nəticə yoxdur</td></tr>';
        }
    } catch (e) {
        document.getElementById('tbody').innerHTML = '<tr><td colspan="5">Məlumat yüklənə bilmədi</td></tr>';
    }
}

async function fetchReports(search) {
    try {
        var res = await fetch(API + '?action=reports&search=' + encodeURIComponent(search));
        var json = await res.json();
        if (json.success) {
            var html = '';
            json.data.forEach(function(item, idx) {
                var badge = item.report_type === 'Dashboard' ? 'badge-success' : 'badge-info';
                html += '<tr data-report-id="' + (item.id || idx) + '">' +
                    '<td><strong>📈 ' + item.report_name + '</strong></td>' +
                    '<td><span class="badge ' + badge + '">' + item.report_type + '</span></td>' +
                    '<td>' + item.department + '</td>' +
                    '<td>' + item.owner + '</td>' +
                    '<td>' + item.user_count + '</td>' +
                    '<td><button onclick="copyElementLink(\'/reports/report/' + (item.id || idx) + '\')" style="background: none; border: none; cursor: pointer; opacity: 0.5;" title="Linki kopyala" onmouseover="this.style.opacity=1" onmouseout="this.style.opacity=0.5">🔗</button></td>' +
                '</tr>';
            });
            document.getElementById('tbody').innerHTML = html || '<tr><td colspan="6">Nəticə yoxdur</td></tr>';
        }
    } catch (e) {
        document.getElementById('tbody').innerHTML = '<tr><td colspan="6">Məlumat yüklənə bilmədi</td></tr>';
    }
}

function searchReports(val) {
    fetchReports(val);
}

async function fetchQuality() {
    try {
        var res = await fetch(API + '?action=quality');
        var json = await res.json();
        if (json.success) {
            var html = '';
            json.data.forEach(function(item) {
                var badge = 'badge-success';
                if (item.severity === 'Critical') badge = 'badge-danger';
                else if (item.severity === 'Warning') badge = 'badge-warning';
                
                var status = item.status === 'Open' ? 'badge-danger' : 'badge-success';
                
                html += '<tr><td><strong>' + item.rule_code + '</strong></td><td>' + item.rule_name + '</td><td><span class="badge ' + badge + '">' + item.severity + '</span></td><td>' + item.table_name + '</td><td><span class="badge ' + status + '">' + item.status + '</span></td></tr>';
            });
            document.getElementById('tbody').innerHTML = html || '<tr><td colspan="5">Problem yoxdur</td></tr>';
        }
    } catch (e) {
        document.getElementById('tbody').innerHTML = '<tr><td colspan="5">Məlumat yüklənə bilmədi</td></tr>';
    }
}

function fetchLineage() {
    var container = document.getElementById('lineageGraph');
    if (!container) return;
    
    // Use columnMappings data to build lineage
    loadMappingsFromStorage();
    
    if (columnMappings.length === 0) {
        container.innerHTML = '<div style="text-align: center; padding: 60px 20px; color: #94a3b8;">' +
            '<div style="font-size: 48px; margin-bottom: 16px;">🔗</div>' +
            '<p style="font-size: 16px; font-weight: 600; color: #64748b;">Heç bir mapping yoxdur</p>' +
            '<p style="font-size: 14px; color: #94a3b8; margin: 12px 0;">Sütun Əlaqələndirici ilə mapping yaradın</p>' +
            '<button onclick="loadColumnMapper()" style="padding: 12px 24px; background: #3b82f6; color: white; border: none; border-radius: 8px; cursor: pointer; font-weight: 600;">⚡ Sütun Əlaqələndirici</button>' +
        '</div>';
        return;
    }
    
    // Build table-level lineage from mappings
    var tableLinks = {};
    columnMappings.forEach(function(m) {
        var sourceKey = m.sourceLayer + '.' + m.sourceTable;
        var targetKey = m.targetLayer + '.' + m.targetTable;
        var linkKey = sourceKey + '->' + targetKey;
        
        if (!tableLinks[linkKey]) {
            tableLinks[linkKey] = {
                source: { layer: m.sourceLayer, table: m.sourceTable },
                target: { layer: m.targetLayer, table: m.targetTable },
                columns: []
            };
        }
        tableLinks[linkKey].columns.push({
            source: m.sourceColumn,
            target: m.targetColumn,
            transform: m.transformation
        });
    });
    
    // Create visual flow
    var html = '<style>' +
        '.tl-flow { display: flex; flex-direction: column; gap: 20px; }' +
        '.tl-link { display: flex; align-items: center; gap: 16px; padding: 16px; background: white; border-radius: 12px; border: 1px solid #e5e7eb; }' +
        '.tl-node { padding: 12px 20px; border-radius: 10px; min-width: 180px; }' +
        '.tl-node-source { background: #dbeafe; border: 2px solid #3b82f6; }' +
        '.tl-node-target { background: #d1fae5; border: 2px solid #10b981; }' +
        '.tl-node-layer { font-size: 10px; font-weight: 700; text-transform: uppercase; color: #64748b; margin-bottom: 4px; }' +
        '.tl-node-table { font-size: 14px; font-weight: 600; color: #1e293b; display: flex; align-items: center; gap: 6px; }' +
        '.tl-arrow { font-size: 24px; color: #f59e0b; }' +
        '.tl-columns { font-size: 11px; color: #64748b; background: #f8fafc; padding: 8px 12px; border-radius: 6px; flex: 1; }' +
        '.tl-columns-count { font-weight: 600; color: #3b82f6; }' +
    '</style>';
    
    html += '<div class="tl-flow">';
    
    Object.values(tableLinks).forEach(function(link) {
        var sourceColor = getLayerColor(link.source.layer);
        var targetColor = getLayerColor(link.target.layer);
        
        html += '<div class="tl-link">' +
            '<div class="tl-node tl-node-source" style="background: ' + sourceColor.bg + '; border-color: ' + sourceColor.border + ';">' +
                '<div class="tl-node-layer">' + sourceColor.icon + ' ' + link.source.layer + '</div>' +
                '<div class="tl-node-table">📊 ' + link.source.table + '</div>' +
            '</div>' +
            '<div class="tl-arrow">➜</div>' +
            '<div class="tl-columns">' +
                '<span class="tl-columns-count">' + link.columns.length + '</span> sütun bağlantısı' +
                '<div style="margin-top: 6px; font-size: 10px;">';
        
        link.columns.slice(0, 3).forEach(function(col) {
            html += '<div>' + col.source + ' → ' + col.target + '</div>';
        });
        if (link.columns.length > 3) {
            html += '<div style="color: #94a3b8;">+' + (link.columns.length - 3) + ' daha...</div>';
        }
        
        html += '</div></div>' +
            '<div class="tl-arrow">➜</div>' +
            '<div class="tl-node tl-node-target" style="background: ' + targetColor.bg + '; border-color: ' + targetColor.border + ';">' +
                '<div class="tl-node-layer">' + targetColor.icon + ' ' + link.target.layer + '</div>' +
                '<div class="tl-node-table">📊 ' + link.target.table + '</div>' +
            '</div>' +
        '</div>';
    });
    
    html += '</div>';
    container.innerHTML = html;
}

