function toggleLDAP(enabled) {
    localStorage.setItem('ldapEnabled', enabled ? 'true' : 'false');
    showToast(enabled ? 'LDAP aktivləşdirildi' : 'LDAP deaktivləşdirildi', 'success');
    loadSettings();
}

function saveLDAPSettings() {
    var url = document.getElementById('ldapUrl').value.trim();
    var baseDn = document.getElementById('ldapBaseDn').value.trim();
    var bindDn = document.getElementById('ldapBindDn').value.trim();
    var bindPassword = document.getElementById('ldapBindPassword').value;
    var usersDn = document.getElementById('ldapUsersDn').value.trim();
    var userFilter = document.getElementById('ldapUserFilter').value.trim() || '(objectClass=person)';

    if (!url || !baseDn || !bindDn || !bindPassword || !usersDn) {
        showToast('Bütün məcburi sahələri (*) doldurun', 'error');
        return;
    }

    localStorage.setItem('ldapUrl', url);
    localStorage.setItem('ldapBaseDn', baseDn);
    localStorage.setItem('ldapBindDn', bindDn);
    localStorage.setItem('ldapBindPassword', bindPassword);
    localStorage.setItem('ldapUsersDn', usersDn);
    localStorage.setItem('ldapUserFilter', userFilter);

    var defaultRole = document.getElementById('ldapDefaultRole').value;
    localStorage.setItem('ldapDefaultRole', defaultRole);

    showToast('LDAP parametrləri yadda saxlanıldı', 'success');
}

async function testLDAPConnection() {
    var url = document.getElementById('ldapUrl').value.trim();
    var baseDn = document.getElementById('ldapBaseDn').value.trim();
    var bindDn = document.getElementById('ldapBindDn').value.trim();
    var bindPassword = document.getElementById('ldapBindPassword').value;

    if (!url || !baseDn || !bindDn || !bindPassword) {
        showToast('LDAP URL, Base DN, Bind DN və Password daxil edin', 'error');
        return;
    }

    var resultDiv = document.getElementById('ldapTestResult');
    resultDiv.style.display = 'block';
    resultDiv.style.background = '#eff6ff';
    resultDiv.style.color = '#1e40af';
    resultDiv.innerHTML = '⏳ LDAP bağlantısı yoxlanılır...';

    try {
        var response = await fetch(API + '?action=ldap/test', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                url: url,
                base_dn: baseDn,
                bind_dn: bindDn,
                bind_password: bindPassword
            })
        });

        var result = await response.json();

        if (result.success) {
            resultDiv.style.background = '#f0fdf4';
            resultDiv.style.color = '#166534';
            resultDiv.innerHTML = '✅ <strong>Bağlantı uğurlu!</strong> ' + (result.data.message || 'LDAP serverə qoşuldu.');
            showToast('LDAP bağlantısı uğurlu!', 'success');
        } else {
            resultDiv.style.background = '#fef2f2';
            resultDiv.style.color = '#dc2626';
            resultDiv.innerHTML = '❌ <strong>Bağlantı uğursuz:</strong> ' + (result.error || 'Naməlum xəta');
            showToast('LDAP bağlantısı uğursuz', 'error');
        }
    } catch (e) {
        console.error('LDAP test error:', e);
        resultDiv.style.background = '#fef2f2';
        resultDiv.style.color = '#dc2626';
        resultDiv.innerHTML = '❌ <strong>Xəta:</strong> Server cavab vermir. Backend-də LDAP dəstəyi aktiv olmalıdır.';
        showToast('LDAP test xətası', 'error');
    }
}

async function syncLDAPUsers() {
    var ldapUrl = localStorage.getItem('ldapUrl');
    var ldapBaseDn = localStorage.getItem('ldapBaseDn');
    var ldapBindDn = localStorage.getItem('ldapBindDn');
    var ldapBindPassword = localStorage.getItem('ldapBindPassword');
    var ldapUsersDn = localStorage.getItem('ldapUsersDn');
    var ldapUserFilter = localStorage.getItem('ldapUserFilter') || '(objectClass=person)';

    if (!ldapUrl || !ldapBaseDn || !ldapBindDn || !ldapBindPassword || !ldapUsersDn) {
        showToast('Əvvəlcə LDAP parametrlərini yadda saxlayın', 'error');
        return;
    }

    // Get Keycloak settings
    var keycloakUrl = localStorage.getItem('ssoUrl') || KEYCLOAK_CONFIG.url;
    var keycloakRealm = localStorage.getItem('ssoRealm') || KEYCLOAK_CONFIG.realm;

    if (!confirm('LDAP istifadəçilərini Keycloak-a sync etmək istəyirsiniz?\n\nKeycloak: ' + keycloakUrl + '\nRealm: ' + keycloakRealm)) {
        return;
    }

    showToast('İstifadəçilər sync olunur...', 'info');

    try {
        var response = await fetch(API + '?action=ldap/sync', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                ldap_url: ldapUrl,
                ldap_base_dn: ldapBaseDn,
                ldap_bind_dn: ldapBindDn,
                ldap_bind_password: ldapBindPassword,
                ldap_users_dn: ldapUsersDn,
                ldap_user_filter: ldapUserFilter,
                keycloak_url: keycloakUrl,
                keycloak_realm: keycloakRealm
            })
        });

        var result = await response.json();

        if (result.success) {
            showToast('Sync tamamlandı! ' + (result.data.synced || 0) + ' istifadəçi import olundu.', 'success');
        } else {
            showToast('Sync xətası: ' + (result.error || 'Naməlum xəta'), 'error');
        }
    } catch (e) {
        console.error('LDAP sync error:', e);
        showToast('Sync xətası baş verdi', 'error');
    }
}

async function fetchLDAPUsers() {
    var url = document.getElementById('ldapUrl').value.trim();
    var baseDn = document.getElementById('ldapBaseDn').value.trim();
    var bindDn = document.getElementById('ldapBindDn').value.trim();
    var bindPassword = document.getElementById('ldapBindPassword').value;
    var usersDn = document.getElementById('ldapUsersDn').value.trim();
    var userFilter = document.getElementById('ldapUserFilter').value.trim() || '(objectClass=person)';
    var defaultRole = document.getElementById('ldapDefaultRole').value || 'viewer';

    if (!url || !baseDn || !bindDn || !bindPassword || !usersDn) {
        showToast('Bütün LDAP parametrlərini doldurun', 'error');
        return;
    }

    var container = document.getElementById('ldapUsersContainer');
    container.style.display = 'block';
    container.innerHTML = '<div style="text-align: center; padding: 30px; color: #64748b;"><div style="font-size: 24px; margin-bottom: 10px;">⏳</div>İstifadəçilər yüklənir və sistemə əlavə edilir...</div>';

    try {
        var response = await fetch(API + '?action=ldap/users', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                url: url,
                base_dn: baseDn,
                bind_dn: bindDn,
                bind_password: bindPassword,
                users_dn: usersDn,
                user_filter: userFilter,
                default_role: defaultRole
            })
        });

        var result = await response.json();

        if (result.success && result.data.users) {
            var users = result.data.users;
            var inserted = result.data.inserted || 0;
            var updated = result.data.updated || 0;
            var defaultRoleUsed = result.data.default_role || 'viewer';

            var summaryHtml = '<div style="background: #ecfdf5; border: 1px solid #a7f3d0; padding: 12px 16px; border-radius: 8px; margin-bottom: 12px;">' +
                '<div style="font-weight: 600; color: #059669; margin-bottom: 6px;">✅ Sync tamamlandı</div>' +
                '<div style="font-size: 13px; color: #047857;">' +
                    '📥 <strong>' + inserted + '</strong> yeni istifadəçi əlavə edildi (' + defaultRoleUsed + ' rolu ilə)<br>' +
                    '🔄 <strong>' + updated + '</strong> istifadəçi yeniləndi' +
                '</div>' +
            '</div>';

            var html = '<div style="margin-top: 16px; border: 1px solid #e5e7eb; border-radius: 10px; overflow: hidden;">' +
                '<div style="background: #f8fafc; padding: 12px 16px; border-bottom: 1px solid #e5e7eb; display: flex; justify-content: space-between; align-items: center;">' +
                    '<span style="font-weight: 600; color: #1e293b;">👥 LDAP İstifadəçiləri (' + users.length + ' nəfər)</span>' +
                    '<button onclick="document.getElementById(\'ldapUsersContainer\').style.display=\'none\'" style="background: none; border: none; font-size: 18px; cursor: pointer; color: #64748b;">✕</button>' +
                '</div>' +
                '<div style="padding: 12px;">' + summaryHtml + '</div>' +
                '<div style="max-height: 400px; overflow-y: auto;">' +
                '<table style="width: 100%; border-collapse: collapse;">' +
                    '<thead style="background: #f1f5f9; position: sticky; top: 0;">' +
                        '<tr>' +
                            '<th style="padding: 10px 12px; text-align: left; font-size: 12px; font-weight: 600; color: #475569;">İstifadəçi adı</th>' +
                            '<th style="padding: 10px 12px; text-align: left; font-size: 12px; font-weight: 600; color: #475569;">Ad Soyad</th>' +
                            '<th style="padding: 10px 12px; text-align: left; font-size: 12px; font-weight: 600; color: #475569;">Email</th>' +
                            '<th style="padding: 10px 12px; text-align: left; font-size: 12px; font-weight: 600; color: #475569;">Status</th>' +
                        '</tr>' +
                    '</thead>' +
                    '<tbody>';

            users.forEach(function(user, idx) {
                var bgColor = idx % 2 === 0 ? '#ffffff' : '#f8fafc';
                var statusBadge = '';
                if (user.status === 'inserted') {
                    statusBadge = '<span style="background: #dcfce7; color: #16a34a; padding: 3px 8px; border-radius: 12px; font-size: 11px; font-weight: 500;">✅ Yeni</span>';
                } else if (user.status === 'updated') {
                    statusBadge = '<span style="background: #dbeafe; color: #2563eb; padding: 3px 8px; border-radius: 12px; font-size: 11px; font-weight: 500;">🔄 Yeniləndi</span>';
                } else {
                    statusBadge = '<span style="background: #f1f5f9; color: #64748b; padding: 3px 8px; border-radius: 12px; font-size: 11px; font-weight: 500;">⏭️ Keçildi</span>';
                }

                html += '<tr style="background: ' + bgColor + '; border-bottom: 1px solid #f1f5f9;">' +
                    '<td style="padding: 10px 12px; font-size: 13px;">' +
                        '<span style="display: inline-flex; align-items: center; gap: 8px;">' +
                            '<span style="width: 32px; height: 32px; background: linear-gradient(135deg, #8b5cf6, #6366f1); color: white; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 600;">' +
                                (user.username ? user.username.charAt(0).toUpperCase() : '?') +
                            '</span>' +
                            '<strong>' + (user.username || '-') + '</strong>' +
                        '</span>' +
                    '</td>' +
                    '<td style="padding: 10px 12px; font-size: 13px; color: #475569;">' + (user.full_name || '-') + '</td>' +
                    '<td style="padding: 10px 12px; font-size: 13px; color: #475569;">' + (user.email || '-') + '</td>' +
                    '<td style="padding: 10px 12px; font-size: 13px;">' + statusBadge + '</td>' +
                '</tr>';
            });

            html += '</tbody></table></div></div>';
            container.innerHTML = html;
            showToast(inserted + ' yeni istifadəçi əlavə edildi, ' + updated + ' yeniləndi', 'success');
        } else {
            container.innerHTML = '<div style="background: #fef2f2; color: #dc2626; padding: 16px; border-radius: 8px; margin-top: 16px;">❌ ' + (result.error || 'İstifadəçi tapılmadı') + '</div>';
            showToast('İstifadəçilər yüklənə bilmədi', 'error');
        }
    } catch (e) {
        console.error('LDAP users fetch error:', e);
        container.innerHTML = '<div style="background: #fef2f2; color: #dc2626; padding: 16px; border-radius: 8px; margin-top: 16px;">❌ Xəta: Backend LDAP dəstəyi aktiv deyil</div>';
        showToast('LDAP xətası', 'error');
    }
}

