function exportSingleData(key) {
    var data = null;
    if (key === 'businessGlossary') {
        data = JSON.stringify({ terms: glossaryData.terms || [] });
    } else if (key === 'columnMappings') {
        data = JSON.stringify(columnMappings || []);
    } else if (key === 'governanceData') {
        data = JSON.stringify(governanceData || {});
    } else {
        showToast('❌ ' + t('No data available'));
        return;
    }
    
    var blob = new Blob([data], { type: 'application/json' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = key + '_' + new Date().toISOString().split('T')[0] + '.json';
    a.click();
    URL.revokeObjectURL(url);
    
    showToast('✅ ' + key + ' ' + t('exported'));
}

function importAllData(event) {
    var file = event.target.files[0];
    if (!file) return;
    
    showToast('⚠️ ' + t('Import not supported - data is stored in MySQL'));
    event.target.value = '';
}

function previewStorage(key) {
    var data = null;
    var preview = document.getElementById('dataPreview');
    
    // Get data from memory (loaded from MySQL)
    if (key === 'businessGlossary') {
        data = JSON.stringify({ terms: glossaryData.terms || [] }, null, 2);
    } else if (key === 'columnMappings') {
        data = JSON.stringify(columnMappings || [], null, 2);
    } else if (key === 'governanceData') {
        data = JSON.stringify(governanceData || {}, null, 2);
    }
    
    if (!data) {
        preview.innerHTML = '<span style="color: #94a3b8;">' + t('No data available') + '</span>';
        return;
    }
    
    // Syntax highlighting
    var formatted = data.replace(/"([^"]+)":/g, '<span class="data-key">"$1"</span>:');
    preview.innerHTML = formatted;
}

function clearSingleStorage(key) {
    showToast('⚠️ ' + t('Data is stored in MySQL - use SQL commands to clear'));
}

function clearAllStorage() {
    showToast('⚠️ ' + t('Data is stored in MySQL - use SQL commands to clear'));
}

