function loadAdminHub() {
    setActive('admin');
    navigateTo('/admin', true);

    var canUsers    = hasAnyPermission('users');
    var canRoles    = hasAnyPermission('roles');
    var canAudit    = hasAnyPermission('audit');
    var canSettings = hasAnyPermission('settings');

    var cards = [];
    if (canUsers)    cards.push({ title: 'Users',          icon: '👥', desc: 'İstifadəçi idarəetməsi',     fn: 'loadUserManagement()' });
    if (canRoles)    cards.push({ title: 'Roles',          icon: '🔐', desc: 'Rol və icazə idarəetməsi',   fn: 'loadRoleManagement()' });
    if (canAudit)    cards.push({ title: 'Audit Jurnalı',  icon: '📋', desc: 'Sistemdəki dəyişiklik tarixi', fn: 'loadAuditLog()' });
    if (canSettings) cards.push({ title: 'Parametrlər',    icon: '⚙️', desc: 'Sistem konfiqurasiyası',     fn: 'loadSettings()' });
    cards.push({ title: 'Scanner Status', icon: '📡', desc: 'Scanner-i yoxla / restart et', fn: 'loadScannerStatusPage()' });

    var html = '<div style="padding:32px;max-width:1100px;margin:0 auto;">' +
        '<div style="display:flex;align-items:center;gap:14px;margin-bottom:8px;">' +
            '<span style="font-size:32px;">🛠️</span>' +
            '<h1 style="margin:0;font-size:26px;color:#1e293b;">Admin Panel</h1>' +
        '</div>' +
        '<p style="color:#64748b;margin:0 0 28px;font-size:14px;">' +
            'Bu səhifə yalnız birbaşa link ilə (<code>#/admin</code>) açılır — yan menyuda gizlədilib.' +
        '</p>';

    if (cards.length === 0) {
        html += '<div style="background:#fef2f2;border:1px solid #fecaca;border-radius:10px;padding:20px;color:#991b1b;">İcazəniz yoxdur — admin alt-bölmələrinə daxil ola bilməzsiniz.</div>';
    } else {
        html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:16px;">';
        cards.forEach(function(c) {
            html += '<div onclick="' + c.fn + '" ' +
                'style="background:white;border:1px solid #e5e7eb;border-radius:12px;padding:20px;cursor:pointer;transition:transform 0.15s,box-shadow 0.15s;" ' +
                'onmouseover="this.style.transform=\'translateY(-2px)\';this.style.boxShadow=\'0 8px 24px rgba(0,0,0,0.08)\'" ' +
                'onmouseout="this.style.transform=\'\';this.style.boxShadow=\'\'">' +
                '<div style="font-size:36px;margin-bottom:10px;">' + c.icon + '</div>' +
                '<div style="font-weight:600;font-size:16px;color:#1e293b;margin-bottom:4px;">' + c.title + '</div>' +
                '<div style="color:#64748b;font-size:13px;line-height:1.5;">' + c.desc + '</div>' +
            '</div>';
        });
        html += '</div>';
    }

    html += '</div>';

    render('Admin Panel', html);
}

