// ============================================================
// URL ROUTING SYSTEM - Deep Links for every element
// ============================================================

function navigateTo(path, updateUrl = true) {
    if (updateUrl) {
        window.location.hash = path;
    }
}

function getCurrentRoute() {
    var hash = window.location.hash || '#/dashboard';
    return hash.replace('#', '');
}

function parseRoute(route) {
    var parts = route.split('/').filter(function(p) { return p !== ''; });
    return {
        module: parts[0] || 'dashboard',
        action: parts[1] || null,
        id: parts[2] || null,
        subId: parts[3] || null
    };
}

function handleRoute() {
    var route = parseRoute(getCurrentRoute());
    console.log('Routing to:', route);
    
    switch(route.module) {
        case 'dashboard':
            loadDashboard();
            break;
        case 'glossary':
            if (route.action === 'term' && route.id) {
                loadTermDetail(route.id);
            } else if (route.action === 'domain' && route.id) {
                loadDomainDetail(decodeURIComponent(route.id));
            } else if (route.action === 'stakeholder' && route.id) {
                loadStakeholderDetail(route.id);
            } else {
                loadGlossary();
            }
            break;
        case 'catalog':
            if (route.action === 'table' && route.id && route.subId) {
                loadTableDetail(route.id, route.subId);
            } else if (route.action === 'layer' && route.id) {
                loadLayerDetail(route.id);
            } else {
                loadCatalog();
            }
            break;
        case 'reports':
            if (route.action === 'report' && route.id) {
                loadReportDetail(route.id);
            } else {
                loadReports();
            }
            break;
        case 'quality':
            if (route.action === 'rule' && route.id) {
                loadQualityRuleDetail(route.id);
            } else {
                loadQuality();
            }
            break;
        case 'lineage':
            if (route.action === 'table' && route.id) {
                loadLineageTableDetail(route.id);
            } else {
                loadLineage();
            }
            break;
        case 'mapper':
            if (route.action === 'mapping' && route.id) {
                loadMappingDetail(route.id);
            } else {
                loadColumnMapper();
            }
            break;
        case 'governance':
            loadGovernance();
            break;
        case 'ai':
            loadAIAssistant();
            break;
        case 'admin':
            if (route.action === 'scanner') {
                loadScannerStatusPage();
            } else {
                loadAdminHub();
            }
            break;
        case 'sql':
            loadSqlConsole();
            break;
        case 'users':
            loadUserManagement();
            break;
        case 'roles':
            loadRoleManagement();
            break;
        case 'audit':
            loadAuditLog();
            break;
        case 'settings':
            loadSettings();
            break;
        case 'external':
            loadExternalSources();
            break;
        default:
            loadDashboard();
    }
}

// Deep link helper functions
function highlightGlossaryTerm(termId) {
    var row = document.querySelector('tr[data-term-id="' + termId + '"]');
    if (row) {
        row.style.background = '#fef3c7';
        row.scrollIntoView({ behavior: 'smooth', block: 'center' });
        setTimeout(function() { row.style.background = ''; }, 3000);
    }
}

function expandCatalogLayer(layerName) {
    var layer = document.querySelector('.catalog-layer[data-layer="' + layerName + '"]');
    if (layer) {
        layer.scrollIntoView({ behavior: 'smooth', block: 'start' });
        var header = layer.querySelector('.layer-header');
        if (header) header.click();
    }
}

function expandCatalogTable(layerName, tableName) {
    expandCatalogLayer(layerName);
    setTimeout(function() {
        var table = document.querySelector('.catalog-table[data-table="' + tableName + '"]');
        if (table) {
            table.style.background = '#fef3c7';
            table.scrollIntoView({ behavior: 'smooth', block: 'center' });
            var header = table.querySelector('.table-header');
            if (header) header.click();
            setTimeout(function() { table.style.background = ''; }, 3000);
        }
    }, 300);
}

function highlightQualityRule(ruleId) {
    var rule = document.querySelector('.quality-rule[data-rule-id="' + ruleId + '"]');
    if (rule) {
        rule.style.background = '#fef3c7';
        rule.scrollIntoView({ behavior: 'smooth', block: 'center' });
        setTimeout(function() { rule.style.background = ''; }, 3000);
    }
}

function highlightLineageTable(tableName) {
    var table = document.querySelector('.flow-table[data-table="' + tableName + '"]');
    if (table) {
        table.style.boxShadow = '0 0 0 3px #f59e0b';
        table.scrollIntoView({ behavior: 'smooth', block: 'center' });
        highlightTableLineage(tableName);
        setTimeout(function() { table.style.boxShadow = ''; }, 5000);
    }
}

// Copy link to clipboard function
function copyElementLink(path) {
    var url = window.location.origin + window.location.pathname + '#' + path;
    navigator.clipboard.writeText(url).then(function() {
        showToast('Link kopyalandı!');
    }).catch(function() {
        // Fallback for older browsers
        var input = document.createElement('input');
        input.value = url;
        document.body.appendChild(input);
        input.select();
        document.execCommand('copy');
        document.body.removeChild(input);
        showToast('Link kopyalandı!');
    });
}

// Generate shareable link button HTML
function getLinkButton(path, title) {
    return '<button onclick="event.stopPropagation(); copyElementLink(\'' + path + '\')" title="' + (title || 'Linki kopyala') + '" style="background: none; border: none; cursor: pointer; padding: 4px; opacity: 0.5; transition: opacity 0.2s;" onmouseover="this.style.opacity=1" onmouseout="this.style.opacity=0.5">🔗</button>';
}

