            html += '</div>';
            var statusColor = rule.status === 'active' ? '#10b981' : '#64748b';
            html += '<div class="search-result-badge" style="background: ' + statusColor + '20; color: ' + statusColor + ';">' + (rule.status || 'active') + '</div>';
